window.KANT_WORK_DATA = {"metadata": {"work_id": "aa-III-A", "series": "AA", "band": "III-A", "title": "Kritik der reinen Vernunft — Anhang (A 1781)", "short_title": "KrV Anhang (A)", "siglum": "KrV", "edition": "Akademie-Ausgabe (1900–1923) via Kant im Kontext III (2017)", "collection_title": "Digitale Kant-Edition", "citation_systems": ["A"], "citation_prefix": "KrV"}, "toc_printed": [{"title": "Erster Theil.", "page_kik": 1179, "page_pdf": 1392, "level": 1}, {"title": "Die Transscendentale Ästhetik.", "page_kik": 1179, "page_pdf": 1392, "level": 2}, {"title": "Erster Abschnitt.", "page_kik": 1181, "page_pdf": 1394, "level": 2}, {"title": "Von dem Raume.", "page_kik": 1181, "page_pdf": 1394, "level": 2}, {"title": "Zweiter Abschnitt.", "page_kik": 1185, "page_pdf": 1398, "level": 2}, {"title": "Von der Zeit.", "page_kik": 1185, "page_pdf": 1398, "level": 2}, {"title": "Zweiter Abschnitt.", "page_kik": 1193, "page_pdf": 1406, "level": 2}, {"title": "Dritter Abschnitt.", "page_kik": 1203, "page_pdf": 1416, "level": 2}], "pages": [{"page_pdf": 1385, "page_book": null, "page_kind": "body", "sigel": "A1 · A2 · A3 · A4", "units": [{"type": "paragraph", "text": "[A] Einleitung"}, {"type": "heading", "text": "I.", "level": 2}, {"type": "paragraph", "text": "Idee der Transscendental-Philosophie. _E_ Erfahrung ist ohne Zweifel das erste Product, welches unser Verstand hervorbringt, indem er den rohen Stoff sinnlicher Empfindungen bearbeitet. Sie ist eben dadurch die erste Belehrung und im Fortgange so unerschöpflich an neuem Unterricht, daß das zusammengekettete Leben aller künftigen Zeugungen an neuen Kenntnissen, die auf diesem Boden gesammlet werden können, niemals Mangel haben wird. Gleichwohl ist sie bei weitem nicht das einzige Feld, darin sich unser Verstand einschränken läßt. Sie sagt uns zwar, was da sei, aber nicht, daß es nothwendiger Weise so und nicht anders sein müsse. Eben darum giebt sie uns auch keine wahre Allgemeinheit, und die Vernunft, welche nach dieser Art von Erkenntnissen so begierig ist, wird durch sie mehr gereizt, als befriedigt. Solche allgemeine Erkenntnisse nun, die zugleich den Charakter der innern Nothwendigkeit haben, müssen von der Erfahrung unabhängig, für sich selbst klar und gewiß sein; man nennt sie daher Erkenntnisse _a priori_: da im Gegentheil das, was lediglich von der Erfahrung erborgt ist, wie man sich ausdrückt, nur _a posteriori_ oder empirisch erkannt wird. Nun zeigt es sich, welches überaus merkwürdig ist, daß selbst unter unsere Erfahrungen sich Erkenntnisse mengen, die ihren Ursprung _a priori_ haben müssen, und die vielleicht nur dazu dienen, um unsern Vorstellungen der Sinne Zusammenhang zu verschaffen. Denn wenn man aus den ersteren auch alles wegschafft, was den Sinnen angehört, so bleiben dennoch gewisse ursprüngliche Begriffe und aus ihnen erzeugte Urtheile übrig, die gänzlich _a priori_, unabhängig von der Erfahrung entstanden sein müssen, weil sie machen, daß man von den Gegenständen, die den Sinnen erscheinen, mehr sagen kann, wenigstens es sagen zu können glaubt, als bloße Erfahrung lehren würde, und daß Behauptungen wahre Allgemeinheit und strenge Nothwendigkeit enthalten, dergleichen die blos empirische Erkenntniß nicht liefern kann. Was aber noch weit mehr sagen will, ist dieses, daß gewisse Erkenntnisse sogar das Feld aller möglichen Erfahrungen verlassen und durch Begriffe, denen überall kein entsprechender Gegenstand in der Erfahrung gegeben werden kann, den Umfang unserer Urtheile über alle Grenzen derselben zu erweitern den Anschein haben. Und gerade in diesen letzteren Erkenntnissen, welche über die Sinnenwelt hinausgehen, wo Erfahrung gar keinen Leitfaden noch Berichtigung geben kann, liegen die Nachforschungen unsrer Vernunft, die wir der Wichtigkeit nach für weit vorzüglicher und ihre Endabsicht für viel erhabener halten, als alles, was der Verstand im Felde der Erscheinungen lernen kann, wobei wir sogar auf die Gefahr zu irren eher alles wagen, als daß wir so angelegene Untersuchungen aus irgend einem Grunde der Bedenklichkeit oder aus Geringschätzung und Gleichgültigkeit aufgeben sollten. Nun scheint es zwar natürlich, daß, so bald man den Boden der Erfahrung verlassen hat, man doch nicht mit Erkenntnissen, die man besitzt, ohne zu wissen woher, und auf den Credit der Grundsätze, deren Ursprung man nicht kennt, sofort ein Gebäude errichten werde, ohne der Grundlegung desselben durch sorgfältige Untersuchungen vorher versichert zu sein, daß man also die Frage vorlängst werde aufgeworfen haben, wie denn der Verstand zu allen diesen Erkenntnissen _a priori _kommen könne, und welchen Umfang, Gültigkeit und Werth sie haben mögen. In der That ist auch nichts natürlicher, wenn man unter diesem Wort das versteht, was billiger und vernünftiger Weise geschehen sollte; versteht man aber darunter das, was gewöhnlicher Maßen geschieht, so ist hinwiederum nichts natürlicher und begreiflicher, als daß diese Untersuchung lange Zeit unterbleiben mußte. Denn ein Theil dieser Erkenntnisse, die mathematische, ist im alten"}], "markers": [{"system": "A", "ref": "A1"}, {"system": "A", "ref": "A2"}, {"system": "A", "ref": "A3"}, {"system": "A", "ref": "A4"}], "running_header": "Einleitung. I. Idee der Transszendental-Philosophie [A, Anhang]"}, {"page_pdf": 1386, "page_book": null, "page_kind": "body", "sigel": "A5 · A6", "units": [{"type": "paragraph", "text": "Besitze der Zuverlässigkeit und giebt dadurch eine günstige Erwartung auch für andere, ob diese gleich von ganz verschiedener Natur sein mögen. Überdem wenn man über den Kreis der Erfahrung hinaus ist, so ist man sicher, durch Erfahrung nicht widersprochen zu werden. Der Reiz, seine Erkenntnisse zu erweitern, ist so groß, daß man nur durch einen klaren Widerspruch, auf den man stößt, in seinem Fortschritt aufgehalten werden kann. Dieser aber kann vermieden werden, wenn man seine Erdichtungen behutsam macht, ohne daß sie deswegen weniger Erdichtungen bleiben. Die Mathematik giebt uns ein glänzendes Beispiel, wie weit wir es unabhängig von der Erfahrung in der Erkenntniß _a priori _bringen können. Nun beschäftigt sie sich zwar mit Gegenständen und Erkenntnissen blos so weit, als sich solche in der Anschauung darstellen lassen. Aber dieser Umstand wird leicht übersehen, weil gedachte Anschauung selbst _a priori _ gegeben werden kann, mithin von einem bloßen reinen Begriff kaum unterschieden wird. Durch einen solchen Beweis von der Macht der Vernunft aufgemuntert, sieht der Trieb zur Erweiterung keine Grenzen. Die leichte Taube, indem sie im freien Fluge die Luft theilt, deren Widerstand sie fühlt, könnte die Vorstellung fassen, daß es ihr im luftleeren Raum noch viel besser gelingen werde. Eben so verließ Plato die Sinnenwelt, weil sie dem Verstande so vielfältige Hindernisse legt, und wagte sich jenseit derselben auf den Flügeln der Ideen in den leeren Raum des reinen Verstandes. Er bemerkte nicht, daß er durch seine Bemühungen keinen Weg gewönne, denn er hatte keinen Widerhalt gleichsam zur Unterlage, worauf er sich steifen und woran er seine Kräfte anwenden konnte, um den Verstand von der Stelle zu bringen. Es ist aber ein gewöhnliches Schicksal der menschlichen Vernunft in der Speculation ihr Gebäude so früh wie möglich fertig zu machen und hintennach allererst zu untersuchen, ob auch der Grund dazu gut gelegt sei. Alsdann aber werden allerlei Beschönigungen herbei gesucht, um uns wegen dessen Tüchtigkeit zu trösten, oder eine solche späte und gefährliche Prüfung abzuweisen. Was uns aber während dem Bauen von aller Besorgniß und Verdacht frei hält und mit scheinbarer Gründlichkeit schmeichelt, ist dieses. Ein großer Theil und vielleicht der größte von dem Geschäfte unserer Vernunft besteht in Zergliederungen der Begriffe, die wir schon von Gegenständen haben. Dieses liefert uns eine Menge von Erkenntnissen, die, ob sie gleich nichts weiter als Aufklärungen oder Erläuterungen desjenigen sind, was in unsern Begriffen (wiewohl noch auf verworrne Art) schon gedacht worden, doch wenigstens der Form nach neuen Einsichten gleich geschätzt werden, wiewohl sie der Materie oder dem Inhalte nach die Begriffe, die wir haben, nicht erweitern, sondern nur aus einander setzen. Da dieses Verfahren nun eine wirkliche Erkenntniß _a priori _giebt, die einen sichern und nützlichen Fortgang hat, so erschleicht die Vernunft, ohne es selbst zu merken, unter dieser Vorspiegelung Behauptungen von ganz anderer Art, wo die Vernunft zu gegebenen Begriffen _a _ _priori_ ganz fremde hinzu thut, ohne daß man weiß, wie sie dazu gelange, und ohne sich diese Frage auch nur in die Gedanken kommen zu lassen. Ich will daher gleich anfangs von dem Unterschiede dieser zwiefachen Erkenntnißart handeln."}], "markers": [{"system": "A", "ref": "A5"}, {"system": "A", "ref": "A6"}], "running_header": "Einleitung. I. Idee der Transszendental-Philosophie [A, Anhang]"}, {"page_pdf": 1387, "page_book": null, "page_kind": "body", "sigel": "A6 · A7 · A8", "units": [{"type": "paragraph", "text": "[A] Von dem Unterschiede analytischer und synthetischer Urtheile. _E_ In allen Urtheilen, worin das Verhältniß eines Subjects zum Prädicat gedacht wird (wenn ich nur die bejahende erwäge: denn auf die verneinende ist die Anwendung leicht), ist dieses Verhältniß auf zweierlei Art möglich. Entweder das Prädicat _B _gehört zum Subject _A_ als etwas, was in diesem Begriffe _A_ (versteckter Weise) enthalten ist; oder _B _liegt ganz außer dem Begriff _A_, ob es zwar mit demselben in Verknüpfung steht. Im ersten Fall nenne ich das Urtheil analytisch, im andern synthetisch. Analytische Urtheile (die bejahende) sind also diejenige, in welchen die Verknüpfung des Prädicats mit dem Subject durch Identität, diejenige aber, in denen diese Verknüpfung ohne Identität gedacht wird, sollen synthetische Urtheile heißen. Die erstere könnte man auch Erläuterungs-, die andere Erweiterungs-Urtheile heißen, weil jene durch das Prädicat nichts zum Begriff des Subjects hinzuthun, sondern diesen nur durch Zergliederung in seine Theilbegriffe zerfällen, die in selbigem schon (obschon verworren) gedacht waren: dahingegen die letztere zu dem Begriffe des Subjects ein Prädicat hinzuthun, welches in jenem gar nicht gedacht war und durch keine Zergliederung desselben hätte können herausgezogen werden. Z.B. wenn ich sage: alle Körper sind ausgedehnt, so ist dies ein analytisch Urtheil. Denn _E_ ich darf nicht aus dem Begriffe, den ich mit dem Wort Körper verbinde, hinausgehen, um die Ausdehnung als mit demselben verknüpft zu finden, sondern jenen Begriff nur zergliedern, d.i. des Mannigfaltigen, welches ich jederzeit in ihm denke, nur bewußt werden, um dieses Prädicat darin anzutreffen; es ist also ein analytisches Urtheil. Dagegen wenn ich sage: alle Körper sind schwer, so ist das Prädicat etwas ganz anders als das, was ich in dem bloßen Begriff eines Körpers überhaupt denke. Die Hinzufügung eines solchen Prädicats giebt also ein synthetisch Urtheil. Nun ist hieraus klar: 1) daß durch analytische Urtheile unsere Erkenntniß gar nicht erweitert werde, sondern der Begriff, den ich schon habe, aus einander gesetzt und mir selbst verständlich gemacht werde; 2) daß bei synthetischen Urtheilen ich außer dem Begriffe des Subjects noch etwas anderes (_X_) haben müsse, worauf sich der Verstand stützt, um ein Prädicat, das in jenem Begriffe nicht liegt, doch als dazu gehörig zu erkennen. Bei empirischen oder Erfahrungsurtheilen hat es hiemit gar keine Schwierigkeit. Denn dieses _X_ ist die vollständige Erfahrung von dem Gegenstande, den ich durch einen Begriff _A_ denke, welcher nur einen Theil dieser Erfahrung ausmacht. Denn ob ich schon in dem Begriff eines Körpers überhaupt das Prädicat der Schwere gar nicht einschließe, so bezeichnet er doch die vollständige Erfahrung durch einen Theil derselben, zu welchem also ich noch andere Theile eben derselben Erfahrung als zu dem ersteren gehörig hinzufügen kann. Ich kann den Begriff des Körpers vorher analytisch durch die Merkmale der Ausdehnung, der Undurchdringlichkeit, der Gestalt etc., die alle in diesem Begriff gedacht werden, erkennen. Nun erweitere ich aber meine Erkenntniß, und indem ich auf die Erfahrung zurück sehe, von welcher ich diesen Begriff des Körpers abgezogen hatte, so finde ich mit obigen Merkmalen auch die Schwere jederzeit _E_ verknüpft. Es ist also die Erfahrung jenes _X_, was außer dem Begriffe _A_ liegt, und worauf sich die Möglichkeit der Synthesis des Prädicats der Schwere _B_ mit dem Begriffe _A_ gründet. A9 _E_ Aber bei synthetischen Urtheilen _a priori _fehlt dieses Hülfsmittel ganz und gar. Wenn ich außer dem Begriffe _A_ hinaus gehen soll, um einen andern _B_ als damit verbunden zu erkennen: was ist das, worauf ich mich stütze, und wodurch die Synthesis möglich wird, da ich hier den Vortheil nicht habe, mich im Felde der Erfahrung darnach umzusehen? Man nehme den Satz: Alles, was geschieht, hat seine Ursache. In dem Begriff von Etwas, das geschieht, denke ich zwar ein Dasein, vor welchem eine Zeit vorhergeht etc., und daraus lassen sich analytische Urtheile ziehen. Aber der Begriff einer Ursache zeigt etwas von dem, was geschieht, Verschiedenes an und ist in dieser letzteren Vorstellung gar nicht mit enthalten. Wie komme ich denn dazu, von dem, was überhaupt"}], "markers": [{"system": "A", "ref": "A6"}, {"system": "A", "ref": "A7"}, {"system": "A", "ref": "A8"}], "running_header": "Von dem Unterschiede analytischer und synthetischer Urtheile [A, Anhang]"}, {"page_pdf": 1388, "page_book": null, "page_kind": "body", "sigel": "A10 · A11 · A12", "units": [{"type": "paragraph", "text": "geschieht, etwas davon ganz Verschiedenes zu sagen und den Begriff der Ursache, obzwar in jenem nicht enthalten, dennoch als dazu gehörig zu erkennen? Was ist hier das _X_, worauf sich der Verstand stützt, wenn er außer dem Begriff von _A_ ein demselben fremdes Prädicat aufzufinden glaubt, das gleichwohl damit verknüpft sei? Erfahrung kann es nicht sein, weil der angeführte Grundsatz nicht allein mit größerer Allgemeinheit, als die Erfahrung verschaffen kann, sondern auch mit dem Ausdruck der Nothwendigkeit, mithin gänzlich _a priori_ und aus bloßen Begriffen diese zweite Vorstellung zu der ersteren hinzufügt. Nun beruht auf solchen synthetischen d.i. Erweiterungs-Grundsätzen die ganze Endabsicht unserer speculativen Erkenntniß _a priori_; denn die analytischen sind zwar höchst wichtig und nöthig, aber nur um zu derjenigen Deutlichkeit der Begriffe zu gelangen, die zu einer sicheren und ausgebreiteten Synthesis, als zu einem wirklich neuen Anbau, erforderlich ist. Es liegt also hier ein gewisses Geheimniß verborgen*, dessen Aufschluß allein den Fortschritt in dem grenzenlosen Felde der reinen Verstandeserkenntniß sicher und zuverlässig machen kann: nämlich mit gehöriger Allgemeinheit den Grund der Möglichkeit synthetischer Urtheile _a priori_ aufzudecken, die Bedingungen, die eine jede Art derselben möglich machen, einzusehen und diese ganze Erkenntniß (die ihre eigene Gattung ausmacht) in einem System nach ihren ursprünglichen Quellen, Abtheilungen, Umfang und Grenzen nicht durch einen flüchtigen Umkreis zu bezeichnen, sondern vollständig und zu jedem Gebrauch hinreichend zu bestimmen. So viel vorläufig von dem Eigenthümlichen, was die synthetischen Urtheile an sich haben. Aus diesem allem ergiebt sich nun die Idee einer besondern Wissenschaft, die zur Kritik der reinen Vernunft dienen könne. Es heißt aber jede Erkenntniß rein, die mit nichts Fremdartigem vermischt ist. Besonders aber wird eine Erkenntniß schlechthin rein genannt, in die sich überhaupt keine Erfahrung oder Empfindung einmischt, welche mithin völlig _a priori_ möglich ist. _E_ Nun ist Vernunft das Vermögen, welches die Principien der Erkenntniß _a priori _an die Hand giebt. Daher ist reine Vernunft diejenige, _E_ welche die Principien etwas schlechthin _a priori _zu erkennen enthält. Ein Organon der reinen Vernunft würde ein Inbegriff derjenigen Principien sein, nach denen alle reine Erkenntnisse _a priori _können erworben und wirklich zu Stande gebracht werden. Die ausführliche Anwendung eines solchen Organon würde ein System der reinen Vernunft verschaffen. Da dieses aber sehr viel verlangt ist, und es noch dahin steht, ob auch überhaupt eine solche Erweiterung unserer Erkenntniß und in welchen Fällen sie möglich sei: so können wir eine Wissenschaft der bloßen Beurtheilung der reinen Vernunft, ihrer Quellen und Grenzen als die Propädeutik zum System der reinen Vernunft ansehen. _E_ Eine solche würde nicht eine Doctrin, sondern nur Kritik der reinen Vernunft heißen müssen, und ihr Nutze würde wirklich nur negativ sein, nicht zur Erweiterung, sondern nur zur Läuterung unserer Vernunft dienen und sie von Irrthümern frei halten, welches schon sehr viel gewonnen ist. Ich nenne alle Erkenntniß transscendental, die sich nicht sowohl mit Gegenständen, sondern mit unsern Begriffen _a _ _priori _von Gegenständen überhaupt beschäftigt. Ein System solcher Begriffe würde Transscendental-Philosophie heißen. Diese ist aber wiederum für den Anfang zu viel. Denn weil eine solche Wissenschaft sowohl die analytische Erkenntniß, als die synthetische _a priori _vollständig enthalten müßte, so ist sie, in so fern es unsre Absicht betrifft, von zu weitem Umfange, indem wir die Analysis nur so weit treiben dürfen, als sie unentbehrlich nöthig ist, um die Principien der Synthesis _a priori_, als warum es uns nur zu thun ist, in ihrem ganzen Umfange einzusehen. Diese Untersuchung, die wir eigentlich nicht Doctrin, sondern nur transscendentale Kritik nennen können, weil sie nicht die Erweiterung der Erkenntnisse selbst, sondern nur die Berichtigung derselben zur Absicht hat und den Probirstein des Werths oder Unwerths aller Erkenntnisse _a priori _abgeben soll, ist das, womit wir uns jetzt beschäftigen. Eine solche Kritik ist demnach eine Vorbereitung wo möglich zu einem Organon, und wenn dieses nicht gelingen sollte, wenigstens zu einem Kanon derselben, nach welchem allenfalls dereinst das vollständige System der Philosophie der reinen Vernunft, es mag"}], "markers": [{"system": "A", "ref": "A10"}, {"system": "A", "ref": "A11"}, {"system": "A", "ref": "A12"}], "running_header": "Von dem Unterschiede analytischer und synthetischer Urtheile [A, Anhang]"}, {"page_pdf": 1389, "page_book": null, "page_kind": "body", "sigel": "A13", "units": [{"type": "paragraph", "text": "nun in Erweiterung oder bloßer Begrenzung ihrer Erkenntniß bestehen, sowohl analytisch, als synthetisch dargestellt werden könnte. Denn daß dieses möglich sei, ja daß ein solches System von nicht gar großem Umfange sein könne, um zu hoffen, es ganz zu vollenden, läßt sich schon zum voraus daraus ermessen, daß hier nicht die Natur der Dinge, welche unerschöpflich ist, sondern der Verstand, der über die Natur der Dinge urtheilt, und auch dieser wiederum nur in Ansehung seiner Erkenntniß _a priori _den Gegenstand ausmacht, dessen Vorrath, weil wir ihn doch nicht auswärtig suchen dürfen, uns nicht verborgen bleiben kann und allem Vermuthen nach klein genug ist, um vollständig aufgenommen, nach seinem Werthe oder Unwerthe beurtheilt und unter richtige Schätzung _E_ gebracht zu werden."}, {"type": "paragraph", "text": "Anmerkungen: * Wäre es einem von den Alten eingefallen, auch nur diese Frage aufzuwerfen, so würde diese allein allen Systemen der reinen Vernunft bis auf unsere Zeit mächtig widerstanden haben und hätte so viele eitele Versuche erspart, die, ohne zu wissen, womit man eigentlich zu thun hat, blindlings unternommen worden."}], "markers": [{"system": "A", "ref": "A13"}], "running_header": "Von dem Unterschiede analytischer und synthetischer Urtheile [A, Anhang]"}, {"page_pdf": 1390, "page_book": null, "page_kind": "body", "sigel": "A13 · A14 · A15 · A16", "units": [{"type": "paragraph", "text": "[A] II. Eintheilung der Transscendentalphilosophie. Die Transscendental-Philosophie ist hier nur eine Idee, wozu die Kritik der reinen Vernunft den ganzen Plan architektonisch, d.i. aus Principien, entwerfen soll, mit völliger Gewährleistung der Vollständigkeit und Sicherheit aller Stücke, die dieses Gebäude ausmachen. Daß diese Kritik nicht schon selbst Transscendental-Philosophie heißt, beruht lediglich darauf, daß sie, um ein vollständig System zu sein, auch eine ausführliche Analysis der ganzen menschlichen Erkenntniß _a priori _enthalten müßte. Nun muß zwar unsre Kritik allerdings auch eine vollständige Herzählung aller Stammbegriffe, welche die gedachte reine Erkenntniß ausmachen, vor Augen legen. Allein der ausführlichen Analysis dieser Begriffe selbst, wie auch der vollständigen Recension der daraus abgeleiteten enthält sie sich billig, theils weil diese Zergliederung nicht zweckmäßig wäre, indem sie die Bedenklichkeit nicht hat, welche bei der Synthesis angetroffen wird, um deren willen eigentlich die ganze Kritik da ist, theils weil es der Einheit des Plans zuwider wäre, sich mit der Verantwortung der Vollständigkeit einer solchen Analysis und Ableitung zu befassen, deren man in Ansehung seiner Absicht doch überhoben sein konnte. Diese Vollständigkeit der Zergliederung sowohl, als der Ableitung aus den künftig zu liefernden Begriffen _a priori _ist indessen leicht zu ergänzen, wenn sie nur allererst als ausführliche Principien der Synthesis da sind, und ihnen in Ansehung dieser wesentlichen Absicht nichts ermangelt. Zur Kritik der reinen Vernunft gehört demnach alles, was die Transscendental-Philosophie ausmacht, und sie ist die vollständige Idee der Transscendental-Philosophie, aber diese Wissenschaft noch nicht selbst, weil sie in der Analysis nur so weit geht, als es zur vollständigen Beurtheilung der synthetischen Erkenntniß _a priori _erforderlich ist. Das vornehmste Augenmerk bei der Eintheilung einer solchen Wissenschaft ist: daß gar keine Begriffe hineinkommen müssen, die irgend etwas Empirisches in sich enthalten, oder daß die Erkenntniß _a priori _völlig rein sei. Daher obzwar die obersten Grundsätze der Moralität und die Grundbegriffe derselben Erkenntnisse _a priori _sind, so gehören sie doch nicht in die Transscendental-Philosophie, weil die Begriffe der Lust und Unlust, der Begierden und Neigungen, der Willkür etc., die insgesammt empirischen Ursprunges sind, dabei vorausgesetzt werden müßten. Daher ist die Transscendental-Philosophie eine Weltweisheit der reinen, blos speculativen Vernunft. Denn alles Praktische, so fern es Bewegungsgründe enthält, bezieht sich auf Gefühle, welche zu empirischen Erkenntnißquellen gehören. Wenn man nun die Eintheilung dieser Wissenschaft aus dem allgemeinen Gesichtspunkte eines Systems überhaupt anstellen will, so muß die, welche wir jetzt vortragen, erstlich eine Elementar-Lehre, zweitens eine Methoden-Lehre der reinen Vernunft enthalten. Jeder dieser Haupttheile würde seine Unterabtheilung haben, deren Gründe sich gleichwohl hier noch nicht vortragen lassen. Nur so viel scheint zur Einleitung oder Vorerinnerung nöthig zu sein, daß es zwei Stämme der menschlichen Erkenntniß gebe, die vielleicht aus einer gemeinschaftlichen, aber uns unbekannten Wurzel entspringen, nämlich Sinnlichkeit und Verstand , durch deren ersteren uns Gegenstände gegeben, durch den zweiten aber gedacht werden. Sofern nun die Sinnlichkeit Vorstellungen _a priori _enthalten sollte, welche die Bedingung ausmachen, unter der uns Gegenstände gegeben werden, so würde sie zur Transscendental-Philosophie gehören. Die transscendentale Sinnenlehre würde zum ersten Theile der Elementarwissenschaft gehören müssen, weil die Bedingungen, worunter allein die Gegenstände der menschlichen Erkenntniß gegeben werden, denjenigen vorgehen, unter welchen selbige gedacht werden."}, {"type": "paragraph", "text": "__________"}], "markers": [{"system": "A", "ref": "A13"}, {"system": "A", "ref": "A14"}, {"system": "A", "ref": "A15"}, {"system": "A", "ref": "A16"}], "running_header": "Eintheilung der Transscendentalphilosophie [A, Anhang]"}, {"page_pdf": 1391, "page_book": null, "page_kind": "blank", "sigel": "", "units": []}, {"page_pdf": 1392, "page_book": null, "page_kind": "body", "sigel": "A19 · A20 · A21 · A22", "units": [{"type": "paragraph", "text": "[A] Der Transscendentalen Elementarlehre"}, {"type": "heading", "text": "Erster Theil.", "level": 1}, {"type": "heading", "text": "Die Transscendentale Ästhetik.", "level": 2}, {"type": "paragraph", "text": "Auf welche Art und durch welche Mittel sich auch immer eine Erkenntniß auf Gegenstände beziehen mag, so ist doch diejenige, wodurch sie sich auf dieselbe unmittelbar bezieht, und worauf alles Denken als Mittel abzweckt, die Anschauung. Diese findet aber nur statt, so fern uns der Gegenstand gegeben wird; dieses aber ist wiederum nur dadurch möglich, daß er das Gemüth auf gewisse Weise _E_ afficire. Die Fähigkeit (Receptivität), Vorstellungen durch die Art, wie wir von Gegenständen afficirt werden, zu bekommen, heißt Sinnlichkeit. Vermittelst der Sinnlichkeit also werden uns Gegenstände gegeben, und sie allein liefert uns Anschauungen; durch den Verstand aber werden sie gedacht, und von ihm entspringen Begriffe. Alles Denken aber muß sich, es sei gerade zu (_directe_) oder im Umschweife (_indirecte_), zuletzt auf Anschauungen, mithin bei uns auf Sinnlichkeit beziehen, weil uns auf andere Weise kein Gegenstand gegeben werden kann. Die Wirkung eines Gegenstandes auf die Vorstellungsfähigkeit, so fern wir von demselben afficirt werden, ist Empfindung. Diejenige Anschauung, welche sich auf den Gegenstand durch Empfindung bezieht, heißt empirisch. Der unbestimmte Gegenstand einer empirischen Anschauung heißt Erscheinung. In der Erscheinung nenne ich das, was der Empfindung correspondirt, die Materie derselben, dasjenige aber, welches macht, daß das Mannigfaltige der Erscheinung, in gewissen Verhältnissen geordnet, angeschauet wird, nenne ich die Form der Erscheinung. Da das, worin sich die Empfindungen allein ordnen und in gewisse Form gestellt werden können, nicht selbst wiederum Empfindung sein kann, so ist uns zwar die Materie aller Erscheinung nur _a posteriori _gegeben, die Form derselben aber muß zu ihnen insgesammt im Gemüthe _a priori _bereit liegen und daher abgesondert von aller Empfindung können betrachtet werden. Ich nenne alle Vorstellungen rein (im transscendentalen Verstande), in denen nichts, was zur Empfindung gehört, angetroffen wird. Demnach wird die reine Form sinnlicher Anschauungen überhaupt im Gemüthe _a_ _priori _angetroffen werden, worin alles Mannigfaltige der Erscheinungen in gewissen Verhältnissen angeschauet wird. Diese reine Form der Sinnlichkeit wird auch selber reine Anschauung heißen. So, wenn ich von der Vorstellung eines Körpers das, was der Verstand davon denkt, als Substanz, Kraft, Theilbarkeit etc., imgleichen was davon zur Empfindung gehört, als Undurchdringlichkeit, Härte, Farbe etc., absondere, so bleibt mir aus dieser empirischen Anschauung noch etwas übrig, nämlich Ausdehnung und Gestalt. Diese gehören zur reinen Anschauung, die _a priori_, auch ohne einen wirklichen Gegenstand der Sinne oder Empfindung, als eine bloße Form der Sinnlichkeit im Gemüthe statt findet. Eine Wissenschaft von allen Principien der Sinnlichkeit _a priori_ nenne ich die transscendentale Ästhetik.* Es muß also eine solche Wissenschaft geben, die den ersten Theil der transscendentalen Elementar-Lehre ausmacht, im Gegensatz mit derjenigen, welche die Principien des reinen Denkens enthält und transscendentale Logik genannt wird. In der transscendentalen Ästhetik also werden wir zuerst die Sinnlichkeit isoliren, dadurch daß wir alles absondern, was der Verstand durch seine Begriffe dabei denkt, damit nichts als empirische Anschauung übrig bleibe. Zweitens werden wir von dieser noch alles, was zur Empfindung gehört, abtrennen, damit nichts als reine Anschauung und die bloße Form der Erscheinungen übrig bleibe, welches das einzige ist, das die Sinnlichkeit _a priori _liefern kann. Bei dieser Untersuchung wird sich finden, daß es zwei reine Formen sinnlicher Anschauung als Principien der Erkenntniß _a priori _gebe, nämlich Raum und Zeit, mit deren Erwägung wir uns"}], "markers": [{"system": "A", "ref": "A19"}, {"system": "A", "ref": "A20"}, {"system": "A", "ref": "A21"}, {"system": "A", "ref": "A22"}], "running_header": "Die Transscendentale Ästhetik [A, Anhang]"}, {"page_pdf": 1393, "page_book": null, "page_kind": "body", "sigel": "", "units": [{"type": "paragraph", "text": "jetzt beschäftigen werden."}, {"type": "paragraph", "text": "Anmerkungen: * Die Deutschen sind die einzige, welche sich jetzt des Worts Ästhetik bedienen, um dadurch das zu bezeichnen, was andre Kritik des Geschmacks heißen. Es liegt hier eine verfehlte Hoffnung zum Grunde, die der vortreffliche Analyst Baumgarten faßte, die kritische Beurtheilung des Schönen unter Vernunftprincipien zu bringen und die Regeln derselben zur Wissenschaft zu erheben. Allein diese Bemühung ist vergeblich. Denn gedachte Regeln oder Kriterien sind ihren Quellen nach blos empirisch und können also niemals zu Gesetzen _a _ _priori _dienen, wornach sich unser Geschmacksurtheil richten müßte; vielmehr macht das letztere den eigentlichen Probirstein der Richtigkeit der ersteren aus. Um deswillen ist es rathsam, diese Benennung wiederum eingehen zu lassen und sie derjenigen Lehre aufzubehalten, die wahre Wissenschaft ist, wodurch man auch der Sprache und dem Sinne der Alten näher treten würde, bei denen die Eintheilung der Erkenntniß in aisjðhta kai nohta sehr berühmt war."}], "running_header": "Die Transscendentale Ästhetik [A, Anhang]"}, {"page_pdf": 1394, "page_book": null, "page_kind": "body", "sigel": "A22 · A23 · A24 · A25", "units": [{"type": "paragraph", "text": "[A] Der Transscendentalen Ästhetik"}, {"type": "heading", "text": "Erster Abschnitt.", "level": 2}, {"type": "heading", "text": "Von dem Raume.", "level": 2}, {"type": "paragraph", "text": "Vermittelst des äußeren Sinnes (einer Eigenschaft unsres Gemüths) stellen wir uns Gegenstände als außer uns und diese insgesammt im Raume vor. Darin ist ihre Gestalt, Größe und Verhältniß gegen einander bestimmt oder bestimmbar. Der innere Sinn, vermittelst dessen das Gemüth sich selbst oder seinen inneren Zustand anschauet, giebt zwar keine Anschauung von der Seele selbst als einem Object, allein es ist doch eine bestimmte Form, unter der die Anschauung ihres innern Zustandes allein möglich ist, so daß alles, was zu den innern Bestimmungen gehört, in Verhältnissen der Zeit vorgestellt wird. Äußerlich kann die Zeit nicht angeschaut werden, so wenig wie der Raum als etwas in uns. Was sind nun Raum und Zeit? Sind es wirkliche Wesen? Sind es zwar nur Bestimmungen oder auch Verhältnisse der Dinge, aber doch solche, welche ihnen auch an sich zukommen würden, wenn sie auch nicht angeschaut würden; oder sind sie solche, die nur an der Form der Anschauung allein haften und mithin an der subjectiven Beschaffenheit unseres Gemüths, ohne welche die Prädicate gar keinem Dinge beigelegt werden können? Um uns hierüber zu belehren, wollen wir zuerst den Raum betrachten. 1) Der Raum ist kein empirischer Begriff, der von äußeren Erfahrungen abgezogen worden. Denn damit gewisse Empfindungen auf etwas außer mir bezogen werden (d.i. auf etwas in einem andern Orte des Raumes, als darin ich mich befinde), imgleichen damit ich sie als außer einander, mithin nicht blos verschieden, sondern als in verschiedenen Orten vorstellen könne, dazu muß die Vorstellung des Raumes schon zum Grunde liegen. Demnach kann die Vorstellung des Raumes nicht aus den Verhältnissen der äußern Erscheinung durch Erfahrung erborgt sein, sondern diese äußere Erfahrung ist selbst nur durch gedachte Vorstellung allererst möglich. 2) Der Raum ist eine nothwendige Vorstellung _a priori_, die allen äußeren Anschauungen zum Grunde liegt. Man kann sich niemals eine Vorstellung davon machen, daß kein Raum sei, ob man sich gleich ganz wohl denken kann, daß keine Gegenstände darin angetroffen werden. Er wird also als die Bedingung der Möglichkeit der Erscheinungen und nicht als eine von ihnen abhängende Bestimmung angesehen und ist eine Vorstellung _a priori_, die nothwendiger Weise äußeren Erscheinungen zum Grunde liegt. 3) Auf diese Nothwendigkeit _a priori_ gründet sich die apodiktische Gewißheit aller geometrischen Grundsätze und die Möglichkeit ihrer Constructionen _a priori_. Wäre nämlich diese Vorstellung des Raums ein _a posteriori_ erworbener Begriff, der aus der allgemeinen äußeren Erfahrung geschöpft wäre, so würden die ersten Grundsätze der mathematischen Bestimmung nichts als Wahrnehmungen sein. Sie hätten also alle Zufälligkeit der Wahrnehmung, und es wäre eben nicht nothwendig, daß zwischen zwei Punkten nur eine gerade Linie sei, sondern die Erfahrung würde es so jederzeit lehren. Was von der Erfahrung entlehnt ist, hat auch nur comparative Allgemeinheit, nämlich durch Induction. Man würde also nur sagen können: so viel zur Zeit noch bemerkt worden, ist kein Raum gefunden worden, der mehr als drei Abmessungen hätte. 4) Der Raum ist kein discursiver oder, wie man sagt, allgemeiner Begriff von Verhältnissen der Dinge überhaupt, sondern eine reine Anschauung. Denn erstlich kann man sich nur einen einigen Raum vorstellen, und wenn man von vielen Räumen redet, so versteht man darunter nur Theile eines und desselben alleinigen Raumes. Diese Theile können auch nicht vor dem einigen, allbefassenden Raume gleichsam als dessen Bestandtheile (daraus seine Zusammensetzung möglich sei) vorhergehen, sondern nur in ihm gedacht werden. Er ist wesentlich einig, das Mannigfaltige in ihm, mithin auch der allgemeine Begriff von Räumen überhaupt beruht lediglich auf Einschränkungen. Hieraus folgt, daß in Ansehung seiner eine Anschauung _a priori _(die nicht"}], "markers": [{"system": "A", "ref": "A22"}, {"system": "A", "ref": "A23"}, {"system": "A", "ref": "A24"}, {"system": "A", "ref": "A25"}], "running_header": "Von dem Raume [A, Anhang]"}, {"page_pdf": 1395, "page_book": null, "page_kind": "body", "sigel": "", "units": [{"type": "paragraph", "text": "empirisch ist) allen Begriffen von demselben zum Grunde liege. So werden auch alle geometrische Grundsätze, z.E. daß in einem Triangel zwei Seiten zusammen größer sind als die dritte, niemals aus allgemeinen Begriffen von Linie und Triangel, sondern aus der Anschauung und zwar _a priori _mit apodiktischer Gewißheit abgeleitet. 5) Der Raum wird als eine unendliche Größe gegeben vorgestellt. Ein allgemeiner Begriff vom Raum (der sowohl einem Fuße, als einer Elle gemein ist) kann in Ansehung der Größe nichts bestimmen. Wäre es nicht die Grenzenlosigkeit im Fortgange der Anschauung, so würde kein Begriff von Verhältnissen ein Principium der Unendlichkeit derselben bei sich führen."}], "running_header": "Von dem Raume [A, Anhang]"}, {"page_pdf": 1396, "page_book": null, "page_kind": "body", "sigel": "A26 · A27 · A28", "units": [{"type": "paragraph", "text": "[A] Schlüsse aus obigen Begriffen. _a_) Der Raum stellt gar keine Eigenschaft irgend einiger Dinge an sich, oder sie in ihrem Verhältniß auf einander vor, d.i. keine Bestimmung derselben, die an Gegenständen selbst haftete, und welche bliebe, wenn man auch von allen subjectiven Bedingungen der Anschauung abstrahirte. Denn weder absolute, noch relative Bestimmungen können vor dem Dasein der Dinge, welchen sie zukommen, mithin nicht _a priori _angeschaut werden. _b_) Der Raum ist nichts anders, als nur die Form aller Erscheinungen äußerer Sinne, d.i. die subjective Bedingung der Sinnlichkeit, unter der allein uns äußere Anschauung möglich ist. Weil nun die Receptivität des Subjects, von Gegenständen afficirt zu werden, nothwendiger Weise vor allen Anschauungen dieser Objecte vorhergeht, so läßt sich verstehen, wie die Form aller Erscheinungen vor allen wirklichen Wahrnehmungen, mithin _a priori _im Gemüthe gegeben sein könne, und wie sie als eine reine Anschauung, in der alle Gegenstände bestimmt werden müssen, Principien der Verhältnisse derselben vor aller Erfahrung enthalten könne. Wir können demnach nur aus dem Standpunkte eines Menschen vom Raum, von ausgedehnten Wesen etc. reden. Gehen wir von der subjectiven Bedingung ab, unter welcher wir allein äußere Anschauung bekommen können, so wie wir nämlich von den Gegenständen afficirt werden mögen, so bedeutet die Vorstellung vom Raume gar nichts. _E_ Dieses Prädicat wird den Dingen nur in so fern beigelegt, als sie uns erscheinen, d.i. Gegenstände der Sinnlichkeit sind. Die beständige Form dieser Receptivität, welche wir Sinnlichkeit nennen, ist eine nothwendige Bedingung aller Verhältnisse, darin Gegenstände als außer uns angeschauet werden, und wenn man von diesen Gegenständen abstrahirt, eine reine Anschauung, welche den Namen Raum führt. Weil wir die besonderen Bedingungen der Sinnlichkeit nicht zu Bedingungen der Möglichkeit der Sachen, sondern nur ihrer Erscheinungen machen können, so können wir wohl sagen, daß der Raum alle Dinge befasse, _E_ die uns äußerlich erscheinen mögen, aber nicht alle Dinge an sich selbst, _E_ sie mögen nun angeschaut werden oder nicht, oder auch von welchem Subject man wolle. Denn wir können von den Anschauungen anderer denkenden Wesen gar nicht urtheilen, ob sie an die nämlichen Bedingungen gebunden seien, welche unsere Anschauung einschränken und für uns allgemein gültig sind. _E_ Wenn wir die Einschränkung eines Urtheils zum Begriff des Subjects hinzufügen, so gilt das Urtheil alsdann unbedingt. Der Satz: _E_ Alle Dinge sind neben einander im Raum, gilt nur unter der Einschränkung, wenn diese Dinge als Gegenstände unserer sinnlichen Anschauung genommen werden. Füge ich hier die Bedingung zum Begriffe und sage: Alle Dinge als äußere Erscheinungen sind neben einander im Raum, so gilt diese Regel allgemein und ohne Einschränkung. Unsere Erörterungen lehren demnach die Realität (d.i. die objective Gültigkeit) des Raumes in Ansehung alles dessen, was äußerlich als Gegenstand uns vorkommen kann, aber zugleich die Idealität des Raums in Ansehung der Dinge, wenn sie durch die Vernunft an sich selbst erwogen werden, d.i. ohne Rücksicht auf die Beschaffenheit unserer Sinnlichkeit zu nehmen. Wir behaupten also die empirische Realität des Raumes (in Ansehung aller möglichen äußeren Erfahrung), _E_ obzwar zugleich die transscendentale Idealität desselben, d.i. daß er Nichts sei, so bald wir die Bedingung der Möglichkeit aller Erfahrung weglassen und ihn als etwas, was den Dingen an sich selbst zum Grunde liegt, annehmen. Es giebt aber auch außer dem Raum keine andere subjective und auf etwas Äußeres bezogene Vorstellung, die _a priori _objectiv heißen könnte; daher diese subjective Bedingung aller äußeren Erscheinungen mit keiner andern kann verglichen werden. Der Wohlgeschmack eines Weines gehört nicht zu den objectiven Bestimmungen des Weines, mithin eines Objects sogar als Erscheinung betrachtet, sondern zu der besondern Beschaffenheit des Sinnes an dem Subjecte, was ihn genießt. Die Farben sind nicht Beschaffenheiten der Körper, deren Anschauung sie"}], "markers": [{"system": "A", "ref": "A26"}, {"system": "A", "ref": "A27"}, {"system": "A", "ref": "A28"}], "running_header": "Schlüsse aus obigen Begriffen [Tr. Ästhetik, A, Anhang]"}, {"page_pdf": 1397, "page_book": null, "page_kind": "body", "sigel": "A29 · A30", "units": [{"type": "paragraph", "text": "anhängen, sondern auch nur Modificationen des Sinnes des Gesichts, welches vom Lichte auf gewisse Weise afficirt wird. Dagegen gehört der Raum, als Bedingung äußerer Objecte, nothwendiger Weise zur Erscheinung oder Anschauung derselben. Geschmack und Farben sind gar nicht nothwendige Bedingungen, unter welchen die Gegenstände allein für uns Objecte der Sinne werden können. Sie sind nur als zufällig beigefügte Wirkungen der besondern Organisation mit der Erscheinung verbunden. Daher sind sie auch keine Vorstellungen _a priori_, sondern auf Empfindung, der Wohlgeschmack aber sogar auf Gefühl (der Lust und Unlust) als einer Wirkung der Empfindung gegründet. Auch kann niemand _a priori_ weder eine Vorstellung einer Farbe, noch irgend eines Geschmacks haben: der Raum aber betrifft nur die reine Form der Anschauung, schließt also gar keine Empfindung (nichts Empirisches) in sich, und alle Arten und Bestimmungen des Raumes können und müssen sogar _a priori_ vorgestellt werden können, wenn Begriffe der Gestalten sowohl, als Verhältnisse entstehen sollen. Durch denselben ist es allein möglich, daß Dinge für uns äußere Gegenstände sind. Die Absicht dieser Anmerkung geht nur dahin, zu verhüten: daß man die behauptete Idealität des Raumes nicht durch bei weitem unzulängliche Beispiele zu erläutern sich einfallen lasse, da nämlich etwa Farben, Geschmack etc. mit Recht nicht als Beschaffenheiten der Dinge, sondern blos als Veränderungen unseres Subjects, die sogar bei verschiedenen Menschen verschieden sein können, betrachtet werden. Denn in diesem Falle gilt das, was ursprünglich selbst nur Erscheinung ist, z.B. eine Rose, im empirischen Verstande für ein Ding an sich selbst, welches doch jedem Auge in Ansehung der Farbe anders erscheinen kann. Dagegen ist der transscendentale Begriff der Erscheinungen im Raume eine kritische Erinnerung, daß überhaupt nichts, was im Raume angeschaut wird, eine Sache an sich, noch daß der Raum eine Form der Dinge sei, die ihnen etwa an sich selbst eigen wäre, sondern daß uns die Gegenstände an sich gar nicht bekannt sind, und was wir äußere Gegenstände nennen, nichts anders als bloße Vorstellungen unserer Sinnlichkeit sind, deren Form der Raum ist, deren wahres Correlatum aber, d.i. das Ding an sich selbst, dadurch gar nicht erkannt wird noch erkannt werden kann, nach welchem aber auch in der Erfahrung niemals gefragt wird."}], "markers": [{"system": "A", "ref": "A29"}, {"system": "A", "ref": "A30"}], "running_header": "Schlüsse aus obigen Begriffen [Tr. Ästhetik, A, Anhang]"}, {"page_pdf": 1398, "page_book": null, "page_kind": "body", "sigel": "A30 · A31 · A32", "units": [{"type": "paragraph", "text": "[A] Der Transscendentalen Ästhetik"}, {"type": "heading", "text": "Zweiter Abschnitt.", "level": 2}, {"type": "heading", "text": "Von der Zeit.", "level": 2}, {"type": "paragraph", "text": "1) Die Zeit ist kein empirischer Begriff, der irgend von einer Erfahrung abgezogen worden. Denn das Zugleichsein oder Aufeinanderfolgen würde selbst nicht in die Wahrnehmung kommen, wenn die Vorstellung der Zeit nicht_ a priori _zum Grunde läge. Nur unter deren Voraussetzung kann man sich vorstellen: daß einiges zu einer und derselben Zeit (zugleich) oder in verschiedenen Zeiten (nach einander) sei. 2) Die Zeit ist eine nothwendige Vorstellung, die allen Anschauungen zum Grunde liegt. Man kann in Ansehung der Erscheinungen überhaupt die Zeit selbst nicht aufheben, ob man zwar ganz wohl die Erscheinungen aus der Zeit wegnehmen kann. Die Zeit ist also _a priori _gegeben. In ihr allein ist alle Wirklichkeit der Erscheinungen möglich. Diese können insgesammt wegfallen, aber sie selbst (als die allgemeine Bedingung ihrer Möglichkeit) kann nicht aufgehoben werden. 3) Auf diese Nothwendigkeit _a priori _gründet sich auch die Möglichkeit apodiktischer Grundsätze von den Verhältnissen der Zeit oder Axiomen von der Zeit überhaupt. Sie hat nur eine Dimension: verschiedene Zeiten sind nicht zugleich, sondern nach einander (so wie verschiedene Räume nicht nach einander, sondern zugleich sind). Diese Grundsätze können aus der Erfahrung nicht gezogen werden, denn diese würde weder strenge Allgemeinheit, noch apodiktische Gewißheit geben. Wir würden nur sagen können: so lehrt es die gemeine Wahrnehmung, nicht aber: so muß es sich verhalten. Diese Grundsätze gelten als Regeln, unter denen überhaupt Erfahrungen möglich sind, und belehren uns vor derselben und nicht durch dieselbe. 4) Die Zeit ist kein discursiver oder, wie man ihn nennt, allgemeiner Begriff, sondern eine reine Form der sinnlichen Anschauung. Verschiedene Zeiten sind nur Theile eben derselben Zeit. Die Vorstellung, die nur durch einen einzigen Gegenstand gegeben werden kann, ist aber Anschauung. Auch würde sich der Satz, daß verschiedene Zeiten nicht zugleich sein können, aus einem allgemeinen Begriff nicht herleiten lassen. Der Satz ist synthetisch und kann aus Begriffen allein nicht entspringen. Er ist also in der Anschauung und Vorstellung der Zeit unmittelbar enthalten. 5) Die Unendlichkeit der Zeit bedeutet nichts weiter, als daß alle bestimmte Größe der Zeit nur durch Einschränkungen einer einigen zum Grunde liegenden Zeit möglich sei. Daher muß die ursprüngliche Vorstellung Zeit als uneingeschränkt gegeben sein. Wovon aber die Theile selbst und jede Größe eines Gegenstandes nur durch Einschränkung bestimmt vorgestellt werden können, da muß die ganze Vorstellung nicht durch Begriffe gegeben sein (denn da gehen die Theilvorstellungen vorher), sondern es muß ihre unmittelbare Anschauung zum Grunde liegen."}], "markers": [{"system": "A", "ref": "A30"}, {"system": "A", "ref": "A31"}, {"system": "A", "ref": "A32"}], "running_header": "Von der Zeit [Tr. Ästhetik, A, Anhang]"}, {"page_pdf": 1399, "page_book": null, "page_kind": "body", "sigel": "A32 · A33 · A34 · A35", "units": [{"type": "paragraph", "text": "[A] Schlüsse aus diesen Begriffen. _a_) Die Zeit ist nicht etwas, was für sich selbst bestände, oder den Dingen als objective Bestimmung anhinge, mithin übrig bliebe, wenn man von allen subjectiven Bedingungen der Anschauung derselben abstrahirt: denn im ersten Fall würde sie etwas sein, was ohne wirklichen Gegenstand dennoch wirklich wäre. Was aber das zweite betrifft, so könnte sie als eine den Dingen selbst anhängende Bestimmung oder Ordnung nicht vor den Gegenständen als ihre Bedingung vorhergehen und _a priori _durch synthetische Sätze erkannt und angeschaut werden. Dieses letztere findet dagegen sehr wohl statt, wenn die Zeit nichts als die subjective Bedingung ist, unter der alle Anschauungen in uns statt finden können. Denn da kann diese Form der innern Anschauung vor den Gegenständen, mithin _a priori _ vorgestellt werden. _b_) Die Zeit ist nichts anders, als die Form des innern Sinnes, d.i. des Anschauens unserer selbst und unsers innern Zustandes. Denn die Zeit kann keine Bestimmung äußerer Erscheinungen sein: sie gehört weder zu einer Gestalt oder Lage etc.; dagegen bestimmt sie das Verhältniß der Vorstellungen in unserm innern Zustande. Und eben weil diese innre Anschauung keine Gestalt giebt, suchen wir auch diesen Mangel durch Analogien zu ersetzen und stellen die Zeitfolge durch eine ins unendliche fortgehende Linie vor, in welcher das Mannigfaltige eine Reihe ausmacht, die nur von einer Dimension ist, und schließen aus den Eigenschaften dieser Linie auf alle Eigenschaften der Zeit außer dem einigen, daß die Theile der erstern zugleich, die der letztern aber jederzeit nach einander sind. Hieraus erhellt auch, daß die Vorstellung der Zeit selbst Anschauung sei, weil alle ihre Verhältnisse sich an einer äußern Anschauung ausdrücken lassen. _c_) Die Zeit ist die formale Bedingung _a priori _aller Erscheinungen überhaupt. Der Raum als die reine Form aller äußeren Anschauung ist als Bedingung _a priori _blos auf äußere Erscheinungen eingeschränkt. Dagegen weil alle Vorstellungen, sie mögen nun äußere Dinge zum Gegenstande haben oder nicht, doch an sich selbst als Bestimmungen des Gemüths zum innern Zustande gehören; dieser innere Zustand aber unter der formalen Bedingung der innern Anschauung, mithin der Zeit gehört: so ist die Zeit eine Bedingung _a priori_ von aller Erscheinung überhaupt und zwar die unmittelbare Bedingung der inneren (unserer Seelen) und eben dadurch mittelbar auch der äußern Erscheinungen. Wenn ich _a priori_ sagen kann: alle äußere Erscheinungen sind im Raume und nach den Verhältnissen des Raumes _a priori _bestimmt, so kann ich aus dem Princip des innern Sinnes ganz allgemein sagen: alle Erscheinungen überhaupt, d.i. alle Gegenstände der Sinne, sind in der Zeit und stehen nothwendiger Weise in Verhältnissen der Zeit. Wenn wir von unsrer Art, uns selbst innerlich anzuschauen und vermittelst dieser Anschauung auch alle äußere Anschauungen in der Vorstellungskraft zu befassen, abstrahiren und mithin die Gegenstände nehmen, so wie sie an sich selbst sein mögen, so ist die Zeit Nichts. Sie ist nur von objectiver Gültigkeit in Ansehung der Erscheinungen, weil dieses schon Dinge sind, die wir als Gegenstände unsrer Sinne annehmen; aber sie ist nicht mehr objectiv, wenn man von der Sinnlichkeit unsrer Anschauung, mithin derjenigen Vorstellungsart, welche uns eigenthümlich ist, abstrahirt und von Dingen überhaupt redet. Die Zeit ist also lediglich eine subjective Bedingung unserer (menschlichen) Anschauung (welche jederzeit sinnlich ist, d.i. so fern wir von Gegenständen afficirt werden) und an sich, außer dem Subjecte, nichts. Nichts desto weniger ist sie in Ansehung aller Erscheinungen, mithin auch aller Dinge, die uns in der Erfahrung vorkommen können, nothwendiger Weise objectiv. Wir können nicht sagen: alle Dinge sind in der Zeit, weil bei dem Begriff der Dinge überhaupt von aller Art der Anschauung derselben abstrahirt wird, diese aber die eigentliche Bedingung ist, unter der die Zeit in die Vorstellung der Gegenstände gehört. Wird nun die Bedingung zum Begriffe hinzugefügt, und es heißt: alle Dinge als Erscheinungen (Gegenstände der sinnlichen Anschauung) sind in der Zeit, so hat der Grundsatz seine gute objective Richtigkeit und Allgemeinheit _a priori_."}], "markers": [{"system": "A", "ref": "A32"}, {"system": "A", "ref": "A33"}, {"system": "A", "ref": "A34"}, {"system": "A", "ref": "A35"}], "running_header": "Schlüsse aus diesen Begriffen [Tr. Ästhetik, A, Anhang]"}, {"page_pdf": 1400, "page_book": null, "page_kind": "body", "sigel": "A36", "units": [{"type": "paragraph", "text": "Unsere Behauptungen lehren demnach empirische Realität der Zeit, d.i. objective Gültigkeit in Ansehung aller Gegenstände, die jemals unsern Sinnen gegeben werden mögen. Und da unsere Anschauung jederzeit sinnlich ist, so kann uns in der Erfahrung niemals ein Gegenstand gegeben werden, der nicht unter die Bedingung der Zeit gehörte. Dagegen streiten wir der Zeit allen Anspruch auf absolute Realität, da sie nämlich, auch ohne auf die Form unserer sinnlichen Anschauung Rücksicht zu nehmen, schlechthin den Dingen als Bedingung oder Eigenschaft anhinge. Solche Eigenschaften, die den Dingen an sich zukommen, können uns durch die Sinne auch niemals gegeben werden. Hierin besteht also die transscendentale Idealität der Zeit, nach welcher sie, wenn man von den subjectiven Bedingungen der sinnlichen Anschauung abstrahirt, gar nichts ist und den Gegenständen an sich selbst (ohne ihr Verhältniß auf unsere Anschauung) weder subsistirend noch inhärirend beigezählt werden kann. Doch ist diese Idealität eben so wenig wie die des Raumes mit den Subreptionen der Empfindungen in Vergleichung zu stellen, weil man doch dabei von der Erscheinung selbst, der diese Prädicate inhäriren, voraussetzt, daß sie objective Realität habe, die hier gänzlich wegfällt, außer so fern sie blos empirisch ist, d.i. den Gegenstand selbst blos als Erscheinung ansieht: wovon die obige Anmerkung des ersteren Abschnitts nachzusehen ist."}], "markers": [{"system": "A", "ref": "A36"}], "running_header": "Schlüsse aus diesen Begriffen [Tr. Ästhetik, A, Anhang]"}, {"page_pdf": 1401, "page_book": null, "page_kind": "body", "sigel": "A36 · A37 · A38 · A39", "units": [{"type": "paragraph", "text": "[A] Erläuterung. Wider diese Theorie, welche der Zeit empirische Realität zugesteht, aber die absolute und transscendentale streitet, habe ich von einsehenden Männern einen Einwurf so einstimmig vernommen, daß ich daraus abnehme, er müsse sich natürlicher Weise bei jedem Leser, dem diese Betrachtungen ungewohnt sind, vorfinden. Er lautet so: Veränderungen sind wirklich (dies beweiset der Wechsel unserer eigenen Vorstellungen, wenn man gleich alle äußere Erscheinungen sammt deren Veränderungen leugnen wollte). Nun sind Veränderungen nur in der Zeit möglich, folglich ist die Zeit etwas Wirkliches. Die Beantwortung hat keine Schwierigkeit. Ich gebe das ganze Argument zu. Die Zeit ist allerdings etwas Wirkliches, nämlich die wirkliche Form der innern Anschauung. Sie hat also subjective Realität in Ansehung der innern Erfahrung, d.i. ich habe wirklich die Vorstellung von der Zeit und meinen Bestimmungen in ihr. Sie ist also wirklich, nicht als Object, sondern als die Vorstellungsart meiner selbst als Objects anzusehen. Wenn aber ich selbst, oder ein ander Wesen mich ohne diese Bedingung der Sinnlichkeit anschauen könnte, so würden eben dieselben Bestimmungen, die wir uns jetzt als Veränderungen vorstellen, eine Erkenntniß geben, in welcher die Vorstellung der Zeit, mithin auch der Veränderung gar nicht vorkäme. Es bleibt also ihre empirische Realität als Bedingung aller unsrer Erfahrungen. Nur die absolute Realität kann ihr nach dem oben Angeführten nicht zugestanden werden. Sie ist nichts, als die Form unsrer inneren Anschauung.* Wenn man von ihr die besondere Bedingung unserer Sinnlichkeit wegnimmt, so verschwindet auch der Begriff der Zeit, und sie hängt nicht an den Gegenständen selbst, sondern blos am Subjecte, welches sie anschauet. Die Ursache aber, weswegen dieser Einwurf so einstimmig gemacht wird und zwar von denen, die gleichwohl gegen die Lehre von der Idealität des Raumes nichts Einleuchtendes einzuwenden wissen, ist diese. Die absolute Realität des Raumes hofften sie nicht apodiktisch darthun zu können, weil ihnen der Idealismus entgegen steht, nach welchem die Wirklichkeit äußerer Gegenstände keines strengen Beweises fähig ist: dagegen die des Gegenstandes unserer innern Sinnen (meiner selbst und meines Zustandes) unmittelbar durchs Bewußtsein klar ist. Jene konnten ein bloßer Schein sein, dieser aber ist ihrer Meinung nach unleugbar etwas Wirkliches. Sie bedachten aber nicht, daß beide, ohne daß man ihre Wirklichkeit als Vorstellungen bestreiten darf, gleichwohl nur zur Erscheinung gehören, welche jederzeit zwei Seiten hat, die eine, da das Object an sich selbst betrachtet wird (unangesehen der Art, dasselbe anzuschauen, dessen Beschaffenheit aber eben darum jederzeit problematisch bleibt), die andere, da auf die Form der Anschauung dieses Gegenstandes gesehen wird, welche nicht in dem Gegenstande an sich selbst, sondern im Subjecte, dem derselbe erscheint, gesucht werden muß, gleichwohl aber der Erscheinung dieses Gegenstandes wirklich und nothwendig zukommt. Zeit und Raum sind demnach zwei Erkenntnißquellen, aus denen _a priori_ verschiedene synthetische Erkenntnisse geschöpft werden können, wie vornehmlich die reine Mathematik in Ansehung der Erkenntnisse vom Raume und dessen Verhältnissen ein glänzendes Beispiel giebt. Sie sind nämlich beide zusammen genommen reine Formen aller sinnlichen Anschauung und machen dadurch synthetische Sätze _a priori _möglich. Aber diese Erkenntnißquellen _a priori_ bestimmen sich eben dadurch (daß sie blos Bedingungen der Sinnlichkeit sind) ihre Grenzen, nämlich daß sie blos auf Gegenstände gehen, so fern sie als Erscheinungen betrachtet werden, nicht aber Dinge an sich selbst darstellen. Jene allein sind das Feld ihrer Gültigkeit, woraus wenn man hinausgeht, weiter kein objectiver Gebrauch derselben statt findet. Diese Realität des Raumes und der Zeit läßt übrigens die Sicherheit der Erfahrungserkenntniß unangetastet: denn wir sind derselben eben so gewiß, ob diese Formen den Dingen an sich selbst, oder nur unsrer Anschauung dieser Dinge nothwendiger Weise anhängen. Dagegen die, so die absolute Realität des Raumes und der Zeit behaupten, sie mögen sie nun als subsistirend oder nur inhärirend annehmen, mit den Principien"}], "markers": [{"system": "A", "ref": "A36"}, {"system": "A", "ref": "A37"}, {"system": "A", "ref": "A38"}, {"system": "A", "ref": "A39"}], "running_header": "Erläuterung [Tr. Ästhetik, A, Anhang]"}, {"page_pdf": 1402, "page_book": null, "page_kind": "body", "sigel": "A40 · A41", "units": [{"type": "paragraph", "text": "der Erfahrung selbst uneinig sein müssen. Denn entschließen sie sich zum ersteren (welches gemeiniglich die Partei der mathematischen Naturforscher ist), so müssen sie zwei ewige und unendliche für sich bestehende Undinge (Raum und Zeit) annehmen, welche da sind, (ohne daß doch etwas Wirkliches ist) nur um alles Wirkliche in sich zu befassen. Nehmen sie die zweite Partei (von der einige metaphysische Naturlehrer sind) und Raum und Zeit gelten ihnen als von der Erfahrung abstrahirte, obzwar in der Absonderung verworren vorgestellte Verhältnisse der Erscheinungen (neben oder nach einander), so müssen sie den mathematischen Lehren _a priori _in Ansehung wirklicher Dinge (z.E. im Raume) ihre Gültigkeit, wenigstens die apodiktische Gewißheit streiten, indem diese _a posteriori _gar nicht statt findet, und die Begriffe _a priori _von Raum und Zeit dieser Meinung nach nur Geschöpfe der Einbildungskraft sind, deren Quell wirklich in der Erfahrung gesucht werden muß, aus deren abstrahirten Verhältnissen die Einbildung etwas gemacht hat, was zwar das Allgemeine derselben enthält, aber ohne die Restrictionen, welche die Natur mit denselben verknüpft hat, nicht statt finden kann. Die erstere gewinnen so viel, daß sie für die mathematische Behauptungen sich das Feld der Erscheinungen frei machen. Dagegen verwirren sie sich sehr durch eben diese Bedingungen, wenn der Verstand über dieses Feld hinausgehen will. Die zweite gewinnen zwar in Ansehung des letzteren, nämlich daß die Vorstellungen von Raum und Zeit ihnen nicht in den Weg kommen, wenn sie von Gegenständen nicht als Erscheinungen, sondern blos im Verhältniß auf den Verstand urtheilen wollen; können aber weder von der Möglichkeit mathematischer Erkenntnisse _a priori _(indem ihnen eine wahre und objectiv gültige Anschauung _a priori _fehlt) Grund angeben, noch die Erfahrungssätze mit jenen Behauptungen in nothwendige Einstimmung bringen. In unserer Theorie von der wahren Beschaffenheit dieser zwei ursprünglichen Formen der Sinnlichkeit ist beiden Schwierigkeiten abgeholfen. Daß schließlich die transscendentale Ästhetik nicht mehr als diese zwei Elemente, nämlich Raum und Zeit, enthalten könne, ist daraus klar, weil alle andre zur Sinnlichkeit gehörige Begriffe, selbst der der Bewegung, welcher beide Stücke vereinigt, etwas Empirisches voraussetzen. Denn diese setzt die Wahrnehmung von etwas Beweglichem voraus. Im Raum, an sich selbst betrachtet, ist aber nichts Bewegliches: daher das Bewegliche etwas sein muß, was im Raume nur durch Erfahrung gefunden wird, mithin ein empirisches Datum. Eben so kann die transscendentale Ästhetik nicht den Begriff der Veränderung unter ihre Data _a priori _zählen: denn die Zeit selbst verändert sich nicht, sondern etwas, das in der Zeit ist. Also wird dazu die Wahrnehmung von irgend einem Dasein und der Succession seiner Bestimmungen, mithin Erfahrung erfordert."}, {"type": "paragraph", "text": "Anmerkungen: * Ich kann zwar sagen: meine Vorstellungen folgen einander; aber das heißt nur: wir sind uns ihrer als in einer Zeitfolge, d.i. nach der Form des innern Sinnes, bewußt. Die Zeit ist darum nicht etwas an sich selbst, auch keine den Dingen objectiv anhängende Bestimmung."}], "markers": [{"system": "A", "ref": "A40"}, {"system": "A", "ref": "A41"}], "running_header": "Erläuterung [Tr. Ästhetik, A, Anhang]"}, {"page_pdf": 1403, "page_book": null, "page_kind": "body", "sigel": "A41 · A42 · A43 · A44", "units": [{"type": "paragraph", "text": "[A] Allgemeine Anmerkungen zur Transscendentalen Ästhetik. Zuerst wird es nöthig sein, uns so deutlich als möglich zu erklären, was in Ansehung der Grundbeschaffenheit der sinnlichen Erkenntniß überhaupt unsre Meinung sei, um aller Mißdeutung derselben vorzubeugen. Wir haben also sagen wollen: daß alle unsre Anschauung nichts als die Vorstellung von Erscheinung sei; daß die Dinge, die wir anschauen, nicht das an sich selbst sind, wofür wir sie anschauen, noch ihre Verhältnisse so an sich selbst beschaffen sind, als sie uns erscheinen, und daß, wenn wir unser Subject oder auch nur die subjective Beschaffenheit der Sinne überhaupt aufheben, alle die Beschaffenheit, alle Verhältnisse der Objecte im Raum und Zeit, ja selbst Raum und Zeit verschwinden würden und als Erscheinungen nicht an sich selbst, sondern nur in uns existiren können. Was es für eine Bewandtniß mit den Gegenständen an sich und abgesondert von aller dieser Receptivität unserer Sinnlichkeit haben möge, bleibt uns gänzlich unbekannt. Wir kennen nichts als unsere Art, sie wahrzunehmen, die uns eigenthümlich ist, die auch nicht nothwendig jedem Wesen, obzwar jedem Menschen zukommen muß. Mit dieser haben wir es lediglich zu thun. Raum und Zeit sind die reine Formen derselben, Empfindung überhaupt die Materie. Jene können wir allein _a priori_, d.i. vor aller wirklichen Wahrnehmung, erkennen, und sie heißt darum reine Anschauung; diese aber ist das in unserm Erkenntniß, was da macht, daß es Erkenntniß _a posteriori_, d.i. empirische Anschauung, heißt. Jene hängen unsrer Sinnlichkeit schlechthin nothwendig an, welcher Art auch unsere Empfindungen sein mögen; diese können sehr verschieden sein. Wenn wir diese unsre Anschauung auch zum höchsten Grade der Deutlichkeit bringen könnten, so würden wir dadurch der Beschaffenheit der Gegenstände an sich selbst nicht näher kommen. Denn wir würden auf allen Fall doch nur unsre Art der Anschauung, d.i. unsere Sinnlichkeit, vollständig erkennen und diese immer nur unter den dem Subject ursprünglich anhängenden Bedingungen von Raum und Zeit; was die Gegenstände an sich selbst sein mögen, würde uns durch die aufgeklärteste Erkenntniß der Erscheinung derselben, die uns allein gegeben ist, doch niemals bekannt werden. Daß daher unsere ganze Sinnlichkeit nichts als die verworrene Vorstellung der Dinge sei, welche lediglich das enthält, was ihnen an sich selbst zukommt, aber nur unter einer Zusammenhäufung von Merkmalen und Theilvorstellungen, die wir nicht mit Bewußtsein auseinander setzen, ist eine Verfälschung des Begriffs von Sinnlichkeit und von Erscheinung, welche die ganze Lehre derselben unnütz und leer macht. Der Unterschied einer undeutlichen von der deutlichen Vorstellung ist blos logisch und betrifft nicht den Inhalt. Ohne Zweifel enthält der Begriff von Recht, dessen sich der gesunde Verstand bedient, eben dasselbe, was die subtilste Speculation aus ihm entwickeln kann, nur daß im gemeinen und praktischen Gebrauche man sich dieser mannigfaltigen Vorstellungen in diesem Gedanken nicht bewußt ist. Darum kann man nicht sagen, daß der gemeine Begriff sinnlich sei und eine bloße Erscheinung enthalte; denn das Recht kann gar nicht erscheinen, sondern sein Begriff liegt im Verstande und stellt eine Beschaffenheit (die moralische) der Handlungen vor, die ihnen an sich selbst zukommt. Dagegen enthält die Vorstellung eines Körpers in der Anschauung gar nichts, was einem Gegenstande an sich selbst zukommen könnte, sondern blos die Erscheinung von Etwas und die Art, wie wir dadurch afficirt werden; und diese Receptivität unserer Erkenntnißfähigkeit heißt Sinnlichkeit und bleibt von der Erkenntniß des Gegenstandes an sich selbst, ob man jene (die Erscheinung) gleich bis auf den Grund durchschauen möchte, dennoch himmelweit unterschieden. Die Leibniz-Wolffische Philosophie hat daher allen Untersuchungen über die Natur und den Ursprung unserer Erkenntnisse einen ganz unrechten Gesichtspunkt angewiesen, indem sie den Unterschied der Sinnlichkeit vom Intellectuellen blos als logisch betrachtete, da er offenbar transscendental ist und nicht blos die Form der Deutlichkeit oder Undeutlichkeit, sondern den Ursprung und den Inhalt derselben betrifft, so daß wir durch die erstere die Beschaffenheit der"}], "markers": [{"system": "A", "ref": "A41"}, {"system": "A", "ref": "A42"}, {"system": "A", "ref": "A43"}, {"system": "A", "ref": "A44"}], "running_header": "Allgemeine Anmerkungen zur Transscendentalen Ästhetik [A, Anhang]"}, {"page_pdf": 1404, "page_book": null, "page_kind": "body", "sigel": "A45 · A46 · A47", "units": [{"type": "paragraph", "text": "Dinge an sich selbst nicht blos undeutlich, sondern gar nicht erkennen, und so bald wir unsre subjective Beschaffenheit wegnehmen, das vorgestellte Object mit den Eigenschaften, die ihm die sinnliche Anschauung beilegte, überall nirgend anzutreffen ist, noch angetroffen werden kann, indem eben diese subjective Beschaffenheit die Form desselben als Erscheinung bestimmt. Wir unterscheiden sonst wohl unter Erscheinungen das, was der Anschauung derselben wesentlich anhängt und für jeden menschlichen Sinn überhaupt gilt, von demjenigen, was derselben nur zufälliger Weise zukommt, indem es nicht auf die Beziehung der Sinnlichkeit überhaupt, sondern nur auf eine besondre Stellung oder Organisation dieses oder jenes Sinnes gültig ist. Und da nennt man die erstere Erkenntniß eine solche, die den Gegenstand an sich selbst vorstellt, die zweite aber nur die Erscheinung desselben. Dieser Unterschied ist aber nur empirisch. Bleibt man dabei stehen (wie es gemeiniglich geschieht) und sieht jene empirische Anschauung nicht wiederum (wie es geschehen sollte) als bloße Erscheinung an, so daß darin gar nichts, was irgend eine Sache an sich selbst anginge, anzutreffen ist, so ist unser transscendentaler Unterschied verloren, und wir glauben alsdann doch, Dinge an sich zu erkennen, ob wir es gleich überall (in der Sinnenwelt), selbst bis zu der tiefsten Erforschung ihrer Gegenstände, mit nichts als Erscheinungen zu thun haben. So werden wir zwar den Regenbogen eine bloße Erscheinung bei einem Sonnregen nennen, diesen Regen aber die Sache an sich selbst, welches auch richtig ist, so fern wir den letztern Begriff nur physisch verstehen als das, was in der allgemeinen Erfahrung unter allen verschiedenen Lagen zu den Sinnen, doch in der Anschauung so und nicht anders bestimmt ist. Nehmen wir aber dieses Empirische überhaupt und fragen, ohne uns an die Einstimmung desselben mit jedem Menschensinne zu kehren, ob auch dieses einen Gegenstand an sich selbst (nicht die Regentropfen, denn die sind dann schon als Erscheinungen empirische Objecte) vorstelle: so ist die Frage von der Beziehung der Vorstellung auf den Gegenstand transscendental, und nicht allein diese Tropfen sind bloße Erscheinungen, sondern selbst ihre runde Gestalt, ja sogar der Raum, in welchem sie fallen, sind nichts an sich selbst, sondern bloße Modificationen oder Grundlagen unserer sinnlichen Anschauung; das transscendentale Object aber bleibt uns unbekannt. Die zweite wichtige Angelegenheit unserer transscendentalen Ästhetik ist, daß sie nicht blos als scheinbare Hypothese einige Gunst erwerbe, sondern so gewiß und ungezweifelt sei, als jemals von einer Theorie gefordert werden kann, die zum Organon dienen soll. Um diese Gewißheit völlig einleuchtend zu machen, wollen wir irgend einen Fall wählen, woran dessen Gültigkeit augenscheinlich werden kann. Setzet demnach, Raum und Zeit seien an sich selbst objectiv und Bedingungen der Möglichkeit der Dinge an sich selbst, so zeigt sich erstlich: daß von beiden _a priori _apodiktische und synthetische Sätze in großer Zahl, vornehmlich vom Raum, vorkommen, welchen wir darum vorzüglich hier zum Beispiel untersuchen wollen. Da die Sätze der Geometrie synthetisch _a priori_, und mit apodiktischer Gewißheit erkannt werden, so frage ich: woher nehmt ihr dergleichen Sätze, und worauf stützt sich unser Verstand, um zu dergleichen schlechthin nothwendigen und allgemein gültigen Wahrheiten zu gelangen? Es ist kein anderer Weg, als durch Begriffe oder durch Anschauungen; beide aber als solche, die entweder _a priori _oder _a posteriori _gegeben sind. Die letztere, nämlich empirische Begriffe, imgleichen das, worauf sie sich gründen, die empirische Anschauung, können keinen synthetischen Satz geben, als nur einen solchen, der auch blos empirisch, d.i. ein Erfahrungssatz ist, mithin niemals Nothwendigkeit und absolute Allgemeinheit enthalten kann, dergleichen doch das Charakteristische aller Sätze der Geometrie ist. Was aber das erstere und einzige Mittel sein würde, nämlich durch bloße Begriffe oder durch Anschauungen _a priori _zu dergleichen Erkenntnissen zu gelangen, so ist klar, daß aus bloßen Begriffen gar keine synthetische Erkenntniß, sondern lediglich analytische erlangt werden kann. Nehmet nur den Satz, daß durch zwei gerade Linien sich gar kein Raum einschließen lasse, mithin keine Figur möglich"}], "markers": [{"system": "A", "ref": "A45"}, {"system": "A", "ref": "A46"}, {"system": "A", "ref": "A47"}], "running_header": "Allgemeine Anmerkungen zur Transscendentalen Ästhetik [A, Anhang]"}, {"page_pdf": 1405, "page_book": null, "page_kind": "body", "sigel": "A48 · A49", "units": [{"type": "paragraph", "text": "sei, und versucht ihn aus dem Begriff von geraden Linien und der Zahl zwei abzuleiten, oder auch, daß aus drei geraden Linien eine Figur möglich sei, und versucht es eben so blos aus diesen Begriffen. Alle eure Bemühung ist vergeblich, und ihr seht euch genöthigt, zur Anschauung eure Zuflucht zu nehmen, wie es die Geometrie auch jederzeit thut. Ihr gebt euch also einen Gegenstand in der Anschauung; von welcher Art aber ist diese, ist es eine reine Anschauung _a priori _oder eine empirische? Wäre das letzte, so könnte niemals ein allgemein gültiger, noch weniger ein apodiktischer Satz daraus werden: denn Erfahrung kann dergleichen niemals liefern. Ihr müßt also euren Gegenstand _a _ _priori _in der Anschauung geben und auf diesen euren synthetischen Satz gründen. Läge nun in euch nicht ein Vermögen, _a priori _anzuschauen; wäre diese subjective Bedingung der Form nach nicht zugleich die allgemeine Bedingung _a priori_, unter der allein das Object dieser (äußeren) Anschauung selbst möglich ist; wäre der Gegenstand (der Triangel) etwas an sich selbst ohne Beziehung auf euer Subject: wie könntet ihr sagen, daß, was in euren subjectiven Bedingungen einen Triangel zu construiren nothwendig liegt, auch dem Triangel an sich selbst nothwendig zukommen müsse? Denn ihr könntet doch zu euren Begriffen (von drei Linien) nichts Neues (die Figur) hinzufügen, welches darum nothwendig an dem Gegenstande angetroffen werden müßte, da dieser vor eurer Erkenntniß und nicht durch dieselbe gegeben ist. Wäre also nicht der Raum (und so auch die Zeit) eine bloße Form eurer Anschauung, welche Bedingungen _a priori _enthält, unter denen allein Dinge für euch äußere Gegenstände sein können, die ohne diese subjective Bedingungen an sich nichts sind, so könntet ihr _a priori _ganz und gar nichts über äußere Objecte synthetisch ausmachen. Es ist also ungezweifelt gewiß und nicht blos möglich oder auch wahrscheinlich, daß Raum und Zeit, als die nothwendige Bedingungen aller (äußern und innern) Erfahrung, blos subjective Bedingungen aller unsrer Anschauung sind, im Verhältniß auf welche daher alle Gegenstände bloße Erscheinungen und nicht für sich in dieser Art gegebene Dinge sind, von denen sich auch um deswillen, was die Form derselben betrifft, vieles _a priori _sagen läßt, niemals aber das Mindeste von dem Dinge an sich selbst, das diesen Erscheinungen zum Grunde liegen mag."}, {"type": "paragraph", "text": "__________"}], "markers": [{"system": "A", "ref": "A48"}, {"system": "A", "ref": "A49"}], "running_header": "Allgemeine Anmerkungen zur Transscendentalen Ästhetik [A, Anhang]"}, {"page_pdf": 1406, "page_book": null, "page_kind": "body", "sigel": "A95 · A96 · A97", "units": [{"type": "paragraph", "text": "[A] Der Deduction der reinen Verstandesbegriffe"}, {"type": "heading", "text": "Zweiter Abschnitt.", "level": 2}, {"type": "paragraph", "text": "Von den Gründen _a priori_ zur Möglichkeit der Erfahrung. Daß ein Begriff völlig _a priori_ erzeugt werden und sich auf einen Gegenstand beziehen solle, obgleich er weder selbst in den Begriff möglicher Erfahrung gehört, noch aus Elementen einer möglichen Erfahrung besteht, ist gänzlich widersprechend und unmöglich. Denn er würde alsdann keinen Inhalt haben, darum weil ihm keine Anschauung correspondirte, indem Anschauungen überhaupt, wodurch uns Gegenstände gegeben werden können, das Feld oder den gesammten Gegenstand möglicher Erfahrung ausmachen. Ein Begriff _a priori_, der sich nicht auf diese bezöge, würde nur die logische Form zu einem Begriff, aber nicht der Begriff selbst sein, wodurch etwas gedacht würde. Wenn es also reine Begriffe _a priori_ giebt, so können diese zwar freilich nichts Empirisches enthalten: sie müssen aber gleichwohl lauter Bedingungen _a priori_ zu einer möglichen Erfahrung sein, als worauf allein ihre objective Realität beruhen kann. Will man daher wissen, wie reine Verstandesbegriffe möglich seien, so muß man untersuchen, welches die Bedingungen _a priori_ seien, worauf die Möglichkeit der Erfahrung ankommt, und die ihr zum Grunde liegen, wenn man gleich von allem Empirischen der Erscheinungen abstrahirt. Ein Begriff, der diese formale und objective Bedingung der Erfahrung allgemein und zureichend ausdrückt, würde ein reiner Verstandesbegriff heißen. Habe ich einmal reine Verstandesbegriffe, so kann ich auch wohl Gegenstände erdenken, die vielleicht unmöglich, vielleicht zwar an sich möglich, aber in keiner Erfahrung gegeben werden können, indem in der Verknüpfung jener Begriffe etwas weggelassen sein kann, was doch zur Bedingung einer möglichen Erfahrung nothwendig gehört (Begriff eines Geistes), oder etwa reine Verstandesbegriffe weiter ausgedehnt werden, als Erfahrung fassen kann (Begriff von Gott). Die Elemente aber zu allen Erkenntnissen _a priori_, selbst zu willkürlichen und ungereimten Erdichtungen können zwar nicht von der Erfahrung entlehnt sein (denn sonst wären sie nicht Erkenntnisse _a priori_); sie müssen aber jederzeit die reine Bedingungen _a priori_ einer möglichen Erfahrung und eines Gegenstandes derselben enthalten, denn sonst würde nicht allein durch sie gar nichts gedacht werden, sondern sie selber würden ohne Data auch nicht einmal im Denken entstehen können. Diese Begriffe nun, welche _a priori_ das reine Denken bei jeder Erfahrung enthalten, finden wir an den Kategorien; und es ist schon eine hinreichende Deduction derselben und Rechtfertigung ihrer objectiven Gültigkeit, wenn wir beweisen können, daß vermittelst ihrer allein ein Gegenstand gedacht werden kann. Weil aber in einem solchen Gedanken mehr als das einzige Vermögen zu denken, nämlich der Verstand, beschäftigt ist, und dieser selbst als ein Erkenntnißvermögen, das sich auf Objecte beziehen soll, eben so wohl einer Erläuterung wegen der Möglichkeit dieser Beziehung bedarf: so müssen wir die subjective Quellen, welche die Grundlage _a priori_ zu der Möglichkeit der Erfahrung ausmachen, nicht nach ihrer empirischen, sondern transscendentalen Beschaffenheit zuvor erwägen. Wenn eine jede einzelne Vorstellung der andern ganz fremd, gleichsam isolirt und von dieser getrennt wäre, so würde niemals so etwas, als Erkenntniß ist, entspringen, welche ein Ganzes verglichener und verknüpfter Vorstellungen ist. Wenn ich also dem Sinne deswegen, weil er in seiner Anschauung Mannigfaltigkeit enthält, eine Synopsis beilege, so correspondirt dieser jederzeit eine Synthesis, und die Receptivität kann nur mit Spontaneität verbunden Erkenntnisse möglich machen. Diese ist nun der Grund einer dreifachen Synthesis, die nothwendiger Weise in allem Erkenntniß vorkommt: nämlich der Apprehension der Vorstellungen als Modificationen des Gemüths in der Anschauung, der Reproduction derselben in der Einbildung und ihrer Recognition im Begriffe. Diese geben nun eine Leitung"}], "markers": [{"system": "A", "ref": "A95"}, {"system": "A", "ref": "A96"}, {"system": "A", "ref": "A97"}], "running_header": "Deduction [...] II. Von den Gründen a priori zur Möglichkeit der Erfahrung [A, Anhang]"}, {"page_pdf": 1407, "page_book": null, "page_kind": "body", "sigel": "A98", "units": [{"type": "paragraph", "text": "auf drei subjective Erkenntnißquellen, welche selbst den Verstand und durch diesen alle Erfahrung als ein empirisches Product des Verstandes möglich machen."}], "markers": [{"system": "A", "ref": "A98"}], "running_header": "Deduction [...] II. Von den Gründen a priori zur Möglichkeit der Erfahrung [A, Anhang]"}, {"page_pdf": 1408, "page_book": null, "page_kind": "body", "sigel": "A98", "units": [{"type": "paragraph", "text": "[A] Vorläufige Erinnerung. Die Deduction der Kategorien ist mit so viel Schwierigkeiten verbunden und nöthigt, so tief in die erste Gründe der Möglichkeit unsrer Erkenntniß überhaupt einzudringen, daß ich, um die Weitläuftigkeit einer vollständigen Theorie zu vermeiden und dennoch bei einer so nothwendigen Untersuchung nichts zu versäumen, es rathsamer gefunden habe, durch folgende vier Nummern den Leser mehr vorzubereiten als zu unterrichten und im nächstfolgenden, dritten Abschnitte die Erörterung dieser Elemente des Verstandes allererst systematisch vorzustellen. Um deswillen wird sich der Leser bis dahin durch die Dunkelheit nicht abwendig machen lassen, die auf einem Wege, der noch ganz unbetreten ist, anfänglich unvermeidlich ist, sich aber, wie ich hoffe, in gedachtem Abschnitte zur vollständigen Einsicht aufklären soll."}], "markers": [{"system": "A", "ref": "A98"}], "running_header": "Vorläufige Erinnerung [A, Anhang]"}, {"page_pdf": 1409, "page_book": null, "page_kind": "body", "sigel": "A98 · A99 · A100", "units": [{"type": "paragraph", "text": "[A] 1. Von der Synthesis der Apprehension in der Anschauung. Unsere Vorstellungen mögen entspringen, woher sie wollen, ob sie durch den Einfluß äußerer Dinge oder durch innere Ursachen gewirkt sind, sie mögen _a priori_ oder empirisch als Erscheinungen entstanden sein: so gehören sie doch als Modificationen des Gemüths zum innern Sinn, und als solche sind alle unsere Erkenntnisse zuletzt doch der formalen Bedingung des innern Sinnes, nämlich der Zeit, unterworfen, als in welcher sie insgesammt geordnet, verknüpft und in Verhältnisse gebracht werden müssen. Dieses ist eine allgemeine Anmerkung, die man bei dem folgenden durchaus zum Grunde legen muß. Jede Anschauung enthält ein Mannigfaltiges in sich, welches doch nicht als ein solches vorgestellt werden würde, wenn das Gemüth nicht die Zeit in der Folge der Eindrücke auf einander unterschiede: denn als in einem Augenblick enthalten kann jede Vorstellung niemals etwas anderes als absolute Einheit sein. Damit nun aus diesem Mannigfaltigen Einheit der Anschauung werde (wie etwa in der Vorstellung des Raumes), so ist erstlich das Durchlaufen der Mannigfaltigkeit und dann die Zusammennehmung desselben nothwendig, welche Handlung ich die Synthesis der Apprehension nenne, weil sie gerade zu auf die Anschauung gerichtet ist, die zwar ein Mannigfaltiges darbietet, dieses aber als ein solches und zwar in einer Vorstellung enthalten niemals ohne eine dabei vorkommende Synthesis bewirken kann. Diese Synthesis der Apprehension muß nun auch _a priori_, d.i. in Ansehung der Vorstellungen, die nicht empirisch sind, ausgeübt werden. Denn ohne sie würden wir weder die Vorstellungen des Raumes, noch der Zeit _a priori_ haben können: da diese nur durch die Synthesis des Mannigfaltigen, welches die Sinnlichkeit in ihrer ursprünglichen Receptivität darbietet, erzeugt werden können. Also haben wir eine reine Synthesis der Apprehension."}], "markers": [{"system": "A", "ref": "A98"}, {"system": "A", "ref": "A99"}, {"system": "A", "ref": "A100"}], "running_header": "1. Von der Synthesis der Apprehension in der Anschauung [A, Anhang]"}, {"page_pdf": 1410, "page_book": null, "page_kind": "body", "sigel": "A100 · A101 · A102", "units": [{"type": "paragraph", "text": "[A] 2. Von der Synthesis der Reproduction in der Einbildung. Es ist zwar ein blos empirisches Gesetz, nach welchem Vorstellungen, die sich oft gefolgt oder begleitet haben, sich mit einander endlich vergesellschaften und dadurch in eine Verknüpfung setzen, nach welcher auch ohne die Gegenwart des Gegenstandes eine dieser Vorstellungen einen Übergang des Gemüths zu der andern nach einer beständigen Regel hervorbringt. Dieses Gesetz der Reproduction setzt aber voraus: daß die Erscheinungen selbst wirklich einer solchen Regel unterworfen seien, und daß in dem Mannigfaltigen ihrer Vorstellungen eine gewissen Regeln gemäße Begleitung oder Folge statt finde; denn ohne das würde unsere empirische Einbildungskraft niemals etwas ihrem Vermögen Gemäßes zu thun bekommen, also wie ein todtes und uns selbst unbekanntes Vermögen im Inneren des Gemüths verborgen bleiben. Würde der Zinnober bald roth, bald schwarz, bald leicht, bald schwer sein, ein Mensch bald in diese, bald in jene thierische Gestalt verändert werden, am längsten Tage bald das Land mit Früchten, bald mit Eis und Schnee bedeckt sein, so könnte meine empirische Einbildungskraft nicht einmal Gelegenheit bekommen, bei der Vorstellung der rothen Farbe den schweren Zinnober in die Gedanken zu bekommen; oder würde ein gewisses Wort bald diesem, bald jenem Dinge beigelegt, oder auch eben dasselbe Ding bald so, bald anders benannt, ohne daß hierin eine gewisse Regel, der die Erscheinungen schon von selbst unterworfen sind, herrschte, so könnte keine empirische Synthesis der Reproduction statt finden. Es muß also etwas sein, was selbst diese Reproduction der Erscheinungen möglich macht, dadurch daß es der Grund _a priori_ einer nothwendigen synthetischen Einheit derselben ist. Hierauf aber kommt man bald, wenn man sich besinnt, daß Erscheinungen nicht Dinge an sich selbst, sondern das bloße Spiel unserer Vorstellungen sind, die am Ende auf Bestimmungen des inneren Sinnes auslaufen. Wenn wir nun darthun können, daß selbst unsere reinste Anschauungen _a priori_ keine Erkenntniß verschaffen, außer so fern sie eine solche Verbindung des Mannigfaltigen enthalten, die eine durchgängige Synthesis der Reproduction möglich macht, so ist diese Synthesis der Einbildungskraft auch vor aller Erfahrung auf Principien _a priori_ gegründet, und man muß eine reine transscendentale Synthesis derselben annehmen, die selbst der Möglichkeit aller Erfahrung (als welche die Reproducibilität der Erscheinungen nothwendig voraussetzt) zum Grunde liegt. Nun ist offenbar, daß, wenn ich eine Linie in Gedanken ziehe, oder die Zeit von einem Mittag zum andern denken, oder auch nur eine gewisse Zahl mir vorstellen will, ich erstlich nothwendig eine dieser mannigfaltigen Vorstellungen nach der andern in Gedanken fassen müsse. Würde ich aber die vorhergehende (die erste Theile der Linie, die vorhergehende Theile der Zeit oder die nach einander vorgestellte Einheiten) immer aus den Gedanken verlieren und sie nicht reproduciren, indem ich zu den folgenden fortgehe, so würde niemals eine ganze Vorstellung und keiner aller vorgenannten Gedanken, ja gar nicht einmal die reinste und erste Grundvorstellungen von Raum und Zeit entspringen können. Die Synthesis der Apprehension ist also mit der Synthesis der Reproduction unzertrennlich verbunden. Und da jene den transscendentalen Grund der Möglichkeit aller Erkenntnisse überhaupt (nicht blos der empirischen, sondern auch der reinen _a priori_) ausmacht, so gehört die reproductive Synthesis der Einbildungskraft zu den transscendentalen Handlungen des Gemüths, und in Rücksicht auf dieselbe wollen wir dieses Vermögen auch das transscendentale Vermögen der Einbildungskraft nennen."}], "markers": [{"system": "A", "ref": "A100"}, {"system": "A", "ref": "A101"}, {"system": "A", "ref": "A102"}], "running_header": "2. Von der Synthesis der Reproduction in der Einbildung [A, Anhang]"}, {"page_pdf": 1411, "page_book": null, "page_kind": "body", "sigel": "A103 · A104 · A105 · A106", "units": [{"type": "paragraph", "text": "[A] 3. Von der Synthesis der Recognition im Begriffe. Ohne Bewußtsein, daß das, was wir denken, eben dasselbe sei, was wir einen Augenblick zuvor dachten, würde alle Reproduction in der Reihe der Vorstellungen vergeblich sein. Denn es wäre eine neue Vorstellung im jetzigen Zustande, die zu dem Actus, wodurch sie nach und nach hat erzeugt werden sollen, gar nicht gehörte, und das Mannigfaltige derselben würde immer kein Ganzes ausmachen, weil es der Einheit ermangelte, die ihm nur das Bewußtsein verschaffen kann. Vergesse ich im Zählen, daß die Einheiten, die mir jetzt vor Sinnen schweben, nach und nach zu einander von mir hinzugethan worden sind, so würde ich die Erzeugung der Menge durch diese successive Hinzuthuung von Einem zu Einem, mithin auch nicht die Zahl erkennen; denn dieser Begriff besteht lediglich in dem Bewußtsein dieser Einheit der Synthesis. Das Wort Begriff könnte uns schon von selbst zu dieser Bemerkung Anleitung geben. Denn dieses eine Bewußtsein ist es, was das Mannigfaltige, nach und nach Angeschaute und dann auch Reproducirte in eine Vorstellung vereinigt. Dieses Bewußtsein kann oft nur schwach sein, so daß wir es nur in der Wirkung, nicht aber in dem Actus selbst, d.i. unmittelbar, mit der Erzeugung der Vorstellung verknüpfen: aber unerachtet dieser Unterschiede muß doch immer ein Bewußtsein angetroffen werden, wenn ihm gleich die hervorstechende Klarheit mangelt, und ohne dasselbe sind Begriffe und mit ihnen Erkenntniß von Gegenständen ganz unmöglich. Und hier ist es denn nothwendig, sich darüber verständlich zu machen, was man denn unter dem Ausdruck eines Gegenstandes der Vorstellungen meine. Wir haben oben gesagt, daß Erscheinungen selbst nichts als sinnliche Vorstellungen sind, die an sich in eben derselben Art nicht als Gegenstände (außer der Vorstellungskraft) müssen angesehen werden. Was versteht man denn, wenn man von einem der Erkenntniß correspondirenden, mithin auch davon unterschiedenen Gegenstande redet? Es ist leicht einzusehen, daß dieser Gegenstand nur als etwas überhaupt =_X_ müsse gedacht werden, weil wir außer unserer Erkenntniß doch nichts haben, welches wir dieser Erkenntniß als correspondirend gegenübersetzen könnten. Wir finden aber, daß unser Gedanke von der Beziehung aller Erkenntniß auf ihren Gegenstand etwas von Nothwendigkeit bei sich führe, da nämlich dieser als dasjenige angesehen wird, was dawider ist, daß unsere Erkenntnisse nicht aufs Gerathewohl oder beliebig, sondern _a priori_ auf gewisse Weise bestimmt sind: weil, indem sie sich auf einen Gegenstand beziehen sollen, sie auch nothwendiger Weise in Beziehung auf diesen unter einander übereinstimmen, d.i. diejenige Einheit haben müssen, welche den Begriff von einem Gegenstande ausmacht. Es ist aber klar, daß, da wir es nur mit dem Mannigfaltigen unserer Vorstellungen zu thun haben, und jenes _X_, was ihnen correspondirt (der Gegenstand), weil er etwas von allen unsern Vorstellungen Unterschiedenes sein soll, für uns nichts ist, die Einheit, welche der Gegenstand nothwendig macht, nichts anders sein könne, als die formale Einheit des Bewußtseins in der Synthesis des Mannigfaltigen der Vorstellungen. Alsdann sagen wir: wir erkennen den Gegenstand, wenn wir in dem Mannigfaltigen der Anschauung synthetische Einheit bewirkt haben. Diese ist aber unmöglich, wenn die Anschauung nicht durch eine solche Function der Synthesis nach einer Regel hat hervorgebracht werden können, welche die Reproduction des Mannigfaltigen _a priori_ nothwendig und einen Begriff, in welchem dieses sich vereinigt, möglich macht. So denken wir uns einen Triangel als Gegenstand, indem wir uns der Zusammensetzung von drei geraden Linien nach einer Regel bewußt sind, nach welcher eine solche Anschauung jederzeit dargestellt werden kann. Diese Einheit der Regel bestimmt nun alles Mannigfaltige und schränkt es auf Bedingungen ein, welche die Einheit der Apperception möglich machen; und der Begriff dieser Einheit ist die Vorstellung vom Gegenstande =_X_, den ich durch die gedachte Prädicate eines Triangels denke. Alles Erkenntniß erfordert einen Begriff, dieser mag nun so unvollkommen oder so dunkel sein, wie er wolle; dieser aber ist seiner Form nach jederzeit etwas Allgemeines, und was zur"}], "markers": [{"system": "A", "ref": "A103"}, {"system": "A", "ref": "A104"}, {"system": "A", "ref": "A105"}, {"system": "A", "ref": "A106"}], "running_header": "3. Von der Synthesis der Recognition im Begriffe [A, Anhang]"}, {"page_pdf": 1412, "page_book": null, "page_kind": "body", "sigel": "A107 · A108 · A109", "units": [{"type": "paragraph", "text": "Regel dient. So dient der Begriff vom Körper nach der Einheit des Mannigfaltigen, welches durch ihn gedacht wird, unserer Erkenntniß äußerer Erscheinungen zur Regel. Eine Regel der Anschauungen kann er aber nur dadurch sein, daß er bei gegebenen Erscheinungen die nothwendige Reproduction des Mannigfaltigen derselben, mithin die synthetische Einheit in ihrem Bewußtsein vorstellt. So macht der Begriff des Körpers bei der Wahrnehmung von Etwas außer uns die Vorstellung der Ausdehnung und mit ihr die der Undurchdringlichkeit, der Gestalt etc. nothwendig. Aller Nothwendigkeit liegt jederzeit eine transscendentale Bedingung zum Grunde. Also muß ein transscendentaler Grund der Einheit des Bewußtseins in der Synthesis des Mannigfaltigen aller unserer Anschauungen, mithin auch der Begriffe der Objecte überhaupt, folglich auch aller Gegenstände der Erfahrung angetroffen werden, ohne welchen es unmöglich wäre, zu unsern Anschauungen irgend einen Gegenstand zu denken: denn dieser ist nichts mehr als das Etwas, davon der Begriff eine solche Nothwendigkeit der Synthesis ausdrückt. Diese ursprüngliche und transscendentale Bedingung ist nun keine andere, als die transscendentale Apperception. Das Bewußtsein seiner selbst nach den Bestimmungen unseres Zustandes bei der innern Wahrnehmung ist blos empirisch, jederzeit wandelbar, es kann kein stehendes oder bleibendes Selbst in diesem Flusse innrer Erscheinungen geben, und wird gewöhnlich der innre Sinn genannt, oder die empirische Apperception. Das, was nothwendig als numerisch identisch vorgestellt werden soll, kann nicht als ein solches durch empirische Data gedacht werden. Es muß eine Bedingung sein, die vor aller Erfahrung vorhergeht und diese selbst möglich macht, welche eine solche transscendentale Voraussetzung geltend machen soll. Nun können keine Erkenntnisse in uns statt finden, keine Verknüpfung und Einheit derselben unter einander ohne diejenige Einheit des Bewußtseins, welche vor allen Datis der Anschauungen vorhergeht, und worauf in Beziehung alle Vorstellung von Gegenständen allein möglich ist. Dieses reine, ursprüngliche, unwandelbare Bewußtsein will ich nun die transscendentale Apperception nennen. Daß sie diesen Namen verdiene, erhellt schon daraus: daß selbst die reinste objective Einheit, nämlich die der Begriffe _a priori_ (Raum und Zeit), nur durch Beziehung der Anschauungen auf sie möglich sei. Die numerische Einheit dieser Apperception liegt also _a _ _priori_ allen Begriffen eben so wohl zum Grunde, als die Mannigfaltigkeit des Raumes und der Zeit den Anschauungen der Sinnlichkeit. Eben diese transscendentale Einheit der Apperception macht aber aus allen möglichen Erscheinungen, die immer in einer Erfahrung beisammen sein können, einen Zusammenhang aller dieser Vorstellungen nach Gesetzen. Denn diese Einheit des Bewußtseins wäre unmöglich, wenn nicht das Gemüth in der Erkenntniß des Mannigfaltigen sich der Identität der Function bewußt werden könnte, wodurch sie dasselbe synthetisch in einer Erkenntniß verbindet. Also ist das ursprüngliche und nothwendige Bewußtsein der Identität seiner selbst zugleich ein Bewußtsein einer eben so nothwendigen Einheit der Synthesis aller Erscheinungen nach Begriffen, d.i. nach Regeln, die sie nicht allein nothwendig reproducibel machen, sondern dadurch auch ihrer Anschauung einen Gegenstand bestimmen, d.i. den Begriff von Etwas, darin sie nothwendig zusammenhängen: denn das Gemüth könnte sich unmöglich die Identität seiner selbst in der Mannigfaltigkeit seiner Vorstellungen und zwar _a priori_ denken, wenn es nicht die Identität seiner Handlung vor Augen hätte, welche alle Synthesis der Apprehension (die empirisch ist) einer transscendentalen Einheit unterwirft und ihren Zusammenhang nach Regeln _a priori_ zuerst möglich macht. Nunmehr werden wir auch unsere Begriffe von einem Gegenstande überhaupt richtiger bestimmen können. Alle Vorstellungen haben als Vorstellungen ihren Gegenstand und können selbst wiederum Gegenstände anderer Vorstellungen sein. Erscheinungen sind die einzigen Gegenstände, die uns unmittelbar gegeben werden können, und das, was sich darin unmittelbar auf den Gegenstand bezieht, heißt Anschauung. Nun sind aber diese Erscheinungen nicht Dinge an sich"}], "markers": [{"system": "A", "ref": "A107"}, {"system": "A", "ref": "A108"}, {"system": "A", "ref": "A109"}], "running_header": "3. Von der Synthesis der Recognition im Begriffe [A, Anhang]"}, {"page_pdf": 1413, "page_book": null, "page_kind": "body", "sigel": "A110", "units": [{"type": "paragraph", "text": "selbst, sondern selbst nur Vorstellungen, die wiederum ihren Gegenstand haben, der also von uns nicht mehr angeschaut werden kann und daher der nichtempirische, d.i. transscendentale, Gegenstand =_X_ genannt werden mag. Der reine Begriff von diesem transscendentalen Gegenstande (der wirklich bei allen unsern Erkenntnissen immer einerlei =_X_ ist) ist das, was allen unsern empirischen Begriffen überhaupt Beziehung auf einen Gegenstand, d.i. objective Realität, verschaffen kann. Dieser Begriff kann nun gar keine bestimmte Anschauung enthalten und wird also nichts anders als diejenige Einheit betreffen, die in einem Mannigfaltigen der Erkenntniß angetroffen werden muß, so fern es in Beziehung auf einen Gegenstand steht. Diese Beziehung aber ist nichts anders, als die nothwendige Einheit des Bewußtseins, mithin auch der Synthesis des Mannigfaltigen durch gemeinschaftliche Function des Gemüths, es in einer Vorstellung zu verbinden. Da nun diese Einheit als _a priori_ nothwendig angesehen werden muß (weil die Erkenntniß sonst ohne Gegenstand sein würde), so wird die Beziehung auf einen transscendentalen Gegenstand, d.i. die objective Realität unserer empirischen Erkenntniß, auf dem transscendentalen Gesetze beruhen, daß alle Erscheinungen, so fern uns dadurch Gegenstände gegeben werden sollen, unter Regeln _a priori_ der synthetischen Einheit derselben stehen müssen, nach welchen ihr Verhältniß in der empirischen Anschauung allein möglich ist, d.i. daß sie eben sowohl in der Erfahrung unter Bedingungen der nothwendigen Einheit der Apperception, als in der bloßen Anschauung unter den formalen Bedingungen des Raumes und der Zeit stehen müssen, ja daß durch jene jede Erkenntniß allererst möglich werde."}], "markers": [{"system": "A", "ref": "A110"}], "running_header": "3. Von der Synthesis der Recognition im Begriffe [A, Anhang]"}, {"page_pdf": 1414, "page_book": null, "page_kind": "body", "sigel": "A110 · A111 · A112 · A113", "units": [{"type": "paragraph", "text": "[A] 4. Vorläufige Erklärung der Möglichkeit der Kategorien als Erkenntnisse _a priori_. Es ist nur eine Erfahrung, in welcher alle Wahrnehmungen als im durchgängigen und gesetzmäßigen Zusammenhange vorgestellt werden: eben so wie nur ein Raum und Zeit ist, in welcher alle Formen der Erscheinung und alles Verhältniß des Seins oder Nichtseins statt finden. Wenn man von verschiedenen Erfahrungen spricht, so sind es nur so viel Wahrnehmungen, so fern solche zu einer und derselben allgemeinen Erfahrung gehören. Die durchgängige und synthetische Einheit der Wahrnehmungen macht nämlich gerade die Form der Erfahrung aus, und sie ist nichts anders, als die synthetische Einheit der Erscheinungen nach Begriffen. Einheit der Synthesis nach empirischen Begriffen würde ganz zufällig sein, und gründeten diese sich nicht auf einen transscendentalen Grund der Einheit, so würde es möglich sein, daß ein Gewühl von Erscheinungen unsere Seele anfüllte, ohne daß doch daraus jemals Erfahrung werden könnte. Alsdann fiele aber auch alle Beziehung der Erkenntniß auf Gegenstände weg, weil ihr die Verknüpfung nach allgemeinen und nothwendigen Gesetzen mangelte, mithin würde sie zwar gedankenlose Anschauung, aber niemals Erkenntniß, also für uns so viel als gar nichts sein. Die Bedingungen _a priori_ einer möglichen Erfahrung überhaupt sind zugleich Bedingungen der Möglichkeit der Gegenstände der Erfahrung. Nun behaupte ich: die oben angeführte Kategorien sind nichts anders, als die Bedingungen des Denkens in einer möglichen Erfahrung, so wie Raum und Zeit die Bedingungen der Anschauung zu eben derselben enthalten. Also sind jene auch Grundbegriffe, Objecte überhaupt zu den Erscheinungen zu denken und haben also _a priori_ objective Gültigkeit; welches dasjenige war, was wir eigentlich wissen wollten. Die Möglichkeit aber, ja sogar die Nothwendigkeit dieser Kategorien beruht auf der Beziehung, welche die gesammte Sinnlichkeit und mit ihr auch alle mögliche Erscheinungen auf die ursprüngliche Apperception haben, in welcher alles nothwendig den Bedingungen der durchgängigen Einheit des Selbstbewußtseins gemäß sein, d.i. unter allgemeinen Functionen der Synthesis stehen muß, nämlich der Synthesis nach Begriffen, als worin die Apperception allein ihre durchgängige und nothwendige Identität _a priori_ beweisen kann. So ist der Begriff einer Ursache nichts anders, als eine Synthesis (dessen, was in der Zeitreihe folgt, mit andern Erscheinungen) nach Begriffen, und ohne dergleichen Einheit, die ihre Regel _a priori_ hat und die Erscheinungen sich unterwirft, würde durchgängige und allgemeine, mithin nothwendige Einheit des Bewußtseins in dem Mannigfaltigen der Wahrnehmungen nicht angetroffen werden. Diese würden aber alsdann auch zu keiner Erfahrung gehören, folglich ohne Object und nichts als ein blindes Spiel der Vorstellungen, d.i. weniger als ein Traum sein. Alle Versuche, jene reine Verstandesbegriffe von der Erfahrung abzuleiten und ihnen einen blos empirischen Ursprung zuzuschreiben, sind also ganz eitel und vergeblich. Ich will davon nichts erwähnen, daß z.E. der Begriff einer Ursache den Zug von Nothwendigkeit bei sich führt, welche gar keine Erfahrung geben kann, die uns zwar lehrt, daß auf eine Erscheinung gewöhnlicher Maßen etwas Andres folge, aber nicht, daß es nothwendig darauf folgen müsse, noch daß _a priori_ und ganz allgemein daraus als einer Bedingung auf die Folge könne geschlossen werden. Aber jene empirische Regel der Association, die man doch durchgängig annehmen muß, wenn man sagt, daß alles in der Reihenfolge der Begebenheiten dermaßen unter Regeln stehe, daß niemals etwas geschieht, vor welchem nicht etwas vorhergehe, darauf es jederzeit folge: dieses als ein Gesetz der Natur, worauf beruht es? frage ich, und wie ist selbst diese Association möglich? Der Grund der Möglichkeit der Association des Mannigfaltigen, so fern er im Objecte liegt, heißt die Affinität des Mannigfaltigen. Ich frage also, wie macht ihr euch die durchgängige Affinität der Erscheinungen (dadurch sie unter beständigen Gesetzen stehen und darunter gehören müssen) begreiflich?"}], "markers": [{"system": "A", "ref": "A110"}, {"system": "A", "ref": "A111"}, {"system": "A", "ref": "A112"}, {"system": "A", "ref": "A113"}], "running_header": "4. Vorläufige Erklärung der Möglichkeit der Kategorien als Erkenntnisse a priori [A, Anhang]"}, {"page_pdf": 1415, "page_book": null, "page_kind": "body", "sigel": "A114", "units": [{"type": "paragraph", "text": "Nach meinen Grundsätzen ist sie sehr wohl begreiflich. Alle mögliche Erscheinungen gehören als Vorstellungen zu dem ganzen möglichen Selbstbewußtsein. Von diesem aber als einer transscendentalen Vorstellung ist die numerische Identität unzertrennlich und _a priori_ gewiß, weil nichts in das Erkenntniß kommen kann, ohne vermittelst dieser ursprünglichen Apperception. Da nun diese Identität nothwendig in der Synthesis alles Mannigfaltigen der Erscheinungen, so fern sie empirische Erkenntniß werden soll, hinein kommen muß, so sind die Erscheinungen Bedingungen _a priori_ unterworfen, welchen ihre Synthesis (der Apprehension) durchgängig gemäß sein muß. Nun heißt aber die Vorstellung einer allgemeinen Bedingung, nach welcher ein gewisses Mannigfaltige (mithin auf einerlei Art) gesetzt werden kann, eine Regel und, wenn es so gesetzt werden muß, ein Gesetz. Also stehen alle Erscheinungen in einer durchgängigen Verknüpfung nach nothwendigen Gesetzen und mithin in einer transscendentalen Affinität, woraus die empirische die bloße Folge ist. Daß die Natur sich nach unserm subjectiven Grunde der Apperception richten, ja gar davon in Ansehung ihrer Gesetzmäßigkeit abhängen solle, lautet wohl sehr widersinnisch und befremdlich. Bedenkt man aber, daß diese Natur an sich nichts als ein Inbegriff von Erscheinungen, mithin kein Ding an sich, sondern blos eine Menge von Vorstellungen des Gemüths sei, so wird man sich nicht wundern, sie blos in dem Radicalvermögen aller unsrer Erkenntniß, nämlich der transscendentalen Apperception, in derjenigen Einheit zu sehen, um deren willen allein sie Object aller möglichen Erfahrung, d.i. Natur, heißen kann; und daß wir auch eben darum diese Einheit _a _ _priori_, mithin auch als nothwendig erkennen können, welches wir wohl müßten unterwegens lassen, wäre sie unabhängig von den ersten Quellen unseres Denkens an sich gegeben. Denn da wüßte ich nicht, wo wir die synthetische Sätze einer solchen allgemeinen Natureinheit hernehmen sollten, weil man sie auf solchen Fall von den Gegenständen der Natur selbst entlehnen müßte. Da dieses aber nur empirisch geschehen könnte, so würde daraus keine andere als blos zufällige Einheit gezogen werden können, die aber bei weitem an den nothwendigen Zusammenhang nicht reicht, den man meint, wenn man Natur nennt."}], "markers": [{"system": "A", "ref": "A114"}], "running_header": "4. Vorläufige Erklärung der Möglichkeit der Kategorien als Erkenntnisse a priori [A, Anhang]"}, {"page_pdf": 1416, "page_book": null, "page_kind": "body", "sigel": "A115 · A116 · A117 · A118", "units": [{"type": "paragraph", "text": "[A] Der Deduction der reinen Verstandesbegriffe"}, {"type": "heading", "text": "Dritter Abschnitt.", "level": 2}, {"type": "paragraph", "text": "Von dem Verhältnisse des Verstandes zu Gegenständen überhaupt und der Möglichkeit diese _a priori_ zu erkennen. Was wir im vorigen Abschnitte abgesondert und einzeln vortrugen, wollen wir jetzt vereinigt und im Zusammenhange vorstellen. Es sind drei subjective Erkenntnißquellen, worauf die Möglichkeit einer Erfahrung überhaupt und Erkenntniß der Gegenstände derselben beruht: Sinn, Einbildungskraft und Apperception; jede derselben kann als empirisch, nämlich in der Anwendung auf gegebene Erscheinungen, betrachtet werden, alle aber sind auch Elemente oder Grundlagen _a priori_, welche selbst diesen empirischen Gebrauch möglich machen. Der Sinn stellt die Erscheinungen empirisch in der Wahrnehmung vor, die Einbildungskraft in der Association (und Reproduction), die Apperception in dem empirischen Bewußtsein der Identität dieser reproductiven Vorstellungen mit den Erscheinungen, dadurch sie gegeben waren, mithin in der Recognition. Es liegt aber der sämmtlichen Wahrnehmung die reine Anschauung (in Ansehung ihrer als Vorstellung die Form der inneren Anschauung, die Zeit), der Association die reine Synthesis der Einbildungskraft und dem empirischen Bewußtsein die reine Apperception, d.i. die durchgängige Identität seiner selbst bei allen möglichen Vorstellungen, _a priori_ zum Grunde. Wollen wir nun den innern Grund dieser Verknüpfung der Vorstellungen bis auf denjenigen Punkt verfolgen, in welchem sie alle zusammenlaufen müssen, um darin allererst Einheit der Erkenntniß zu einer möglichen Erfahrung zu bekommen, so müssen wir von der reinen Apperception anfangen. Alle Anschauungen sind für uns nichts und gehen uns nicht im mindesten etwas an, wenn sie nicht ins Bewußtsein aufgenommen werden können, sie mögen nun direct oder indirect darauf einfließen, und nur durch dieses allein ist Erkenntniß möglich. Wir sind uns _a _ _priori_ der durchgängigen Identität unserer selbst in Ansehung aller Vorstellungen, die zu unserem Erkenntniß jemals gehören können, bewußt, als einer nothwendigen Bedingung der Möglichkeit aller Vorstellungen (weil diese in mir doch nur dadurch etwas vorstellen, daß sie mit allem andern zu einem Bewußtsein gehören, mithin darin wenigstens müssen verknüpft werden können). Dies Princip steht _a priori_ fest und kann das transscendentale Princip der Einheit alles Mannigfaltigen unserer Vorstellungen (mithin auch in der Anschauung) heißen. Nun ist die Einheit des Mannigfaltigen in einem Subject synthetisch: also giebt die reine Apperception ein Principium der synthetischen Einheit des Mannigfaltigen in aller möglichen Anschauung an die Hand.*[1] Diese synthetische Einheit setzt aber eine Synthesis voraus oder schließt sie ein; und soll jene _a priori_ nothwendig sein, so muß letztere auch eine Synthesis _a priori_ sein. Also bezieht sich die transscendentale Einheit der Apperception auf die reine Synthesis der Einbildungskraft als eine Bedingung _a priori_ der Möglichkeit aller Zusammensetzung des Mannigfaltigen in einer Erkenntniß. Es kann aber nur die productive Synthesis der Einbildungskraft _a priori_ statt finden; denn die reproductive beruht auf Bedingungen der Erfahrung. Also ist das Principium der nothwendigen Einheit der reinen (productiven) Synthesis der Einbildungskraft vor der Apperception der Grund der Möglichkeit aller Erkenntniß, besonders der Erfahrung. Nun nennen wir die Synthesis des Mannigfaltigen in der Einbildungskraft transscendental, wenn ohne Unterschied der Anschauungen sie auf nichts, als blos auf die Verbindung des Mannigfaltigen _a priori_ geht, und die Einheit dieser Synthesis heißt transscendental, wenn sie in Beziehung auf die ursprüngliche Einheit der Apperception als _a priori_ nothwendig vorgestellt wird. Da diese letztere nun der Möglichkeit aller Erkenntnisse zum Grunde liegt, so ist die transscendentale Einheit der Synthesis der Einbildungskraft die reine Form aller möglichen Erkenntniß, durch welche mithin alle Gegenstände möglicher Erfahrung _a priori_ vorgestellt"}], "markers": [{"system": "A", "ref": "A115"}, {"system": "A", "ref": "A116"}, {"system": "A", "ref": "A117"}, {"system": "A", "ref": "A118"}], "running_header": "Deduction [...] III. Von dem Verhältnisse des Verstandes zu Gegenständen überhaupt [...] [A, Anhang]"}, {"page_pdf": 1417, "page_book": null, "page_kind": "body", "sigel": "A119 · A120 · A121 · A122", "units": [{"type": "paragraph", "text": "werden müssen. Die Einheit der Apperception in Beziehung auf die Synthesis der Einbildungskraft ist der Verstand und eben dieselbe Einheit beziehungsweise auf die transscendentale Synthesis der Einbildungskraft der reine Verstand. Also sind im Verstande reine Erkenntnisse _a priori_, welche die nothwendige Einheit der reinen Synthesis der Einbildungskraft in Ansehung aller möglichen Erscheinungen enthalten. Dieses sind aber die Kategorien, d.i. reine Verstandesbegriffe; folglich enthält die empirische Erkenntnißkraft des Menschen nothwendig einen Verstand, der sich auf alle Gegenstände der Sinne, obgleich nur vermittelst der Anschauung und der Synthesis derselben durch Einbildungskraft bezieht, unter welchen also alle Erscheinungen als Data zu einer möglichen Erfahrung stehen. Da nun diese Beziehung der Erscheinungen auf mögliche Erfahrung ebenfalls nothwendig ist (weil wir ohne diese gar keine Erkenntniß durch sie bekommen würden, und sie uns mithin gar nichts angingen), so folgt, daß der reine Verstand vermittelst der Kategorien ein formales und synthetisches Principium aller Erfahrungen sei, und die Erscheinungen eine nothwendige Beziehung auf den Verstand haben. Jetzt wollen wir den nothwendigen Zusammenhang des Verstandes mit den Erscheinungen vermittelst der Kategorien dadurch vor Augen legen, daß wir von unten auf, nämlich dem Empirischen, anfangen. Das erste, was uns gegeben wird, ist Erscheinung, welche, wenn sie mit Bewußtsein verbunden ist, Wahrnehmung heißt (ohne das Verhältniß zu einem wenigstens möglichen Bewußtsein würde Erscheinung für uns niemals ein Gegenstand der Erkenntniß werden können und also für uns nichts sein und, weil sie an sich selbst keine objective Realität hat und nur im Erkenntnisse existirt, überall nichts sein). Weil aber jede Erscheinung ein Mannigfaltiges enthält, mithin verschiedene Wahrnehmungen im Gemüthe an sich zerstreuet und einzeln angetroffen werden, so ist eine Verbindung derselben nöthig, welche sie in dem Sinne selbst nicht haben können. Es ist also in uns ein thätiges Vermögen der Synthesis dieses Mannigfaltigen, welches wir Einbildungskraft nennen, und deren unmittelbar an den Wahrnehmungen ausgeübte Handlung ich Apprehension nenne*[2]. Die Einbildungskraft soll nämlich das Mannigfaltige der Anschauung in ein Bild bringen; vorher muß sie also die Eindrücke in ihre Thätigkeit aufnehmen, d.i. apprehendiren. Es ist aber klar, daß selbst diese Apprehension des Mannigfaltigen allein noch kein Bild und keinen Zusammenhang der Eindrücke hervorbringen würde, wenn nicht ein subjectiver Grund da wäre, eine Wahrnehmung, von welcher das Gemüth zu einer andern übergegangen, zu den nachfolgenden herüber zu rufen und so ganze Reihen derselben darzustellen, d.i. ein reproductives Vermögen der Einbildungskraft, welches denn auch nur empirisch ist. Weil aber, wenn Vorstellungen so, wie sie zusammen gerathen, einander ohne Unterschied reproducirten, wiederum kein bestimmter Zusammenhang derselben, sondern blos regellose Haufen derselben, mithin gar kein Erkenntniß entspringen würde: so muß die Reproduction derselben eine Regel haben, nach welcher eine Vorstellung vielmehr mit dieser, als einer andern in der Einbildungskraft in Verbindung tritt. Diesen subjectiven und empirischen Grund der Reproduction nach Regeln nennt man die Association der Vorstellungen. Würde nun aber diese Einheit der Association nicht auch einen objectiven Grund haben, so daß es unmöglich wäre, daß Erscheinungen von der Einbildungskraft anders apprehendirt würden, als unter der Bedingung einer möglichen synthetischen Einheit dieser Apprehension, so würde es auch etwas ganz Zufälliges sein, daß sich Erscheinungen in einen Zusammenhang der menschlichen Erkenntnisse schickten. Denn ob wir gleich das Vermögen hätten, Wahrnehmungen zu associiren, so bliebe es doch an sich ganz unbestimmt und zufällig, ob sie auch associabel wären; und in dem Falle, daß sie es nicht wären, so würde eine Menge Wahrnehmungen und auch wohl eine ganze Sinnlichkeit möglich sein, in welcher viel empirisches Bewußtsein in meinem Gemüth anzutreffen wäre, aber getrennt und ohne daß es zu einem Bewußtsein meiner selbst gehörte, welches aber unmöglich ist. Denn"}], "markers": [{"system": "A", "ref": "A119"}, {"system": "A", "ref": "A120"}, {"system": "A", "ref": "A121"}, {"system": "A", "ref": "A122"}], "running_header": "Deduction [...] III. Von dem Verhältnisse des Verstandes zu Gegenständen überhaupt [...] [A, Anhang]"}, {"page_pdf": 1418, "page_book": null, "page_kind": "body", "sigel": "A123 · A124", "units": [{"type": "paragraph", "text": "nur dadurch, daß ich alle Wahrnehmungen zu einem Bewußtsein (der ursprünglichen Apperception) zähle, kann ich bei allen Wahrnehmungen sagen: daß ich mir ihrer bewußt sei. Es muß also ein objectiver, d.i. vor allen empirischen Gesetzen der Einbildungskraft _a priori_ einzusehender, Grund sein, worauf die Möglichkeit, ja sogar die Nothwendigkeit eines durch alle Erscheinungen sich erstreckenden Gesetzes beruht, sie nämlich durchgängig als solche Data der Sinne anzusehen, welche an sich associabel und allgemeinen Regeln einer durchgängigen Verknüpfung in der Reproduction unterworfen sind. Diesen objectiven Grund aller Association der Erscheinungen nenne ich die Affinität derselben. Diesen können wir aber nirgends anders, als in dem Grundsatze von der Einheit der Apperception in Ansehung aller Erkenntnisse, die mir angehören sollen, antreffen. Nach diesem müssen durchaus alle Erscheinungen so ins Gemüth kommen oder apprehendirt werden, daß sie zur Einheit der Apperception zusammenstimmen, welches ohne synthetische Einheit in ihrer Verknüpfung, die mithin auch objectiv nothwendig ist, unmöglich sein würde. Die objective Einheit alles (empirischen) Bewußtseins in einem Bewußtsein (der ursprünglichen Apperception) ist also die nothwendige Bedingung sogar aller möglichen Wahrnehmung, und die Affinität aller Erscheinungen (nahe oder entfernte) ist eine nothwendige Folge einer Synthesis in der Einbildungskraft, die _a priori_ auf Regeln gegründet ist. Die Einbildungskraft ist also auch ein Vermögen einer Synthesis _a priori_, weswegen wir ihr den Namen der productiven Einbildungskraft geben; und so fern sie in Ansehung alles Mannigfaltigen der Erscheinung nichts weiter, als die nothwendige Einheit in der Synthesis derselben zu ihrer Absicht hat, kann diese die transscendentale Function der Einbildungskraft genannt werden. Es ist daher zwar befremdlich, allein aus dem bisherigen doch einleuchtend, daß nur vermittelst dieser transscendentalen Function der Einbildungskraft sogar die Affinität der Erscheinungen, mit ihr die Association und durch diese endlich die Reproduction nach Gesetzen, folglich die Erfahrung selbst möglich werde: weil ohne sie gar keine Begriffe von Gegenständen in eine Erfahrung zusammenfließen würden. Denn das stehende und bleibende Ich (der reinen Apperception) macht das Correlatum aller unserer Vorstellungen aus, so fern es blos möglich ist, sich ihrer bewußt zu werden, und alles Bewußtsein gehört eben so wohl zu einer allbefassenden reinen Apperception, wie alle sinnliche Anschauung als Vorstellung zu einer reinen innern Anschauung, nämlich der Zeit. Diese Apperception ist es nun, welche zu der reinen Einbildungskraft hinzukommen muß, um ihre Function intellectuell zu machen. Denn an sich selbst ist die Synthesis der Einbildungskraft, obgleich _a priori_ ausgeübt, dennoch jederzeit sinnlich, weil sie das Mannigfaltige nur so verbindet, wie es in der Anschauung erscheint, z.B. die Gestalt eines Triangels. Durch das Verhältniß des Mannigfaltigen aber zur Einheit der Apperception werden Begriffe, welche dem Verstande angehören, aber nur vermittelst der Einbildungskraft in Beziehung auf die sinnliche Anschauung, zu Stande kommen können. Wir haben also eine reine Einbildungskraft als ein Grundvermögen der menschlichen Seele, das aller Erkenntniß _a priori_ zum Grunde liegt. Vermittelst deren bringen wir das Mannigfaltige der Anschauung einerseits mit der Bedingung der nothwendigen Einheit der reinen Apperception andererseits in Verbindung. Beide äußerste Enden, nämlich Sinnlichkeit und Verstand, müssen vermittelst dieser transscendentalen Function der Einbildungskraft nothwendig zusammenhängen: weil jene sonst zwar Erscheinungen, aber keine Gegenstände eines empirischen Erkenntnisses, mithin keine Erfahrung geben würde. Die wirkliche Erfahrung, welche aus der Apprehension, der Association (der Reproduction), endlich der Recognition der Erscheinungen besteht, enthält in der letzteren A125 _R_ und höchsten (der blos empirischen Elemente der Erfahrung) Begriffe, welche die formale Einheit der Erfahrung und mit ihr alle objective Gültigkeit (Wahrheit) der empirischen Erkenntniß möglich machen. Diese Gründe der Recognition des Mannigfaltigen, so fern sie blos die Form einer Erfahrung überhaupt angehen, sind nun jene Kategorien. Auf ihnen gründet sich"}], "markers": [{"system": "A", "ref": "A123"}, {"system": "A", "ref": "A124"}], "running_header": "Deduction [...] III. Von dem Verhältnisse des Verstandes zu Gegenständen überhaupt [...] [A, Anhang]"}, {"page_pdf": 1419, "page_book": null, "page_kind": "body", "sigel": "A126 · A127 · A128", "units": [{"type": "paragraph", "text": "also alle formale Einheit in der Synthesis der Einbildungskraft und vermittelst dieser auch alles empirischen Gebrauchs derselben (in der Recognition, Reproduction, Association, Apprehension) bis herunter zu den Erscheinungen, weil diese nur vermittelst jener Elemente der Erkenntniß, und überhaupt unserm Bewußtsein, mithin uns selbst angehören können. Die Ordnung und Regelmäßigkeit also an den Erscheinungen, die wir Natur nennen, bringen wir selbst hinein und würden sie auch nicht darin finden können, hätten wir sie nicht oder die Natur unseres Gemüths ursprünglich hineingelegt. Denn diese Natureinheit soll eine nothwendige d.i. _a priori_ gewisse, Einheit der Verknüpfung der Erscheinungen sein. Wie sollten wir aber wohl _a priori_ eine synthetische Einheit auf die Bahn, bringen können, wären nicht in den ursprünglichen Erkenntnißquellen unseres Gemüths subjective Gründe solcher Einheit _a priori_ enthalten, und wären diese subjective Bedingungen nicht zugleich objectiv gültig, indem sie die Gründe der Möglichkeit sind, überhaupt ein Object in der Erfahrung zu erkennen. Wir haben den Verstand oben auf mancherlei Weise erklärt: durch eine Spontaneität der Erkenntniß (im Gegensatz der Receptivität der Sinnlichkeit), durch ein Vermögen zu denken, oder auch ein Vermögen der Begriffe, oder auch der Urtheile, welche Erklärungen, wenn man sie beim lichten besieht, auf eins hinauslaufen. Jetzt können wir ihn als das Vermögen der Regeln charakterisiren. Dieses Kennzeichen ist fruchtbarer und tritt dem Wesen desselben näher. Sinnlichkeit giebt uns Formen (der Anschauung), der Verstand aber Regeln. Dieser ist jederzeit geschäftig, die Erscheinungen in der Absicht durchzuspähen, um an ihnen irgend eine Regel aufzufinden. _E_ Regeln, so fern sie objectiv sind (mithin der Erkenntniß des Gegenstandes nothwendig anhängen), heißen Gesetze. Ob wir gleich durch Erfahrung viel Gesetze lernen, so sind diese doch nur besondere Bestimmungen noch höherer Gesetze, unter denen die höchsten (unter welchen alle andere stehen) _a priori_ aus dem Verstande selbst herkommen und nicht von der Erfahrung entlehnt sind, sondern vielmehr den Erscheinungen ihre Gesetzmäßigkeit verschaffen und eben dadurch Erfahrung möglich machen müssen. Es ist also der Verstand nicht blos ein Vermögen, durch Vergleichung der Erscheinungen sich Regeln zu machen: er ist selbst die Gesetzgebung für die Natur, d.i. ohne Verstand würde es überall nicht Natur, d.i. synthetische Einheit des Mannigfaltigen der Erscheinungen nach Regeln, geben; denn Erscheinungen können als solche nicht außer uns statt finden, sondern existiren nur in unsrer Sinnlichkeit. Diese aber als Gegenstand der Erkenntniß in einer Erfahrung mit allem, was sie enthalten mag, ist nur in der Einheit der Apperception möglich. Die Einheit der Apperception aber ist der transscendentale Grund der nothwendigen Gesetzmäßigkeit aller Erscheinungen in einer Erfahrung. Eben dieselbe Einheit der Apperception in Ansehung eines Mannigfaltigen von Vorstellungen (es nämlich aus einer einzigen zu bestimmen) ist die Regel und das Vermögen dieser Regeln der Verstand. Alle Erscheinungen liegen also als mögliche Erfahrungen eben so _a priori_ im Verstande und erhalten ihre formale Möglichkeit von ihm, wie sie als bloße Anschauungen in der Sinnlichkeit liegen und durch dieselbe der Form nach allein möglich sind. So übertrieben, so widersinnisch es also auch lautet, zu sagen: der Verstand ist selbst der Quell der Gesetze der Natur und mithin der formalen Einheit der Natur, so richtig und dem Gegenstande, nämlich der Erfahrung, angemessen ist gleichwohl eine solche Behauptung. Zwar können empirische Gesetze als solche ihren Ursprung keinesweges vom reinen Verstande herleiten, so wenig als die unermeßliche Mannigfaltigkeit der Erscheinungen aus der reinen Form der sinnlichen Anschauung hinlänglich begriffen werden kann. Aber alle empirische Gesetze sind nur besondere Bestimmungen der reinen Gesetze des Verstandes, unter welchen und nach deren Norm jene allererst möglich sind, und die Erscheinungen eine gesetzliche Form annehmen, so wie auch alle Erscheinungen unerachtet der Verschiedenheit ihrer empirischen Form dennoch jederzeit den Bedingungen der reinen Form der Sinnlichkeit gemäß sein müssen."}], "markers": [{"system": "A", "ref": "A126"}, {"system": "A", "ref": "A127"}, {"system": "A", "ref": "A128"}], "running_header": "Deduction [...] III. Von dem Verhältnisse des Verstandes zu Gegenständen überhaupt [...] [A, Anhang]"}, {"page_pdf": 1420, "page_book": null, "page_kind": "body", "sigel": "", "units": [{"type": "paragraph", "text": "Der reine Verstand ist also in den Kategorien das Gesetz der synthetischen Einheit aller Erscheinungen und macht dadurch Erfahrung ihrer Form nach allererst und ursprünglich möglich. Mehr aber hatten wir in der transscendentalen Deduction der Kategorien nicht zu leisten, als dieses Verhältniß des Verstandes zur Sinnlichkeit und vermittelst derselben zu allen Gegenständen der Erfahrung, mithin die objective Gültigkeit seiner reinen Begriffe _a priori_ begreiflich zu machen und dadurch ihren Ursprung und Wahrheit fest zu setzen."}, {"type": "paragraph", "text": "Anmerkungen: *[1] Man gebe auf diesen Satz wohl acht, der von großer Wichtigkeit ist. Alle Vorstellungen haben eine nothwendige Beziehung auf ein mögliches empirisches Bewußtsein: denn hätten sie dieses nicht, und wäre es gänzlich unmöglich, sich ihrer bewußt zu werden, so würde das so viel sagen, sie existirten gar nicht. Alles empirische Bewußtsein hat aber eine nothwendige Beziehung auf ein transscendentales (vor aller besondern Erfahrung vorhergehendes) Bewußtsein, nämlich das Bewußtsein meiner selbst als die ursprüngliche Apperception. Es ist also schlechthin nothwendig, daß in meinem Erkenntnisse alles Bewußtsein zu einem Bewußtsein (meiner selbst) gehöre. Hier ist nun eine synthetische Einheit des Mannigfaltigen (Bewußtseins), die _a priori_ erkannt wird und gerade so den Grund zu synthetischen Sätzen _a priori_, die das reine Denken betreffen, als Raum und Zeit zu solchen Sätzen, die die Form der bloßen Anschauung angehen, abgiebt. Der synthetische Satz: daß alles verschiedene empirische Bewußtsein in einem einigen Selbstbewußtsein verbunden sein müsse, ist der schlechthin erste und synthetische Grundsatz unseres Denkens überhaupt. Es ist aber nicht aus der Acht zu lassen, daß die bloße Vorstellung Ich in Beziehung auf alle andere (deren collective Einheit sie möglich macht) das transscendentale Bewußtsein sei. Diese Vorstellung mag nun klar (empirisches Bewußtsein) oder dunkel sein, daran liegt hier nichts, ja nicht einmal an der Wirklichkeit desselben; sondern die Möglichkeit der logischen Form alles Erkenntnisses beruht nothwendig auf dem Verhältniß zu dieser Apperception als einem Vermögen. *[2] Daß die Einbildungskraft ein nothwendiges Ingredienz der Wahrnehmung selbst sei, daran hat wohl noch kein Psychologe gedacht. Das kommt daher, weil man dieses Vermögen theils nur auf Reproductionen einschränkte, theils weil man glaubte, die Sinne lieferten uns nicht allein Eindrücke, sondern setzten solche auch sogar zusammen und brächten Bilder der Gegenstände zuwege, wozu ohne Zweifel außer der Empfänglichkeit der Eindrücke noch etwas mehr, nämlich eine Function der Synthesis derselben, erfordert wird."}], "running_header": "Deduction [...] III. Von dem Verhältnisse des Verstandes zu Gegenständen überhaupt [...] [A, Anhang]"}, {"page_pdf": 1421, "page_book": null, "page_kind": "body", "sigel": "A128 · A129 · A130", "units": [{"type": "paragraph", "text": "[A] Summarische Vorstellung der Richtigkeit und einzigen Möglichkeit dieser Deduction der reinen Verstandesbegriffe. Wären die Gegenstände, womit unsre Erkenntniß zu thun hat, Dinge an sich selbst, so würden wir von diesen gar keine Begriffe _a priori_ haben können. Denn woher sollten wir sie nehmen? Nehmen wir sie vom Object (ohne hier noch einmal zu untersuchen, wie dieses uns bekannt werden könnte), so wären unsere Begriffe blos empirisch und keine Begriffe _a _ _priori_. Nehmen wir sie aus uns selbst, so kann das, was blos in uns ist, die Beschaffenheit eines von unsern Vorstellungen unterschiedenen Gegenstandes nicht bestimmen, d.i. ein Grund sein, warum es ein Ding geben solle, dem so etwas, als wir in Gedanken haben, zukomme, und nicht vielmehr alle diese Vorstellung leer sei. Dagegen wenn wir es überall nur mit Erscheinungen zu thun haben, so ist es nicht allein möglich, sondern auch nothwendig, daß gewisse Begriffe _a priori_ vor der empirischen Erkenntniß der Gegenstände vorhergehen. Denn als Erscheinungen machen sie einen Gegenstand aus, der blos in uns ist, weil eine bloße Modification unserer Sinnlichkeit außer uns gar nicht angetroffen wird. Nun drückt selbst diese Vorstellung, daß alle diese Erscheinungen, mithin alle Gegenstände, womit wir uns beschäftigen können, insgesammt in mir, d.i. Bestimmungen meines identischen Selbst sind, eine durchgängige Einheit derselben in einer und derselben Apperception als nothwendig aus. In dieser Einheit des möglichen Bewußtseins aber besteht auch die Form aller Erkenntniß der Gegenstände (wodurch das Mannigfaltige als zu Einem Object gehörig gedacht wird). Also geht die Art, wie das Mannigfaltige der sinnlichen Vorstellung (Anschauung) zu einem Bewußtsein gehört, vor aller Erkenntniß des Gegenstandes als die intellectuelle Form derselben vorher und macht selbst eine formale Erkenntniß aller Gegenstände _a priori_ überhaupt aus, so fern sie gedacht werden (Kategorien). Die Synthesis derselben durch die reine Einbildungskraft, die Einheit aller Vorstellungen in Beziehung auf die ursprüngliche Apperception gehen aller empirischen Erkenntniß vor. Reine Verstandesbegriffe sind also nur darum _a priori_ möglich, ja gar in Beziehung auf Erfahrung nothwendig, weil unser Erkenntniß mit nichts als Erscheinungen zu thun hat, deren Möglichkeit in uns selbst liegt, deren Verknüpfung und Einheit (in der Vorstellung eines Gegenstandes) blos in uns angetroffen wird, mithin vor aller Erfahrung vorhergehen und diese der Form nach auch allererst möglich machen muß. Und aus diesem Grunde, dem einzigmöglichen unter allen, ist denn auch unsere Deduction der Kategorien geführt worden."}], "markers": [{"system": "A", "ref": "A128"}, {"system": "A", "ref": "A129"}, {"system": "A", "ref": "A130"}], "running_header": "Summarische Vorstellung der Richtigkeit und einzigen Möglichkeit dieser Deduction der reinen Verstandesbegriffe [A, Anhang]"}, {"page_pdf": 1422, "page_book": null, "page_kind": "body", "sigel": "A348 · A349 · A350 · A351", "units": [{"type": "paragraph", "text": "[A] Erster Paralogism, der Substantialität. [...] Dasjenige, dessen Vorstellung das absolute Subject unserer Urtheile ist und daher nicht als Bestimmung eines andern Dinges gebraucht werden kann, ist Substanz. Ich, als ein denkend Wesen, bin das absolute Subject aller meiner möglichen Urtheile, und diese Vorstellung von mir selbst kann nicht zum Prädicat irgend eines andern Dinges gebraucht werden. Also bin ich, als denkend Wesen (Seele), Substanz."}, {"type": "paragraph", "text": "Kritik des ersten Paralogism der reinen Psychologie. Wir haben in dem analytischen Theile der transscendentalen Logik gezeigt: daß reine Kategorien (und unter diesen auch die der Substanz) an sich selbst gar keine objective Bedeutung haben, wo ihnen nicht eine Anschauung unterlegt ist, auf deren Mannigfaltiges sie als Functionen der synthetischen Einheit angewandt werden können. Ohne das sind sie lediglich Functionen eines Urtheils ohne Inhalt. Von jedem Dinge überhaupt kann ich sagen, es sei Substanz, so fern ich es von bloßen Prädicaten und Bestimmungen der Dinge unterscheide. Nun ist in allem unserem Denken das Ich das Subject, dem Gedanken nur als Bestimmungen inhäriren, und dieses Ich kann nicht als die Bestimmung eines anderen Dinges gebraucht werden. Also muß jedermann sich selbst nothwendiger Weise als die Substanz, das Denken aber nur als Accidenzen seines Daseins und Bestimmungen seines Zustandes ansehen. Was soll ich aber nun von diesem Begriffe einer Substanz für einen Gebrauch machen? Daß ich als ein denkend Wesen für mich selbst fortdaure, natürlicher Weise weder entstehe noch vergehe, das kann ich daraus keinesweges schließen, und dazu allein kann mir doch der Begriff der Substantialität meines denkenden Subjects nutzen, ohne welches ich ihn gar wohl entbehren könnte. Es fehlt so viel, daß man diese Eigenschaften aus der bloßen, reinen Kategorie einer Substanz schließen könnte, daß wir vielmehr die Beharrlichkeit eines gegebenen Gegenstandes aus der Erfahrung zum Grunde legen müssen, wenn wir auf ihn den empirisch brauchbaren Begriff von einer Substanz anwenden wollen. Nun haben wir aber bei unserem Satze keine Erfahrung zum Grunde gelegt, sondern lediglich aus dem Begriffe der Beziehung, die alles Denken auf das Ich als das gemeinschaftliche Subject hat, dem es inhärirt, geschlossen. Wir würden auch, wenn wir es gleich darauf anlegten, durch keine sichere Beobachtung eine solche Beharrlichkeit darthun können. Denn das Ich ist zwar in allen Gedanken; es ist aber mit dieser Vorstellung nicht die mindeste Anschauung verbunden die es von anderen Gegenständen der Anschauung unterschiede. Man kann also zwar wahrnehmen, daß diese Vorstellung bei allem Denken immer wiederum vorkommt, nicht aber, daß es eine stehende und bleibende Anschauung sei, worin die Gedanken (als wandelbar) wechselten. Hieraus folgt: daß der erste Vernunftschluß der transscendentalen Psychologie uns nur eine vermeintliche neue Einsicht aufhefte, indem er das beständige logische Subject des Denkens für die Erkenntniß des realen Subjects der Inhärenz ausgiebt, von welchem wir nicht die mindeste Kenntniß haben, noch haben können, weil das Bewußtsein das einzige ist, was alle Vorstellungen zu Gedanken macht, und worin mithin alle unsere Wahrnehmungen als dem transscendentalen Subjecte müssen angetroffen werden, und wir außer dieser logischen Bedeutung des Ich keine Kenntniß von dem Subjecte an sich selbst haben, was diesem so wie allen Gedanken als Substratum zum Grunde liegt. Indessen kann man den Satz: die Seele ist Substanz, gar wohl gelten lassen, wenn man sich nur bescheidet, daß dieser unser Begriff nicht im mindesten weiter führe, oder irgend eine von den gewöhnlichen Folgerungen der vernünftelnden Seelenlehre, als z.B. die immerwährende Dauer derselben bei"}], "markers": [{"system": "A", "ref": "A348"}, {"system": "A", "ref": "A349"}, {"system": "A", "ref": "A350"}, {"system": "A", "ref": "A351"}], "running_header": "Erster Paralogism, der Substantialität  [A, Anhang]"}, {"page_pdf": 1423, "page_book": null, "page_kind": "body", "sigel": "", "units": [{"type": "paragraph", "text": "allen Veränderungen und selbst dem Tode des Menschen lehren könne, daß er also nur eine Substanz in der Idee, aber nicht in der Realität bezeichne."}], "running_header": "Erster Paralogism, der Substantialität  [A, Anhang]"}, {"page_pdf": 1424, "page_book": null, "page_kind": "body", "sigel": "A351 · A352 · A353 · A354", "units": [{"type": "paragraph", "text": "[A] Zweiter Paralogism, der Simplicität. Dasjenige Ding, dessen Handlung niemals als die Concurrenz vieler handelnden Dinge angesehen werden kann, ist einfach. Nun ist die Seele oder das denkende Ich ein solches: Also etc."}, {"type": "paragraph", "text": "Kritik des zweiten Paralogisms der transscendentalen Psychologie. Dies ist der Achilles aller dialektischen Schlüsse der reinen Seelenlehre, nicht etwa blos ein sophistisches Spiel, welches ein Dogmatiker erkünstelt, um seinen Behauptungen einen flüchtigen Schein zu geben, sondern ein Schluß, der sogar die schärfste Prüfung und die größte Bedenklichkeit des Nachforschens auszuhalten scheint. Hier ist er. Eine jede zusammengesetzte Substanz ist ein Aggregat vieler, und die Handlung eines Zusammengesetzten oder das, was ihm als einem solchen inhärirt, ist ein Aggregat vieler Handlungen oder Accidenzen, welche unter der Menge der Substanzen vertheilt sind. Nun ist zwar eine Wirkung, die aus der Concurrenz vieler handelnden Substanzen entspringt, möglich, wenn diese Wirkung blos äußerlich ist (wie z.B. die Bewegung eines Körpers die vereinigte Bewegung aller seiner Theile ist). Allein mit Gedanken, als innerlich zu einem denkenden Wesen gehörigen Accidenzen, ist es anders beschaffen. Denn setzet, das Zusammengesetzte dächte: so würde ein jeder Theil desselben einen Theil des Gedanken, alle aber zusammengenommen allererst den ganzen Gedanken enthalten. Nun ist dieses aber widersprechend. Denn weil die Vorstellungen, die unter verschiedenen Wesen vertheilt sind, (z.B. die einzelne Wörter eines Verses) niemals einen ganzen Gedanken (einen Vers) ausmachen: so kann der Gedanke nicht einem Zusammengesetzten als einem solchen inhäriren. Er ist also nur in einer Substanz möglich, die nicht ein Aggregat von vielen, mithin schlechterdings einfach ist*. Der so genannte _nervus probandi_ dieses Arguments liegt in dem Satze: daß viele Vorstellungen in der absoluten Einheit des denkenden Subjects enthalten sein müssen, um einen Gedanken auszumachen. Diesen Satz aber kann niemand aus Begriffen beweisen. Denn wie wollte er es wohl anfangen, um dieses zu leisten? Der Satz: Ein Gedanke kann nur die Wirkung der absoluten Einheit des denkenden Wesens sein, kann nicht als analytisch behandelt werden. Denn die Einheit des Gedanken, der aus vielen Vorstellungen besteht, ist collectiv und kann sich den bloßen Begriffen nach eben sowohl auf die collective Einheit der daran mitwirkenden Substanzen beziehen (wie die Bewegung eines Körpers die zusammengesetzte Bewegung aller Theile desselben ist), als auf die absolute Einheit des Subjects. Nach der Regel der Identität kann also die Nothwendigkeit der Voraussetzung einer einfachen Substanz bei einem zusammengesetzten Gedanken nicht eingesehen werden. Daß aber eben derselbe Satz synthetisch und völlig _a priori_ aus lauter Begriffen erkannt werden solle, das wird sich niemand zu verantworten getrauen, der den Grund der Möglichkeit synthetischer Sätze _a _ _priori_, so wie wir ihn oben dargelegt haben, einsieht. Nun ist es aber auch unmöglich, diese nothwendige Einheit des Subjects als die Bedingung der Möglichkeit eines jeden Gedankens aus der Erfahrung abzuleiten. Denn diese giebt keine Nothwendigkeit zu erkennen, geschweige daß der Begriff der absoluten Einheit weit über ihre Sphäre ist. Woher nehmen wir denn diesen Satz, worauf sich der ganze psychologische Vernunftschluß stützt? Es ist offenbar: daß, wenn man sich ein denkend Wesen vorstellen will, man sich selbst an seine Stelle setzen und also dem Objecte, welches man erwägen wollte, sein eigenes Subject unterschieben müsse (welches in keiner anderen Art der Nachforschung der Fall ist), und daß wir nur darum absolute Einheit des Subjects zu einem Gedanken erfordern, weil sonst nicht gesagt werden könnte: Ich denke (das Mannigfaltige in einer Vorstellung). Denn obgleich das Ganze des Gedanken getheilt und unter"}], "markers": [{"system": "A", "ref": "A351"}, {"system": "A", "ref": "A352"}, {"system": "A", "ref": "A353"}, {"system": "A", "ref": "A354"}], "running_header": "Zweiter Paralogism, der Simplicität  [A, Anhang]"}, {"page_pdf": 1425, "page_book": null, "page_kind": "body", "sigel": "A355 · A356 · A357", "units": [{"type": "paragraph", "text": "viele Subjecte vertheilt werden könnte, so kann doch das subjective Ich nicht getheilt und vertheilt werden, und dieses setzen wir doch bei allem Denken voraus. Also bleibt eben so hier, wie in dem vorigen Paralogism der formale Satz der Apperception: Ich denke, der ganze Grund, auf welchen die rationale Psychologie die Erweiterung ihrer Erkenntnisse wagt, welcher Satz zwar freilich keine Erfahrung ist, sondern die Form der Apperception, die jeder Erfahrung anhängt und ihr vorgeht, gleichwohl aber nur immer in Ansehung einer möglichen Erkenntniß überhaupt als blos subjective Bedingung derselben angesehen werden muß, die wir mit Unrecht zur Bedingung der Möglichkeit einer Erkenntniß der Gegenstände, nämlich zu einem Begriffe vom denkenden Wesen überhaupt, machen, weil wir dieses uns nicht vorstellen können, ohne uns selbst mit der Formel unseres Bewußtseins an die Stelle jedes andern intelligenten Wesens zu setzen. Aber die Einfachheit meiner selbst (als Seele) wird auch wirklich nicht aus dem Satze: Ich denke, geschlossen, sondern die erstere liegt schon in jedem Gedanken selbst. Der Satz: Ich bin einfach, muß als ein unmittelbarer Ausdruck der Apperception angesehen werden, so wie der vermeintliche Cartesianische Schluß: _cogito, ergo sum,_ in der That tautologisch ist, indem das _cogito_ (_sum cogitans_) die Wirklichkeit unmittelbar aussagt. Ich bin einfach, bedeutet aber nichts mehr, als daß diese Vorstellung: Ich, nicht die mindeste Mannigfaltigkeit in sich fasse, und daß sie absolute (obzwar blos logische) Einheit sei. Also ist der so berühmte psychologische Beweis lediglich auf der untheilbaren Einheit einer Vorstellung, die nur das Verbum in Ansehung einer Person dirigirt, gegründet. Es ist aber offenbar, daß das Subject der Inhärenz durch das dem Gedanken angehängte Ich nur transscendental bezeichnet werde, ohne die mindeste Eigenschaft desselben zu bemerken, oder überhaupt etwas von ihm zu kennen oder zu wissen. Es bedeutet ein Etwas überhaupt (transscendentales Subject), dessen Vorstellung allerdings einfach sein muß, eben darum weil man gar nichts an ihm bestimmt, wie denn gewiß nichts einfacher vorgestellt werden kann, als durch den Begriff von einem bloßen Etwas. Die Einfachheit aber der Vorstellung von einem Subject ist darum nicht eine Erkenntniß von der Einfachheit des Subjects selbst, denn von dessen Eigenschaften wird gänzlich abstrahirt, wenn es lediglich durch den an Inhalt gänzlich leeren Ausdruck: Ich, (welchen ich auf jedes denkende Subject anwenden kann) bezeichnet wird. So viel ist gewiß, daß ich mir durch das Ich jederzeit eine absolute, aber logische Einheit des Subjects (Einfachheit) gedenke, aber nicht, daß ich dadurch die wirkliche Einfachheit meines Subjects erkenne. So wie der Satz: ich bin Substanz, nichts als die reine Kategorie bedeutete, von der ich _in concreto_ keinen Gebrauch (empirischen) machen kann, so ist es mir auch erlaubt zu sagen: Ich bin eine einfache Substanz, d.i. deren Vorstellung niemals eine Synthesis des Mannigfaltigen enthält; aber dieser Begriff oder auch dieser Satz lehrt uns nicht das mindeste in Ansehung meiner selbst als eines Gegenstandes der Erfahrung, weil der Begriff der Substanz selbst nur als Function der Synthesis, ohne unterlegte Anschauung, mithin ohne Object gebraucht wird und nur von der Bedingung unserer Erkenntniß, aber nicht von irgend einem anzugebenden Gegenstande gilt. Wir wollen über die vermeintliche Brauchbarkeit dieses Satzes einen Versuch anstellen. Jedermann muß gestehen, daß die Behauptung von der einfachen Natur der Seele nur so fern von einigem Werthe sei, als ich dadurch dieses Subject von aller Materie unterscheiden und sie folglich von der Hinfälligkeit ausnehmen kann, der diese jederzeit unterworfen ist. Auf diesen Gebrauch ist obiger Satz auch ganz eigentlich angelegt, daher er auch mehrentheils so ausgedrückt wird: die Seele ist nicht körperlich. Wenn ich nun zeigen kann, daß, ob man gleich diesem Cardinalsatze der rationalen Seelenlehre in der reinen Bedeutung eines bloßen Vernunfturtheils (aus reinen Kategorien) alle objective Gültigkeit einräumt (alles, was denkt, ist einfache Substanz), dennoch nicht der mindeste Gebrauch von diesem Satze in Ansehung der Ungleichartigkeit oder Verwandtschaft derselben mit der Materie gemacht werden"}], "markers": [{"system": "A", "ref": "A355"}, {"system": "A", "ref": "A356"}, {"system": "A", "ref": "A357"}], "running_header": "Zweiter Paralogism, der Simplicität  [A, Anhang]"}, {"page_pdf": 1426, "page_book": null, "page_kind": "body", "sigel": "A358 · A359 · A360", "units": [{"type": "paragraph", "text": "könne: so wird dieses eben so viel sein, als ob ich diese vermeintliche psychologische Einsicht in das Feld bloßer Ideen verwiesen hätte, denen es an Realität des objectiven Gebrauchs mangelt. Wir haben in der transscendentalen Ästhetik unläugbar bewiesen, daß Körper bloße Erscheinungen unseres äußeren Sinnes und nicht Dinge an sich selbst sind. Diesem gemäß können wir mit Recht sagen, daß unser denkendes Subject nicht körperlich sei, das heißt, daß, da es als Gegenstand des inneren Sinnes von uns vorgestellt wird, es, in so fern als es denkt, kein Gegenstand äußerer Sinne, d.i. keine Erscheinung im Raume, sein könne. Dieses will nun so viel sagen: es können uns niemals unter äußeren Erscheinungen denkende Wesen als solche vorkommen, oder: wir können ihre Gedanken, ihr Bewußtsein, ihre Begierden etc. nicht äußerlich anschauen; denn dieses gehört alles vor den innern Sinn. In der That scheint dieses Argument auch das natürliche und populäre, worauf selbst der gemeinste Verstand von jeher gefallen zu sein scheint und dadurch schon sehr früh Seelen als von den Körpern ganz unterschiedene Wesen zu betrachten angefangen hat. Ob nun aber gleich die Ausdehnung, die Undurchdringlichkeit, Zusammenhang und Bewegung, kurz alles, was uns äußere Sinne nur liefern können, nicht Gedanken, Gefühl, Neigung oder Entschließung sind oder solche enthalten werden, als die überall keine Gegenstände äußerer Anschauung sind, so könnte doch wohl dasjenige Etwas, welches den äußeren Erscheinungen zum Grunde liegt, was unseren Sinn so afficirt, daß er die Vorstellungen von Raum, Materie, Gestalt etc. bekommt, dieses Etwas, als Noumenon (oder besser als transscendentaler Gegenstand) betrachtet, könnte doch auch zugleich das Subject der Gedanken sein, wiewohl wir durch die Art, wie unser äußerer Sinn dadurch afficirt wird, keine Anschauung von Vorstellungen, Willen etc., sondern blos vom Raum und dessen Bestimmungen bekommen. Dieses Etwas aber ist nicht ausgedehnt, nicht undurchdringlich, nicht zusammengesetzt, weil alle diese Prädicate nur die Sinnlichkeit und deren Anschauung angehen, so fern wir von dergleichen (uns übrigens unbekannten) Objecten afficirt werden. Diese Ausdrücke aber geben gar nicht zu erkennen, was für ein Gegenstand es sei, sondern nur, daß ihm als einem solchen, der ohne Beziehung auf äußere Sinne an sich selbst betrachtet wird, diese Prädicate äußerer Erscheinungen nicht beigelegt werden können. Allein die Prädicate des innern Sinnes, Vorstellungen und Denken, widersprechen ihm nicht. Demnach ist selbst durch die eingeräumte Einfachheit der Natur die menschliche Seele von der Materie, wenn man sie (wie man soll) blos als Erscheinung betrachtet, in Ansehung des Substrati derselben gar nicht hinreichend unterschieden. Wäre Materie ein Ding an sich selbst, so würde sie als ein zusammengesetztes Wesen von der Seele als einem einfachen sich ganz und gar unterscheiden. Nun ist sie aber blos äußere Erscheinung, deren Substratum durch gar keine anzugebende Prädicate erkannt wird; mithin kann ich von diesem wohl annehmen, daß es an sich einfach sei, ob es zwar in der Art, wie es unsere Sinne afficirt, in uns die Anschauung des Ausgedehnten und mithin Zusammengesetzten hervorbringt, und daß also der Substanz, der in Ansehung unseres äußeren Sinnes Ausdehnung zukommt, an sich selbst Gedanken beiwohnen, die durch ihren eigenen inneren Sinn mit Bewußtsein vorgestellt werden können. Auf solche Weise würde eben dasselbe, was in einer Beziehung körperlich heißt, in einer andern zugleich ein denkend Wesen sein, dessen Gedanken wir zwar nicht, aber doch die Zeichen derselben in der Erscheinung anschauen können. Dadurch würde der Ausdruck wegfallen, daß nur Seelen (als besondere Arten von Substanzen) denken; es würde vielmehr wie gewöhnlich heißen, daß Menschen denken, d.i. eben dasselbe, was als äußere Erscheinung ausgedehnt ist, innerlich (an sich selbst) ein Subject sei, was nicht zusammengesetzt, sondern einfach ist und denkt. Aber ohne dergleichen Hypothesen zu erlauben, kann man allgemein bemerken, daß, wenn ich unter Seele ein denkend Wesen an sich selbst verstehe, die Frage an sich schon unschicklich sei: ob sie nämlich mit der Materie (die gar kein Ding an sich selbst, sondern nur eine Art Vorstellungen in uns ist) von gleicher Art sei, oder nicht; denn das versteht sich schon von selbst,"}], "markers": [{"system": "A", "ref": "A358"}, {"system": "A", "ref": "A359"}, {"system": "A", "ref": "A360"}], "running_header": "Zweiter Paralogism, der Simplicität  [A, Anhang]"}, {"page_pdf": 1427, "page_book": null, "page_kind": "body", "sigel": "A361", "units": [{"type": "paragraph", "text": "daß ein Ding an sich selbst von anderer Natur sei, als die Bestimmungen, die blos seinen Zustand ausmachen. Vergleichen wir aber das denkende Ich nicht mit der Materie, sondern mit dem Intelligibelen, welches der äußeren Erscheinung, die wir Materie nennen, zum Grunde liegt: so können wir, weil wir vom letzteren gar nichts wissen, auch nicht sagen, daß die Seele sich von diesem irgend worin innerlich unterscheide. So ist demnach das einfache Bewußtsein keine Kenntniß der einfachen Natur unseres Subjects, in so fern als dieses dadurch von der Materie als einem zusammengesetzten Wesen unterschieden werden soll. Wenn dieser Begriff aber dazu nicht taugt, in dem einzigen Falle, da er brauchbar ist, nämlich in der Vergleichung meiner selbst mit Gegenständen äußerer Erfahrung, das Eigenthümliche und Unterscheidende seiner Natur zu bestimmen, so mag man immer zu wissen vorgeben: das denkende Ich, die Seele (ein Name für den transscendentalen Gegenstand des inneren Sinnes), sei einfach; dieser Ausdruck hat deshalb doch gar keinen auf wirkliche Gegenstände sich erstreckenden Gebrauch und kann daher unsere Erkenntniß nicht im mindesten erweitern. So fällt demnach die ganze rationale Psychologie mit ihrer Hauptstütze, und wir können so wenig hier wie sonst jemals hoffen, durch bloße Begriffe (noch weniger aber durch die bloße subjective Form aller unserer Begriffe, das Bewußtsein) ohne Beziehung auf mögliche Erfahrung Einsichten auszubreiten, zumal da selbst der Fundamentalbegriff einer einfachen Natur von der Art ist, daß er überall in keiner Erfahrung angetroffen werden kann, und es mithin gar keinen Weg giebt, zu demselben als einem objectiv gültigen Begriffe zu gelangen."}, {"type": "paragraph", "text": "Anmerkungen: * Es ist sehr leicht, diesem Beweise die gewöhnliche schulgerechte Abgemessenheit der Einkleidung zu geben. Allein es ist zu meinem Zwecke schon hinreichend, den bloßen Beweisgrund allenfalls auf populäre Art vor Augen zu legen."}], "markers": [{"system": "A", "ref": "A361"}], "running_header": "Zweiter Paralogism, der Simplicität  [A, Anhang]"}, {"page_pdf": 1428, "page_book": null, "page_kind": "body", "sigel": "A361 · A362 · A363 · A364 · A365", "units": [{"type": "paragraph", "text": "[A] Dritter Paralogism, der Personalität. Was sich der numerischen Identität seiner selbst in verschiedenen Zeiten bewußt ist, ist so fern eine Person: Nun ist die Seele etc. Also ist sie eine Person."}, {"type": "paragraph", "text": "Kritik des dritten Paralogisms der transscendentalen Psychologie. Wenn ich die numerische Identität eines äußeren Gegenstandes durch Erfahrung erkennen will, so werde ich auf das Beharrliche derjenigen Erscheinung, worauf als Subject sich alles Übrige als Bestimmung bezieht, Acht haben und die Identität von jenem in der Zeit, da dieses wechselt, bemerken. Nun aber bin ich ein Gegenstand des innern Sinnes, und alle Zeit ist blos die Form des innern Sinnes. Folglich beziehe ich alle und jede meiner successiven Bestimmungen auf das numerisch identische Selbst in aller Zeit, d.i. in der Form der inneren Anschauung meiner selbst. Auf diesen Fuß müßte die Persönlichkeit der Seele nicht einmal als geschlossen, sondern als ein völlig identischer Satz des Selbstbewußtseins in der Zeit angesehen werden, und das ist auch die Ursache, weswegen er _a priori_ gilt. Denn er sagt wirklich nichts mehr als: in der ganzen Zeit, darin ich mir meiner bewußt bin, bin ich mir dieser Zeit als zur Einheit meines Selbst gehörig bewußt; und es ist einerlei, ob ich sage: diese ganze Zeit ist in mir als individueller Einheit, oder: ich bin mit numerischer Identität in aller dieser Zeit befindlich. Die Identität der Person ist also in meinem eigenen Bewußtsein unausbleiblich anzutreffen. Wenn ich mich aber aus dem Gesichtspunkte eines andern (als Gegenstand seiner äußeren Anschauung) betrachte, so erwägt dieser äußere Beobachter mich allererst in der Zeit, denn in der Apperception ist die Zeit eigentlich nur in mir vorgestellt. Er wird also aus dem Ich, welches alle Vorstellungen zu aller Zeit in meinem Bewußtsein und zwar mit völliger Identität begleitet, ob er es gleich einräumt, doch noch nicht auf die objective Beharrlichkeit meiner selbst schließen. Denn da alsdann die Zeit, in welche der Beobachter mich setzt, nicht diejenige ist, die in meiner eigenen, sondern die in seiner Sinnlichkeit angetroffen wird, so ist die Identität, die mit meinem Bewußtsein nothwendig verbunden ist, nicht darum mit dem seinigen, d.i. mit der äußeren Anschauung meines Subjects, verbunden. Es ist also die Identität des Bewußtseins meiner selbst in verschiedenen Zeiten nur eine formale Bedingung meiner Gedanken und ihres Zusammenhanges, beweiset aber gar nicht die numerische Identität meines Subjects, in welchem unerachtet der logischen Identität des Ich doch ein solcher Wechsel vorgegangen sein kann, der es nicht erlaubt, die Identität desselben beizubehalten, obzwar ihm immer noch das gleichlautende Ich zuzutheilen, welches in jedem andern Zustande, selbst der Umwandelung des Subjects, doch immer den Gedanken des vorhergehenden Subjects aufbehalten und so auch dem folgenden überliefern könnte.* Wenn gleich der Satz einiger alten Schulen, daß alles fließend und nichts in der Welt beharrlich und bleibend sei, nicht statt finden kann, sobald man Substanzen annimmt, so ist er doch nicht durch die Einheit des Selbstbewußtseins widerlegt. Denn wir selbst können aus unserem Bewußtsein darüber nicht urtheilen, ob wir als Seele beharrlich sind, oder nicht, weil wir zu unserem identischen Selbst nur dasjenige zählen, dessen wir uns bewußt sind, und so allerdings nothwendig urtheilen müssen, daß wir in der ganzen Zeit, deren wir uns bewußt sind, eben dieselbe sind. In dem Standpunkte eines Fremden aber können wir dieses darum noch nicht für gültig erklären, weil, da wir an der Seele keine beharrliche Erscheinung antreffen als nur die Vorstellung Ich, welche sie alle begleitet und verknüpft, so können wir niemals ausmachen, ob dieses Ich (ein bloßer Gedanke) nicht eben sowohl fließe als die übrige Gedanken, die dadurch an einander gekettet werden. Es ist aber merkwürdig, daß die Persönlichkeit und deren Voraussetzung, die Beharrlichkeit,"}], "markers": [{"system": "A", "ref": "A361"}, {"system": "A", "ref": "A362"}, {"system": "A", "ref": "A363"}, {"system": "A", "ref": "A364"}, {"system": "A", "ref": "A365"}], "running_header": "Dritter Paralogism, der Personalität [A, Anhang]"}, {"page_pdf": 1429, "page_book": null, "page_kind": "body", "sigel": "A366", "units": [{"type": "paragraph", "text": "mithin die Substantialität der Seele jetzt allererst bewiesen werden muß. Denn könnten wir diese voraussetzen, so würde zwar daraus noch nicht die Fortdauer des Bewußtseins, aber doch die Möglichkeit eines fortwährenden Bewußtseins in einem bleibenden Subject folgen, welches zu der Persönlichkeit schon hinreichend ist, die dadurch, daß ihre Wirkung etwa eine Zeit hindurch unterbrochen wird, selbst nicht sofort aufhört. Aber diese Beharrlichkeit ist uns vor der numerischen Identität unserer selbst, die wir aus der identischen Apperception folgeren, durch nichts gegeben, sondern wird daraus allererst gefolgert (und auf diese müßte, wenn es recht zuginge, allererst der Begriff der Substanz folgen, der allein empirisch brauchbar ist). Da nun diese Identität der Person aus der Identität des Ich in dem Bewußtsein aller Zeit, darin ich mich erkenne, keinesweges folgt, so hat auch oben die Substantialität der Seele darauf nicht gegründet werden können. Indessen kann so wie der Begriff der Substanz und des Einfachen, eben so auch der Begriff der Persönlichkeit (so fern er blos transscendental ist, d.i. Einheit des Subjects, das uns übrigens unbekannt ist, in dessen Bestimmungen aber eine durchgängige Verknüpfung durch Apperception ist) bleiben, und so fern ist dieser Begriff auch zum praktischen Gebrauche nöthig und hinreichend; aber auf ihn als Erweiterung unserer Selbsterkenntniß durch reine Vernunft, welche uns eine ununterbrochene Fortdauer des Subjects aus dem bloßen Begriffe des identischen Selbst vorspiegelt, können wir nimmermehr Staat machen, da dieser Begriff sich immer um sich selbst herumdreht und uns in Ansehung keiner einzigen Frage, welche auf synthetische Erkenntniß angelegt ist, weiter bringt. Was Materie für ein Ding an sich selbst (transscendentales Object) sei, ist uns zwar gänzlich unbekannt; gleichwohl kann doch die Beharrlichkeit derselben als Erscheinung, dieweil sie als etwas Äußerliches vorgestellt wird, beobachtet werden. Da ich aber, wenn ich das bloße Ich bei dem Wechsel aller Vorstellungen beobachten will, kein ander Correlatum meiner Vergleichungen habe, als wiederum mich selbst mit den allgemeinen Bedingungen meines Bewußtseins, so kann ich keine andere als tautologische Beantwortungen auf alle Fragen geben: indem ich nämlich meinen Begriff und dessen Einheit den Eigenschaften, die mir selbst als Object zukommen, unterschiebe und das voraussetze, was man zu wissen verlangte."}, {"type": "paragraph", "text": "Anmerkungen: * Eine elastische Kugel, die auf eine gleiche in gerader Richtung stößt, theilt dieser ihre ganze Bewegung, mithin ihren ganzen Zustand (wenn man blos auf die Stellen im Raume sieht) mit. Nehmet nun nach der Analogie mit dergleichen Körpern Substanzen an, deren die eine der andern Vorstellungen sammt deren Bewußtsein //A364// einflößte, so wird sich eine ganze Reihe derselben denken lassen, deren die erste ihren Zustand sammt dessen Bewußtsein der zweiten, diese ihren eigenen Zustand sammt dem der vorigen Substanz der dritten und diese eben so die Zustände aller vorigen sammt ihrem eigenen und deren Bewußtsein mittheilte. Die letzte Substanz würde also aller Zustände der vor ihr veränderten Substanzen sich als ihrer eigenen bewußt sein, weil jene zusammt dem Bewußtsein in sie übertragen worden, und dem unerachtet würde sie doch nicht eben dieselbe Person in allen diesen Zuständen gewesen sein."}], "markers": [{"system": "A", "ref": "A366"}], "running_header": "Dritter Paralogism, der Personalität [A, Anhang]"}, {"page_pdf": 1430, "page_book": null, "page_kind": "body", "sigel": "A366 · A367 · A368 · A369", "units": [{"type": "paragraph", "text": "[A] Der vierte Paralogism, der Idealität (des äußeren Verhältnisses). Dasjenige, auf dessen Dasein nur als einer Ursache zu gegebenen Wahrnehmungen geschlossen werden kann, hat eine nur zweifelhafte Existenz. Nun sind alle äußere Erscheinungen von der Art, daß ihr Dasein nicht unmittelbar wahrgenommen, sondern auf sie als die Ursache gegebener Wahrnehmungen allein geschlossen werden kann: Also ist das Dasein aller Gegenstände äußerer Sinne zweifelhaft. Diese Ungewißheit nenne ich die Idealität äußerer Erscheinungen, und die Lehre dieser Idealität heißt der Idealism, in Vergleichung mit welchem die Behauptung einer möglichen Gewißheit von Gegenständen äußerer Sinne der Dualism genannt wird."}, {"type": "paragraph", "text": "Kritik des vierten Paralogisms der transscendentalen Psychologie."}, {"type": "paragraph", "text": "Zuerst wollen wir die Prämissen der Prüfung unterwerfen. Wir können mit Recht behaupten, daß nur dasjenige, was in uns selbst ist, unmittelbar wahrgenommen werden könne, und daß meine eigene Existenz allein der Gegenstand einer bloßen Wahrnehmung sein könne. Also ist das Dasein eines wirklichen Gegenstandes außer mir (wenn dieses Wort in intellectueller Bedeutung genommen wird) niemals gerade zu in der Wahrnehmung gegeben, sondern kann nur zu dieser, welche eine Modification des inneren Sinnes ist, als äußere Ursache derselben hinzu gedacht und mithin geschlossen werden. Daher auch Cartesius mit Recht alle Wahrnehmung in der engsten Bedeutung auf den Satz einschränkte: Ich (als ein denkend Wesen) bin. Es ist nämlich klar, daß, da das Äußere nicht in mir ist, ich es nicht in meiner Apperception, mithin auch in keiner Wahrnehmung, welche eigentlich nur die Bestimmung der Apperception ist, antreffen könne. Ich kann also äußere Dinge eigentlich nicht wahrnehmen, sondern nur aus meiner inneren Wahrnehmung auf ihr Dasein schließen, indem ich diese als die Wirkung ansehe, wozu etwas Äußeres die nächste Ursache ist. Nun ist aber der Schluß von einer gegebenen Wirkung auf eine bestimmte Ursache jederzeit unsicher, weil die Wirkung aus mehr als einer Ursache entsprungen sein kann. Demnach bleibt es in der Beziehung der Wahrnehmung auf ihre Ursache jederzeit zweifelhaft, ob diese innerlich, oder äußerlich sei, ob also alle sogenannte äußere Wahrnehmungen nicht ein bloßes Spiel unseres innern Sinnes seien, oder ob sie sich auf äußere wirkliche Gegenstände als ihre Ursache beziehen. Wenigstens ist das Dasein der letzteren nur geschlossen und läuft die Gefahr aller Schlüsse, da hingegen der Gegenstand des inneren Sinnes (Ich selbst mit allen meinen Vorstellungen) unmittelbar wahrgenommen wird, und die Existenz desselben gar keinen Zweifel leidet. Unter einem Idealisten muß man also nicht denjenigen verstehen, der das Dasein äußerer Gegenstände der Sinne läugnet, sondern der nur nicht einräumt, daß es durch unmittelbare Wahrnehmung erkannt werde, daraus aber schließt, daß wir ihrer Wirklichkeit durch alle mögliche Erfahrung niemals völlig gewiß werden können. Ehe ich nun unseren Paralogismus seinem trüglichen Scheine nach darstelle, muß ich zuvor bemerken, daß man nothwendig einen zweifachen Idealism unterscheiden müsse, den transscendentalen und den empirischen. Ich verstehe aber unter dem transscendentalen Idealism aller Erscheinungen den Lehrbegriff, nach welchem wir sie insgesammt als bloße Vorstellungen und nicht als Dinge an sich selbst ansehen, und dem gemäß Zeit und Raum nur sinnliche Formen unserer Anschauung, nicht aber für sich gegebene Bestimmungen oder Bedingungen der Objecte als Dinge an sich selbst sind. Diesem Idealism ist ein transscendentaler Realism entgegengesetzt, der Zeit und Raum als etwas an sich (unabhängig von unserer Sinnlichkeit) Gegebenes ansieht. Der transscendentale Realist stellt sich"}], "markers": [{"system": "A", "ref": "A366"}, {"system": "A", "ref": "A367"}, {"system": "A", "ref": "A368"}, {"system": "A", "ref": "A369"}], "running_header": "Der vierte Paralogism, der Idealität (des äußeren Verhältnisses) [A, Anhang]"}, {"page_pdf": 1431, "page_book": null, "page_kind": "body", "sigel": "A370 · A371 · A372", "units": [{"type": "paragraph", "text": "also äußere Erscheinungen (wenn man ihre Wirklichkeit einräumt) als Dinge an sich selbst vor, die unabhängig von uns und unserer Sinnlichkeit existiren, also auch nach reinen Verstandesbegriffen außer uns wären. Dieser transscendentale Realist ist es eigentlich, welcher nachher den empirischen Idealisten spielt und, nachdem er fälschlich von Gegenständen der Sinne vorausgesetzt hat, daß, wenn sie äußere sein sollen, sie an sich selbst, auch ohne Sinne, ihre Existenz haben müßten, in diesem Gesichtspunkte alle unsere Vorstellungen der Sinne unzureichend findet, die Wirklichkeit derselben gewiß zu machen. Der transscendentale Idealist kann hingegen ein empirischer Realist, mithin, wie man ihn nennt, ein Dualist sein, d.i. die Existenz der Materie einräumen, ohne aus dem bloßen Selbstbewußtsein hinauszugehen und etwas mehr als die Gewißheit der Vorstellungen in mir, mithin das _cogito, ergo sum_ anzunehmen. Denn weil er diese Materie und sogar deren innere Möglichkeit blos für Erscheinung gelten läßt, die, von unserer Sinnlichkeit abgetrennt, nichts ist: so ist sie bei ihm nur eine Art Vorstellungen (Anschauung), welche äußerlich heißen, nicht als ob sie sich auf an sich selbst äußere Gegenstände bezögen, sondern weil sie Wahrnehmungen auf den Raum beziehen, in welchem alles außer einander, er selbst, der Raum, aber in uns ist. Für diesen transscendentalen Idealism haben wir uns nun schon im Anfange erklärt. Also fällt bei unserem Lehrbegriff alle Bedenklichkeit weg, das Dasein der Materie eben so auf das Zeugniß unseres bloßen Selbstbewußtseins anzunehmen und dadurch für bewiesen zu erklären, wie das Dasein meiner selbst als eines denkenden Wesens. Denn ich bin mir doch meiner Vorstellungen bewußt; also existiren diese und ich selbst, der ich diese Vorstellungen habe. Nun sind aber äußere Gegenstände (die Körper) blos Erscheinungen, mithin auch nichts anders als eine Art meiner Vorstellungen, deren Gegenstände nur durch diese Vorstellungen etwas sind, von ihnen abgesondert aber nichts sind. Also existiren eben sowohl äußere Dinge, als ich selbst existire, und zwar beide auf das unmittelbare Zeugniß meines Selbstbewußtseins, nur mit dem Unterschiede, daß die Vorstellung meiner selbst als des denkenden Subjects blos auf den innern, die Vorstellungen aber, welche ausgedehnte Wesen bezeichnen, auch auf den äußern Sinn bezogen werden. Ich habe in Absicht auf die Wirklichkeit äußerer Gegenstände eben so wenig nöthig zu schließen, als in Ansehung der Wirklichkeit des Gegenstandes meines innern Sinnes (meiner Gedanken); denn sie sind beiderseitig nichts als Vorstellungen, deren unmittelbare Wahrnehmung (Bewußtsein) zugleich ein genugsamer Beweis ihrer Wirklichkeit ist. Also ist der transscendentale Idealist ein empirischer Realist und gesteht der Materie als Erscheinung eine Wirklichkeit zu, die nicht geschlossen werden darf, sondern unmittelbar wahrgenommen wird. Dagegen kommt der transscendentale Realismus nothwendig in Verlegenheit und sieht sich genöthigt, dem empirischen Idealismus Platz einzuräumen, weil er die Gegenstände äußerer Sinne für etwas von den Sinnen selbst Unterschiedenes und bloße Erscheinungen für selbstständige Wesen ansieht, die sich außer uns befinden; da denn freilich bei unserem besten Bewußtsein unserer Vorstellung von diesen Dingen noch lange nicht gewiß ist, daß, wenn die Vorstellung existirt, auch der ihr correspondirende Gegenstand existire; dahingegen in unserem System diese äußere Dinge, die Materie nämlich, in allen ihren Gestalten und Veränderungen nichts als bloße Erscheinungen, d.i. Vorstellungen in uns, sind, deren Wirklichkeit wir uns unmittelbar bewußt werden. Da nun, so viel ich weiß, alle dem empirischen Idealismus anhängende Psychologen transscendentale Realisten sind, so haben sie freilich ganz consequent verfahren, dem empirischen Idealism große Wichtigkeit zuzugestehen, als einem von den Problemen, daraus die menschliche Vernunft sich schwerlich zu helfen wisse. Denn in der That, wenn man äußere Erscheinungen als Vorstellungen ansieht, die von ihren Gegenständen als an sich außer uns befindlichen Dingen in uns gewirkt werden, so ist nicht abzusehen, wie man dieser ihr Dasein anders als durch den Schluß von der Wirkung auf die Ursache erkennen könne, bei welchem es immer zweifelhaft"}], "markers": [{"system": "A", "ref": "A370"}, {"system": "A", "ref": "A371"}, {"system": "A", "ref": "A372"}], "running_header": "Der vierte Paralogism, der Idealität (des äußeren Verhältnisses) [A, Anhang]"}, {"page_pdf": 1432, "page_book": null, "page_kind": "body", "sigel": "A373 · A374", "units": [{"type": "paragraph", "text": "bleiben muß, ob die letztere in uns, oder außer uns sei. Nun kann man zwar einräumen, daß von unseren äußeren Anschauungen etwas, was im transscendentalen Verstande außer uns sein mag, die Ursache sei; aber dieses ist nicht der Gegenstand, den wir unter den Vorstellungen der Materie und körperlicher Dinge verstehen; denn diese sind lediglich Erscheinungen, d.i. bloße Vorstellungsarten, die sich jederzeit nur in uns befinden, und deren Wirklichkeit auf dem unmittelbaren Bewußtsein eben so, wie das Bewußtsein meiner eigenen Gedanken beruht. Der transscendentale Gegenstand ist sowohl in Ansehung der inneren als äußeren Anschauung gleich unbekannt. Von ihm aber ist auch nicht die Rede, sondern von dem empirischen, welcher alsdann ein äußerer heißt, wenn er im Raume, und ein innerer Gegenstand, wenn er lediglich im Zeitverhältnisse vorgestellt wird; Raum aber und Zeit sind beide nur in uns anzutreffen. Weil indessen der Ausdruck: außer uns, eine nicht zu vermeidende Zweideutigkeit bei sich führt, indem er bald etwas bedeutet, was als Ding an sich selbst von uns unterschieden existirt, bald was blos zur äußeren Erscheinung gehört, so wollen wir, um diesen Begriff in der letzteren Bedeutung, als in welcher eigentlich die psychologische Frage wegen der Realität unserer äußeren Anschauung genommen wird, außer Unsicherheit zu setzen, empirisch äußerliche Gegenstände dadurch von denen, die so im transscendentalen Sinne heißen möchten, unterscheiden, daß wir sie gerade zu Dinge nennen, die im Raume anzutreffen sind. Raum und Zeit sind zwar Vorstellungen _a priori_, welche uns als Formen unserer sinnlichen Anschauung beiwohnen, ehe noch ein wirklicher Gegenstand unseren Sinn durch Empfindung bestimmt hat, um ihn unter jenen sinnlichen Verhältnissen vorzustellen. Allein dieses Materielle oder Reale, dieses Etwas, was im Raume angeschaut werden soll, setzt nothwendig Wahrnehmung voraus und kann unabhängig von dieser, welche die Wirklichkeit von Etwas im Raume anzeigt, durch keine Einbildungskraft gedichtet und hervorgebracht werden. Empfindung ist also dasjenige, was eine Wirklichkeit im Raume und der Zeit bezeichnet, nachdem sie auf die eine oder die andere Art der sinnlichen Anschauung bezogen wird. Ist Empfindung einmal gegeben (welche, wenn sie auf einen Gegenstand überhaupt, ohne diesen zu bestimmen, angewandt wird, Wahrnehmung heißt), so kann durch die Mannigfaltigkeit derselben mancher Gegenstand in der Einbildung gedichtet werden, der außer der Einbildung im Raume oder der Zeit keine empirische Stelle hat. Dieses ist ungezweifelt gewiß; man mag nun die Empfindungen Lust und Schmerz, oder auch der äußeren Sinne, als Farben, Wärme etc. nehmen, so ist Wahrnehmung dasjenige, wodurch der Stoff, um Gegenstände der sinnlichen Anschauung zu denken, zuerst gegeben werden muß. Diese Wahrnehmung stellt also (damit wir diesmal nur bei äußeren Anschauungen bleiben) etwas Wirkliches im Raume vor. Denn erstlich ist Wahrnehmung die Vorstellung einer Wirklichkeit, so wie Raum die Vorstellung einer bloßen Möglichkeit des Beisammenseins. Zweitens wird diese Wirklichkeit vor dem äußeren Sinn, d.i. im Raume, vorgestellt. Drittens ist der Raum selbst nichts anders als bloße Vorstellung; mithin kann in ihm nur das als wirklich gelten, was in ihm vorgestellt* wird, und umgekehrt, was in ihm A375 _R_ gegeben, d.i. durch Wahrnehmung vorgestellt wird, ist in ihm auch wirklich; denn wäre es in ihm nicht wirklich, d.i. unmittelbar durch empirische Anschauung gegeben, so könnte es auch nicht erdichtet werden, weil man das Reale der Anschauungen gar nicht _a priori_ erdenken kann. Alle äußere Wahrnehmung also beweiset unmittelbar etwas Wirkliches im Raume, oder ist vielmehr das Wirkliche selbst, und in so fern ist also der empirische Realismus außer Zweifel, d.i. es correspondirt unseren äußeren Anschauungen etwas Wirkliches im Raume. Freilich ist der Raum selbst mit allen seinen Erscheinungen als Vorstellungen nur in mir, aber in diesem Raume ist doch gleichwohl das Reale oder der Stoff aller Gegenstände äußerer Anschauung wirklich und unabhängig von aller Erdichtung gegeben, und es ist auch unmöglich, daß in diesem Raume irgend etwas außer uns (im transscendentalen Sinne) gegeben werden sollte, weil der Raum"}], "markers": [{"system": "A", "ref": "A373"}, {"system": "A", "ref": "A374"}], "running_header": "Der vierte Paralogism, der Idealität (des äußeren Verhältnisses) [A, Anhang]"}, {"page_pdf": 1433, "page_book": null, "page_kind": "body", "sigel": "A376 · A377 · A378", "units": [{"type": "paragraph", "text": "selbst außer unserer Sinnlichkeit nichts ist. Also kann der strengste Idealist nicht verlangen, man solle beweisen, daß unserer Wahrnehmung der Gegenstand außer uns (in stricter Bedeutung) entspreche. Denn wenn es dergleichen gäbe, so würde es doch nicht als außer uns vorgestellt und angeschauet werden können, weil dieses den Raum voraussetzt, und die Wirklichkeit im Raume als einer bloßen Vorstellung nichts anders als die Wahrnehmung selbst ist. Das Reale äußerer Erscheinungen ist also wirklich nur in der Wahrnehmung und kann auf keine andere Weise wirklich sein. Aus Wahrnehmungen kann nun entweder durch ein bloßes Spiel der Einbildung, oder auch vermittelst der Erfahrung Erkenntniß der Gegenstände erzeugt werden. Und da können allerdings trügliche Vorstellungen entspringen, denen die Gegenstände nicht entsprechen und wobei die Täuschung bald einem Blendwerke der Einbildung (im Traume), bald einem Fehltritte der Urtheilskraft (beim sogenannten Betruge der Sinne) beizumessen ist. Um nun hierin dem falschen Scheine zu entgehen, verfährt man nach der Regel: Was mit einer Wahrnehmung nach empirischen Gesetzen zusammenhängt, ist wirklich. Allein diese Täuschung sowohl, als die Verwahrung wider dieselbe trifft eben sowohl den Idealism als den Dualism, indem es dabei nur um die Form der Erfahrung zu thun ist. Den empirischen Idealismus, als eine falsche Bedenklichkeit wegen der objectiven Realität unserer äußeren Wahrnehmungen, zu widerlegen, ist schon hinreichend: daß äußere Wahrnehmung eine Wirklichkeit im Raume unmittelbar beweise, welcher Raum, ob er zwar an sich nur bloße Form der Vorstellungen ist, dennoch in Ansehung aller äußeren Erscheinungen (die auch nichts anders als bloße Vorstellungen sind) objective Realität hat; imgleichen: daß ohne Wahrnehmung selbst die Erdichtung und der Traum nicht möglich seien, unsere äußere Sinne also den _datis_ nach, woraus Erfahrung entspringen kann, ihre wirkliche correspondirende Gegenstände im Raume haben. Der dogmatische Idealist würde derjenige sein, der das Dasein der Materie läugnet, der sceptische, der sie bezweifelt, weil er sie für unerweislich hält. Der erstere kann es nur darum sein, weil er in der Möglichkeit einer Materie überhaupt Widersprüche zu finden glaubt; und mit diesem haben wir es jetzt noch nicht zu thun. Der folgende Abschnitt von dialektischen Schlüssen, der die Vernunft in ihrem inneren Streite in Ansehung der Begriffe von der Möglichkeit dessen, was in den Zusammenhang der Erfahrung gehört, vorstellt, wird auch dieser Schwierigkeit abhelfen. Der sceptische Idealist aber, der blos den Grund unserer Behauptung anficht und unsere Überredung von dem Dasein der Materie, die wir auf unmittelbare Wahrnehmung zu gründen glauben, für unzureichend erklärt, ist so fern ein Wohlthäter der menschlichen Vernunft, als er uns nöthigt, selbst bei dem kleinsten Schritte der gemeinen Erfahrung die Augen wohl aufzuthun und, was wir vielleicht nur erschleichen, nicht sogleich als wohlerworben in unseren Besitz aufzunehmen. Der Nutzen, den diese idealistische Einwürfe hier schaffen, fällt jetzt klar in die Augen. Sie treiben uns mit Gewalt dahin, wenn wir uns nicht in unseren gemeinsten Behauptungen verwickeln wollen, alle Wahrnehmungen, sie mögen nun innere oder äußere heißen, blos als ein Bewußtsein dessen, was unserer Sinnlichkeit anhängt, und die äußere Gegenstände derselben nicht für Dinge an sich selbst, sondern nur für Vorstellungen anzusehen, deren wir uns wie jeder anderen Vorstellung unmittelbar bewußt werden können, die aber darum äußere heißen, weil sie demjenigen Sinne anhängen, den wir den äußeren Sinn nennen, dessen Anschauung der Raum ist, der aber doch selbst nichts anders als eine innere Vorstellungsart ist, in welcher sich gewisse Wahrnehmungen mit einander verknüpfen. Wenn wir äußere Gegenstände für Dinge an sich gelten lassen, so ist schlechthin unmöglich zu begreifen, wie wir zur Erkenntniß ihrer Wirklichkeit außer uns kommen sollten, indem wir uns blos auf die Vorstellung stützen, die in uns ist. Denn man kann doch außer sich nicht empfinden, sondern nur in sich selbst, und das ganze Selbstbewußtsein liefert daher nichts, als lediglich unsere eigene Bestimmungen. Also nöthigt uns der sceptische Idealism, die einzige Zuflucht, die uns übrig bleibt, nämlich zu der Idealität aller Erscheinungen, zu ergreifen, welche wir in der"}], "markers": [{"system": "A", "ref": "A376"}, {"system": "A", "ref": "A377"}, {"system": "A", "ref": "A378"}], "running_header": "Der vierte Paralogism, der Idealität (des äußeren Verhältnisses) [A, Anhang]"}, {"page_pdf": 1434, "page_book": null, "page_kind": "body", "sigel": "A379 · A380", "units": [{"type": "paragraph", "text": "transscendentalen Ästhetik unabhängig von diesen Folgen, die wir damals nicht voraussehen konnten, dargethan haben. Frägt man nun, ob denn diesem zu Folge der Dualism allein in der Seelenlehre statt finde, so ist die Antwort: Allerdings! aber nur im empirischen Verstande; d.i. in dem Zusammenhange der Erfahrung ist wirklich Materie als Substanz in der Erscheinung dem äußeren Sinne, so wie das denkende Ich, gleichfalls als Substanz in der Erscheinung, vor dem inneren Sinne gegeben; und nach den Regeln, welche diese Kategorie in den Zusammenhang unserer äußeren sowohl als inneren Wahrnehmungen zu einer Erfahrung hineinbringt, müssen auch beiderseits Erscheinungen unter sich verknüpft werden. Wollte man aber den Begriff des Dualismus, wie es gewöhnlich geschieht, erweitern und ihn im transscendentalen Verstande nehmen, so hätten weder er, noch der ihm entgegengesetzte Pneumatismus einerseits, oder der Materialismus andererseits nicht den mindesten Grund, indem man alsdann die Bestimmung seiner Begriffe verfehlte und die Verschiedenheit der Vorstellungsart von Gegenständen, die uns nach dem, was sie an sich sind, unbekannt bleiben, für eine Verschiedenheit dieser Dinge selbst hält. Ich, durch den innern Sinn in der Zeit vorgestellt, und Gegenstände im Raume außer mir sind zwar specifisch ganz unterschiedene Erscheinungen, aber dadurch werden sie nicht als verschiedene Dinge gedacht. Das transscendentale Object, welches den äußeren Erscheinungen, imgleichen das, was der innern Anschauung zum Grunde liegt, ist weder Materie, noch ein denkend Wesen an sich selbst, sondern ein uns unbekannter Grund der Erscheinungen, die den empirischen Begriff von der ersten sowohl als zweiten Art an die Hand geben. Wenn wir also, wie uns denn die gegenwärtige Kritik augenscheinlich dazu nöthigt, der oben festgesetzten Regel treu bleiben, unsere Fragen nicht weiter zu treiben, als nur so weit mögliche Erfahrung uns das Object derselben an die Hand geben kann: so werden wir es uns nicht einmal einfallen lassen, über die Gegenstände unserer Sinne nach demjenigen, was sie an sich selbst, d.i. ohne alle Beziehung auf die Sinne, sein mögen, Erkundigung anzustellen. Wenn aber der Psycholog Erscheinungen für Dinge an sich selbst nimmt, so mag er als Materialist einzig und allein Materie, oder als Spiritualist blos denkende Wesen (nämlich nach der Form unsers innern Sinnes), oder als Dualist beide als für sich existirende Dinge in seinen Lehrbegriff aufnehmen: so ist er doch immer durch Mißverstand hingehalten über die Art zu vernünfteln, wie dasjenige an sich selbst existiren möge, was doch kein Ding an sich, sondern nur die Erscheinung eines Dinges überhaupt ist."}, {"type": "paragraph", "text": "Anmerkungen: * Man muß diesen paradoxen, aber richtigen Satz wohl merken: daß im Raume nichts sei, als was in ihm vorgestellt wird. Denn der Raum ist selbst nichts anders als Vorstellung; folglich was in ihm ist, muß in der //A375// Vorstellung enthalten sein, und im Raume ist gar nichts, außer so fern es in ihm wirklich vorgestellt wird. Ein Satz, der allerdings befremdlich klingen muß, daß eine Sache nur in der Vorstellung von ihr existiren könne, der aber hier das Anstößige verliert, weil die Sachen, mit denen wir es zu thun haben, nicht Dinge an sich, sondern nur Erscheinungen, d.i. Vorstellungen, sind."}], "markers": [{"system": "A", "ref": "A379"}, {"system": "A", "ref": "A380"}], "running_header": "Der vierte Paralogism, der Idealität (des äußeren Verhältnisses) [A, Anhang]"}, {"page_pdf": 1435, "page_book": null, "page_kind": "body", "sigel": "A381 · A382 · A383", "units": [{"type": "paragraph", "text": "[A] Betrachtung über die Summe der reinen Seelenlehre zu Folge diesen Paralogismen. Wenn wir die Seelenlehre als die Physiologie des inneren Sinnes mit der Körperlehre als einer Physiologie der Gegenstände äußerer Sinne vergleichen: so finden wir außer dem, daß in beiden vieles empirisch erkannt werden kann, doch diesen merkwürdigen Unterschied, daß in der letzteren Wissenschaft doch vieles _a priori_ aus dem bloßen Begriffe eines ausgedehnten undurchdringlichen Wesens, in der ersteren aber aus dem Begriffe eines denkenden Wesens gar nichts _a priori_ synthetisch erkannt werden kann. Die Ursache ist diese. Obgleich beides Erscheinungen sind, so hat doch die Erscheinung vor dem äußeren Sinne etwas Stehendes oder Bleibendes, welches ein den wandelbaren Bestimmungen zum Grunde liegendes Substratum und mithin einen synthetischen Begriff, nämlich den vom Raume und einer Erscheinung in demselben, an die Hand giebt: anstatt daß die Zeit, welche die einzige Form unserer innern Anschauung ist, nichts Bleibendes hat, mithin nur den Wechsel der Bestimmungen, nicht aber den bestimmbaren Gegenstand zu erkennen giebt. Denn in dem, was wir Seele nennen, ist alles im continuirlichen Flusse und nichts Bleibendes außer _E_ etwa (wenn man es durchaus will) das darum so einfache Ich, weil diese Vorstellung keinen Inhalt, mithin kein Mannigfaltiges hat, weswegen sie auch scheint ein einfaches Object vorzustellen oder, besser gesagt, zu bezeichnen. Dieses Ich müßte eine Anschauung sein, welche, da sie beim Denken überhaupt (vor aller Erfahrung) vorausgesetzt würde, als Anschauung _a priori_ synthetische Sätze lieferte, wenn es möglich sein sollte, eine reine Vernunfterkenntniß von der Natur eines denkenden Wesens überhaupt zu Stande zu bringen. Allein dieses Ich ist so wenig Anschauung als Begriff von irgend einem Gegenstande, sondern _E_ die bloße Form des Bewußtseins, welches beiderlei Vorstellungen begleiten und sie dadurch zu Erkenntnissen erheben kann, so fern nämlich dazu noch irgend etwas anders in der Anschauung gegeben wird, welches zu einer Vorstellung von einem Gegenstande Stoff darreicht. Also fällt die ganze rationale Psychologie als eine alle Kräfte der menschlichen Vernunft übersteigende Wissenschaft, und es bleibt uns nichts übrig, als unsere Seele an dem Leitfaden der Erfahrung zu studiren und uns in den Schranken der Fragen zu halten, die nicht weiter gehen, als mögliche innere Erfahrung ihren Inhalt darlegen kann. Ob sie nun aber gleich als erweiternde Erkenntniß keinen Nutzen hat, sondern auch solche aus lauter Paralogismen zusammengesetzt ist, so kann man ihr doch, wenn sie für nichts mehr als eine kritische Behandlung unserer dialektischen Schlüsse und zwar der gemeinen und natürlichen Vernunft gelten soll, einen wichtigen negativen Nutzen nicht absprechen. Wozu haben wir wohl eine blos auf reine Vernunftprincipien gegründete Seelenlehre nöthig? Ohne Zweifel vorzüglich in der Absicht, um unser denkendes Selbst wider die Gefahr des Materialismus zu sichern. Dieses leistet aber der Vernunftbegriff von unserem denkenden Selbst, den wir gegeben haben. Denn weit gefehlt, daß nach demselben einige Furcht übrig bliebe, daß, wenn man die Materie wegnähme, dadurch alles Denken und selbst die Existenz denkender Wesen aufgehoben werden würde, so wird vielmehr klar gezeigt, daß, wenn ich das denkende Subject wegnehme, die ganze Körperwelt wegfallen muß, als die nichts ist, als die Erscheinung in der Sinnlichkeit unseres Subjects und eine Art Vorstellungen desselben. Dadurch erkenne ich zwar freilich dieses denkende Selbst seinen Eigenschaften nach nicht besser, noch kann ich seine Beharrlichkeit, ja selbst nicht einmal die Unabhängigkeit seiner Existenz von dem etwanigen transscendentalen Substratum äußerer Erscheinungen einsehen; denn dieses ist mir eben sowohl als jenes unbekannt. Weil es aber gleichwohl möglich ist, daß ich anders woher als aus blos speculativen Gründen Ursache hernähme, eine selbstständige und bei allem möglichen Wechsel meines Zustandes beharrliche Existenz meiner denkenden Natur zu hoffen, so ist dadurch schon viel gewonnen, bei dem freien Geständniß meiner eigenen Unwissenheit dennoch die dogmatische Angriffe eines speculativen Gegners abtreiben zu können"}], "markers": [{"system": "A", "ref": "A381"}, {"system": "A", "ref": "A382"}, {"system": "A", "ref": "A383"}], "running_header": "Betrachtung über die Summe der reinen Seelenlehre zu Folge diesen Paralogismen [A, Anhang]"}, {"page_pdf": 1436, "page_book": null, "page_kind": "body", "sigel": "A384 · A385 · A386", "units": [{"type": "paragraph", "text": "und ihm zu zeigen, daß er niemals mehr von der Natur meines Subjects wissen könne, um meinen Erwartungen die Möglichkeit abzusprechen, als ich, um mich an ihnen zu halten. Auf diesen transscendentalen Schein unserer psychologischen Begriffe gründen sich dann noch drei dialektische Fragen, welche das eigentliche Ziel der rationalen Psychologie ausmachen und nirgend anders, als durch obige Untersuchungen entschieden werden können, nämlich: 1) von der Möglichkeit der Gemeinschaft der Seele mit einem organischen Körper, d.i. der Animalität und dem Zustande der Seele im Leben des Menschen; 2) vom Anfange dieser Gemeinschaft, d.i. der Seele in und vor der Geburt des Menschen; 3) dem Ende dieser Gemeinschaft, d.i. der Seele im und nach dem Tode des Menschen (Frage wegen der Unsterblichkeit). Ich behaupte nun, daß alle Schwierigkeiten, die man bei diesen Fragen vorzufinden glaubt, und mit denen als dogmatischen Einwürfen man sich das Ansehen einer tieferen Einsicht in die Natur der Dinge, als der gemeine Verstand wohl haben kann, zu geben sucht, auf einem bloßen Blendwerke beruhen, nach welchem man das, was blos in Gedanken existirt, hypostasirt und in eben derselben Qualität als einen wirklichen Gegenstand außerhalb dem denkenden Subjecte annimmt, nämlich Ausdehnung, die nichts als Erscheinung ist, für eine auch ohne unsere Sinnlichkeit subsistirende Eigenschaft äußerer Dinge und Bewegung für deren Wirkung, welche auch außer unseren Sinnen an sich wirklich vorgeht, zu halten. Denn die Materie, deren Gemeinschaft mit der Seele so großes Bedenken erregt, ist nichts anders als eine bloße Form oder eine gewisse Vorstellungsart eines unbekannten Gegenstandes durch diejenige Anschauung, welche man den äußeren Sinn nennt. Es mag also wohl etwas außer uns sein, dem diese Erscheinung, welche wir Materie nennen, correspondirt; aber in derselben Qualität als Erscheinung ist es nicht außer uns, sondern lediglich als ein Gedanke in uns, wiewohl dieser Gedanke durch genannten Sinn es als außer uns befindlich vorstellt. Materie bedeutet also nicht eine von dem Gegenstande des inneren Sinnes (Seele) so ganz unterschiedene und heterogene Art von Substanzen, sondern nur die Ungleichartigkeit der Erscheinungen von Gegenständen (die uns an sich selbst unbekannt sind), deren Vorstellungen wir äußere nennen in Vergleichung mit denen, die wir zum inneren Sinne zählen, ob sie gleich eben sowohl blos zum denkenden Subjecte, als alle übrige Gedanken gehören, nur daß sie dieses Täuschende an sich haben: daß, da sie Gegenstände im Raume vorstellen, sie sich gleichsam von der Seele ablösen und außer ihr zu schweben scheinen, da doch selbst der Raum, darin sie angeschauet werden, nichts als eine Vorstellung ist, deren Gegenbild in derselben Qualität außer der Seele gar nicht angetroffen werden kann. Nun ist die Frage nicht mehr von der Gemeinschaft der Seele mit anderen bekannten und fremdartigen Substanzen außer uns, sondern blos von der Verknüpfung der Vorstellungen des inneren Sinnes mit den Modificationen unserer äußeren Sinnlichkeit, und wie diese unter einander nach beständigen Gesetzen verknüpft sein mögen, so daß sie in einer Erfahrung zusammenhängen. So lange wir innere und äußere Erscheinungen als bloße Vorstellungen in der Erfahrung mit einander zusammen halten, so finden wir nichts Widersinnisches und welches die Gemeinschaft beider Art Sinne befremdlich machte. Sobald wir aber die äußere Erscheinungen hypostasiren, sie nicht mehr als Vorstellungen, sondern in derselben Qualität, wie sie in uns sind, auch als außer uns für sich bestehende Dinge, ihre Handlungen aber, die sie als Erscheinungen gegen einander im Verhältniß zeigen, auf unser denkendes Subject beziehen, so haben wir einen Charakter der wirkenden Ursachen außer uns, der sich mit ihren Wirkungen in uns nicht zusammen reimen will, weil jener sich blos auf äußere Sinne, diese aber auf den innern Sinn beziehen, welche, ob sie zwar in einem Subjecte vereinigt, dennoch höchst ungleichartig sind. Da haben wir denn keine andere äußere Wirkungen als Veränderungen des Orts und keine Kräfte als blos Bestrebungen, welche auf Verhältnisse im Raume als ihre Wirkungen auslaufen. In uns aber sind die Wirkungen Gedanken, unter denen kein Verhältniß des"}], "markers": [{"system": "A", "ref": "A384"}, {"system": "A", "ref": "A385"}, {"system": "A", "ref": "A386"}], "running_header": "Betrachtung über die Summe der reinen Seelenlehre zu Folge diesen Paralogismen [A, Anhang]"}, {"page_pdf": 1437, "page_book": null, "page_kind": "body", "sigel": "A387 · A388 · A389", "units": [{"type": "paragraph", "text": "Orts, Bewegung, Gestalt oder Raumesbestimmung überhaupt statt findet, und wir verlieren den Leitfaden der Ursachen gänzlich an den Wirkungen, die sich davon in dem inneren Sinne zeigen sollten. Aber wir sollten bedenken: daß nicht die Körper Gegenstände an sich sind, die uns gegenwärtig sind, sondern eine bloße Erscheinung wer weiß welches unbekannten Gegenstandes; daß die Bewegung nicht die Wirkung dieser unbekannten Ursache, sondern blos die Erscheinung ihres Einflusses auf unsere Sinne sei, daß folglich beide nicht Etwas außer uns, sondern blos Vorstellungen in uns seien, mithin daß nicht die Bewegung der Materie in uns Vorstellungen wirke, sondern daß sie selbst (mithin auch die Materie, die sich dadurch kennbar macht) bloße Vorstellung sei; und endlich die ganze selbstgemachte Schwierigkeit darauf hinauslaufe: wie und durch welche Ursache die Vorstellungen unserer Sinnlichkeit so untereinander in Verbindung stehen, daß diejenige, welche wir äußere Anschauungen nennen, nach empirischen Gesetzen als Gegenstände außer uns vorgestellt werden können; welche Frage nun ganz und gar nicht die vermeinte Schwierigkeit enthält, den Ursprung der Vorstellungen von außer uns befindlichen, ganz fremdartigen wirkenden Ursachen zu erklären, indem wir die Erscheinungen einer unbekannten Ursache für die Ursache außer uns nehmen, welches nichts als Verwirrung veranlassen kann. In Urtheilen, in denen eine durch lange Gewohnheit eingewurzelte Mißdeutung vorkommt, ist es unmöglich, die Berichtigung sofort zu derjenigen Faßlichkeit zu bringen, welche in anderen Fällen gefördert werden kann, wo keine dergleichen unvermeidliche Illusion den Begriff verwirrt. Daher wird diese unsere Befreiung der Vernunft von sophistischen Theorien schwerlich schon die Deutlichkeit haben, die ihr zur völligen Befriedigung nöthig ist. Ich glaube diese auf folgende Weise befördern zu können. Alle Einwürfe können in dogmatische, kritische und sceptische eingetheilt werden. Der dogmatische Einwurf ist, der wider einen Satz, der kritische, der wider den Beweis eines Satzes gerichtet ist. Der erstere bedarf einer Einsicht in die Beschaffenheit der Natur des Gegenstandes, um das Gegentheil von demjenigen behaupten zu können, was der Satz von diesem Gegenstande vorgiebt; er ist daher selbst dogmatisch und giebt vor, die Beschaffenheit, von der die Rede ist, besser zu kennen als der Gegentheil. Der kritische Einwurf, weil er den Satz in seinem Werthe oder Unwerthe unangetastet läßt und nur den Beweis anficht, bedarf gar nicht den Gegenstand besser zu kennen, oder sich einer besseren Kenntniß desselben anzumaßen; er zeigt nur, daß die Behauptung grundlos, nicht, daß sie unrichtig sei. Der sceptische stellt Satz und Gegensatz wechselseitig gegen einander als Einwürfe von gleicher Erheblichkeit, einen jeden derselben wechselsweise als Dogma und den andern als dessen Einwurf, ist also auf zwei entgegengesetzten Seiten dem Scheine nach dogmatisch, um alles Urtheil über den Gegenstand gänzlich zu vernichten. Der dogmatische also sowohl als sceptische Einwurf müssen beide so viel Einsicht ihres Gegenstandes vorgeben, als nöthig ist, etwas von ihm bejahend oder verneinend zu behaupten. Der kritische ist allein von der Art, daß, indem er blos zeigt, man nehme zum Behuf seiner Behauptung etwas an, was nichtig und blos eingebildet ist, die Theorie stürzt, dadurch daß er ihr die angemaßte Grundlage entzieht, ohne sonst etwas über die Beschaffenheit des Gegenstandes ausmachen zu wollen. Nun sind wir nach den gemeinen Begriffen unserer Vernunft in Ansehung der Gemeinschaft, darin unser denkendes Subject mit den Dingen außer uns steht, dogmatisch und sehen diese als wahrhafte, unabhängig von uns bestehende Gegenstände an nach einem gewissen transscendentalen Dualism, der jene äußere Erscheinungen nicht als Vorstellungen zum Subjecte zählt, sondern sie, so wie sinnliche Anschauung sie uns liefert, außer uns als Objecte versetzt und sie von dem denkenden Subjecte gänzlich abtrennt. Diese Subreption ist nun die Grundlage aller Theorien über die Gemeinschaft zwischen Seele und Körper, und es wird niemals gefragt, ob denn diese objective Realität der Erscheinungen so ganz richtig sei, sondern diese wird als zugestanden vorausgesetzt und nur über die Art vernünftelt, wie sie erklärt und begriffen werden müsse."}], "markers": [{"system": "A", "ref": "A387"}, {"system": "A", "ref": "A388"}, {"system": "A", "ref": "A389"}], "running_header": "Betrachtung über die Summe der reinen Seelenlehre zu Folge diesen Paralogismen [A, Anhang]"}, {"page_pdf": 1438, "page_book": null, "page_kind": "body", "sigel": "A390 · A391 · A392", "units": [{"type": "paragraph", "text": "Die gewöhnliche drei hierüber erdachte und wirklich einzig mögliche Systeme sind die des physischen Einflusses, der vorher bestimmten Harmonie und der übernatürlichen Assistenz. Die zwei letztere Erklärungsarten der Gemeinschaft der Seele mit der Materie sind auf Einwürfe gegen die erstere, welche die Vorstellung des gemeinen Verstandes ist, gegründet: daß nämlich dasjenige, was als Materie erscheint, durch seinen unmittelbaren Einfluß nicht die Ursache von Vorstellungen als einer ganz heterogenen Art von Wirkungen sein könne. Sie können aber alsdann mit dem, was sie unter dem Gegenstande äußerer Sinne verstehen, nicht den Begriff einer Materie verbinden, welche nichts als Erscheinung, mithin schon an sich selbst bloße Vorstellung ist, die durch irgend welche äußere Gegenstände gewirkt worden; denn sonst würden sie sagen, daß die Vorstellungen äußerer Gegenstände (die Erscheinungen) nicht äußere Ursachen der Vorstellungen in unserem Gemüthe sein können, welches ein ganz sinnleerer Einwurf sein würde, weil es niemanden einfallen wird, das, was er einmal als bloße Vorstellung anerkannt hat, für eine äußere Ursache zu halten. Sie müssen also nach unseren Grundsätzen ihre Theorie darauf richten, daß dasjenige, was der wahre (transscendentale) Gegenstand unserer äußeren Sinne ist, nicht die Ursache derjenigen Vorstellungen (Erscheinungen) sein könne, die wir unter dem Namen Materie verstehen. Da nun niemand mit Grunde vorgeben kann, etwas von der transscendentalen Ursache unserer Vorstellungen äußerer Sinne zu kennen, so ist ihre Behauptung ganz grundlos. Wollten aber die vermeinte Verbesserer der Lehre vom physischen Einflusse nach der gemeinen Vorstellungsart eines transscendentalen Dualism die Materie als solche für ein Ding an sich selbst (und nicht als bloße Erscheinung eines unbekannten Dinges) ansehen und ihren Einwurf dahin richten, zu zeigen, daß ein solcher äußerer Gegenstand, welcher keine andere Causalität als die der Bewegungen an sich zeigt, nimmermehr die wirkende Ursache von Vorstellungen sein könne, sondern daß sich ein drittes Wesen deshalb ins Mittel schlagen müsse, um, wo nicht Wechselwirkung, doch wenigstens Correspondenz und Harmonie zwischen beiden zu stiften; so würden sie ihre Widerlegung davon anfangen, das prwton q»eudoV des physischen Einflusses in ihrem Dualismus anzunehmen, und also durch ihren Einwurf nicht sowohl den natürlichen Einfluß, sondern ihre eigene dualistische Voraussetzung widerlegen. Denn alle Schwierigkeiten, welche die Verbindung der denkenden Natur mit der Materie treffen, entspringen ohne Ausnahme lediglich aus jener erschlichenen dualistischen Vorstellung: daß Materie als solche nicht Erscheinung, d.i. bloße Vorstellung des Gemüths, der ein unbekannter Gegenstand entspricht, sondern der Gegenstand an sich selbst sei, so wie er außer uns und unabhängig von aller Sinnlichkeit existirt. Es kann also wider den gemein angenommenen physischen Einfluß kein dogmatischer Einwurf gemacht werden. Denn nimmt der Gegner an, daß Materie und ihre Bewegung bloße Erscheinungen und also selbst nur Vorstellungen seien, so kann er nur darin die Schwierigkeit setzen, daß der unbekannte Gegenstand unserer Sinnlichkeit nicht die Ursache der Vorstellungen in uns sein könne, welches aber vorzugeben ihn nicht das mindeste berechtigt, weil niemand von einem unbekannten Gegenstande ausmachen kann, was er thun oder nicht thun könne. Er muß aber nach unseren obigen Beweisen diesen transscendentalen Idealism nothwendig einräumen, wofern er nicht offenbar Vorstellungen hypostasiren und sie als wahre Dinge außer sich versetzen will. Gleichwohl kann wider die gemeine Lehrmeinung des physischen Einflusses ein gegründeter kritischer Einwurf gemacht werden. Eine solche vorgegebene Gemeinschaft zwischen zwei Arten von Substanzen, der denkenden und der ausgedehnten, legt einen groben Dualism zum Grunde und macht die letztere, die doch nichts als bloße Vorstellungen des denkenden Subjects sind, zu Dingen, die für sich bestehen. Also kann der mißverstandene physische Einfluß dadurch völlig vereitelt werden, daß man den Beweisgrund desselben als nichtig und erschlichen aufdeckt. Die berüchtigte Frage wegen der Gemeinschaft des Denkenden und Ausgedehnten würde also,"}], "markers": [{"system": "A", "ref": "A390"}, {"system": "A", "ref": "A391"}, {"system": "A", "ref": "A392"}], "running_header": "Betrachtung über die Summe der reinen Seelenlehre zu Folge diesen Paralogismen [A, Anhang]"}, {"page_pdf": 1439, "page_book": null, "page_kind": "body", "sigel": "A393 · A394 · A395", "units": [{"type": "paragraph", "text": "wenn man alles Eingebildete absondert, lediglich darauf hinauslaufen: wie in einem denkenden Subject überhaupt äußere Anschauung, nämlich die des Raumes (einer Erfüllung desselben, Gestalt und Bewegung), möglich sei. Auf diese Frage aber ist es keinem Menschen möglich eine Antwort zu finden, und man kann diese Lücke unseres Wissens niemals ausfüllen, sondern nur dadurch bezeichnen, daß man die äußere Erscheinungen einem transscendentalen Gegenstande zuschreibt, welcher die Ursache dieser Art Vorstellungen ist, den wir aber gar nicht kennen, noch jemals einigen Begriff von ihm bekommen werden. In allen Aufgaben, die im Felde der Erfahrung vorkommen mögen, behandeln wir jene Erscheinungen als Gegenstände an sich selbst, ohne uns um den ersten Grund ihrer Möglichkeit (als Erscheinungen) zu bekümmern. Gehen wir aber über deren Gränze hinaus, so wird der Begriff eines transscendentalen Gegenstandes nothwendig. Von diesen Erinnerungen über die Gemeinschaft zwischen dem denkenden und den ausgedehnten Wesen ist die Entscheidung aller Streitigkeiten oder Einwürfe, welche den Zustand der denkenden Natur vor dieser Gemeinschaft (dem Leben), oder nach aufgehobener solchen Gemeinschaft (im Tode) betreffen, eine unmittelbare Folge. Die Meinung, daß das denkende Subject vor aller Gemeinschaft mit Körpern habe denken können, würde sich so ausdrücken: daß vor dem Anfange dieser Art der Sinnlichkeit, wodurch uns etwas im Raume erscheint, dieselbe transscendentale Gegenstände, welche im gegenwärtigen Zustande als Körper erscheinen, auf ganz andere Art haben angeschaut werden können. Die Meinung aber, daß die Seele nach Aufhebung aller Gemeinschaft mit der körperlichen Welt noch fortfahren könne zu denken, würde sich in dieser Form ankündigen: daß, wenn die Art der Sinnlichkeit, wodurch uns transscendentale und für jetzt ganz unbekannte Gegenstände als materielle Welt erscheinen, aufhören sollte, so sei darum noch nicht alle Anschauung derselben aufgehoben, und es sei ganz wohl möglich, daß eben dieselbe unbekannte Gegenstände fortführen, obzwar freilich nicht mehr in der Qualität der Körper, von dem denkenden Subject erkannt zu werden. Nun kann zwar niemand den mindesten Grund zu einer solchen Behauptung aus speculativen Principien anführen, ja nicht einmal die Möglichkeit davon darthun, sondern nur voraussetzen; aber eben so wenig kann auch jemand irgend einen gültigen dogmatischen Einwurf dagegen machen. Denn wer er auch sei, so weiß er eben so wenig von der absoluten und inneren Ursache äußerer und körperlicher Erscheinungen, wie ich oder jemand anders. Er kann also auch nicht mit Grunde vorgeben, zu wissen, worauf die Wirklichkeit der äußeren Erscheinungen im jetzigen Zustande (im Leben) beruhe, mithin auch nicht: daß die Bedingung aller äußeren Anschauung, oder auch das denkende Subject selbst nach demselben (im Tode) aufhören werde. So ist denn also aller Streit über die Natur unseres denkenden Wesens und der Verknüpfung desselben mit der Körperwelt lediglich eine Folge davon, daß man in Aufhebung dessen, wovon man nichts weiß, die Lücke durch Paralogismen der Vernunft ausfüllt, da man seine Gedanken zu Sachen macht und sie hypostasirt; woraus eingebildete Wissenschaft sowohl in Ansehung dessen, der bejahend, als dessen, der verneinend behauptet, entspringt, indem ein jeder entweder von Gegenständen etwas zu wissen vermeint, davon kein Mensch einigen Begriff hat, oder seine eigene Vorstellungen zu Gegenständen macht und sich so in einem ewigen Zirkel von Zweideutigkeiten und Widersprüchen herum dreht. Nicht als die Nüchternheit einer strengen, aber gerechten Kritik kann von diesem dogmatischen Blendwerke, das so viele durch eingebildete Glückseligkeit unter Theorien und Systemen hinhält, befreien und alle unsere speculative Ansprüche blos auf das Feld möglicher Erfahrung einschränken, nicht etwa durch schalen Spott über so oft fehlgeschlagene Versuche, oder fromme Seufzer über die Schranken unserer Vernunft, sondern vermittelst einer nach sicheren Grundsätzen vollzogenen Gränzbestimmung derselben, welche ihr _nihil ulterius_ mit größter Zuverlässigkeit an die herculische Säulen heftet, die die Natur selbst aufgestellt hat, um die Fahrt unserer Vernunft nur so weit, als die stetig fortlaufende"}], "markers": [{"system": "A", "ref": "A393"}, {"system": "A", "ref": "A394"}, {"system": "A", "ref": "A395"}], "running_header": "Betrachtung über die Summe der reinen Seelenlehre zu Folge diesen Paralogismen [A, Anhang]"}, {"page_pdf": 1440, "page_book": null, "page_kind": "body", "sigel": "A396 · A397 · A398", "units": [{"type": "paragraph", "text": "Küsten der Erfahrung reichen, fortzusetzen, die wir nicht verlassen können, ohne uns auf einen uferlosen Ocean zu wagen, der uns unter immer trüglichen Aussichten am Ende nöthigt, alle beschwerliche und langwierige Bemühung als hoffnungslos aufzugeben."}, {"type": "paragraph", "text": "* * *"}, {"type": "paragraph", "text": "Wir sind noch eine deutliche und allgemeine Erörterung des transscendentalen und doch natürlichen Scheins in den Paralogismen der reinen Vernunft, imgleichen die Rechtfertigung der systematischen und der Tafel der Kategorien parallel laufenden Anordnungen derselben bisher schuldig geblieben. Wir hätten sie im Anfange dieses Abschnitts nicht übernehmen können, ohne in Gefahr der Dunkelheit zu gerathen, oder uns unschicklicher Weise selbst vorzugreifen. Jetzt wollen wir diese Obliegenheit zu erfüllen suchen. Man kann allen Schein darin setzen: daß die subjective Bedingung des Denkens für die Erkenntniß des Objects gehalten wird. Ferner haben wir in der Einleitung in die transscendentale Dialektik gezeigt: daß reine Vernunft sich lediglich mit der Totalität der Synthesis der Bedingungen zu einem gegebenen Bedingten beschäftige. Da nun der dialektische Schein der reinen Vernunft kein empirischer Schein sein kann, der sich beim bestimmten empirischen Erkenntnisse vorfindet, so wird er das Allgemeine der Bedingungen des Denkens betreffen, und es wird nur drei Fälle des dialektischen Gebrauchs der reinen Vernunft geben: 1. Die Synthesis der Bedingungen eines Gedankens überhaupt. 2. Die Synthesis der Bedingungen des empirischen Denkens. 3. Die Synthesis der Bedingungen des reinen Denkens. In allen diesen drei Fällen beschäftigt sich die reine Vernunft blos mit der absoluten Totalität dieser Synthesis, d.i. mit derjenigen Bedingung, die selbst unbedingt ist. Auf diese Eintheilung gründet sich auch der dreifache transscendentale Schein, der zu drei Abschnitten der Dialektik Anlaß giebt und zu eben so viel scheinbaren Wissenschaften aus reiner Vernunft, der transscendentalen Psychologie, Kosmologie und Theologie, die Idee an die Hand giebt. Wir haben es hier nur mit der ersteren zu thun. Weil wir beim Denken überhaupt von aller Beziehung des Gedanken auf irgend ein Object (es sei der Sinne oder des reinen Verstandes) abstrahiren: so ist die Synthesis der Bedingungen eines Gedanken überhaupt (_no._ 1) gar nicht objectiv, sondern blos eine Synthesis des Gedanken mit dem Subject, die aber fälschlich für eine synthetische Vorstellung eines Objects gehalten wird. Es folgt aber auch hieraus, daß der dialektische Schluß auf die Bedingung alles Denkens überhaupt, die selbst unbedingt ist, nicht einen Fehler im Inhalte begehe (denn er abstrahirt von allem Inhalte oder Objecte), sondern daß er allein in der Form fehle und Paralogism genannt werden müsse. Weil ferner die einzige Bedingung, die alles Denken begleitet, das Ich in dem allgemeinen Satze: Ich denke, ist, so hat die Vernunft es mit dieser Bedingung, so fern sie selbst unbedingt ist, zu thun. Sie ist aber nur die formale Bedingung, nämlich die logische Einheit eines jeden Gedanken, bei dem ich von allem Gegenstande abstrahire, und wird gleichwohl als ein Gegenstand, den ich denke, nämlich Ich selbst und die unbedingte Einheit desselben, vorgestellt. Wenn mir jemand überhaupt die Frage aufwürfe: von welcher Beschaffenheit ist ein Ding, welches denkt?, so weiß ich darauf _a priori_ nicht das mindeste zu antworten, weil die Antwort synthetisch sein soll (denn eine analytische erklärt vielleicht wohl das Denken, aber giebt keine erweiterte Erkenntniß von demjenigen, worauf dieses Denken seiner Möglichkeit nach beruht). Zu jeder synthetischen Auflösung aber wird Anschauung erfordert, die in der so allgemeinen Aufgabe gänzlich weggelassen worden. Eben so kann niemand die Frage in ihrer Allgemeinheit beantworten: was wohl das für ein Ding sein müsse, welches beweglich ist? Denn die undurchdringliche Ausdehnung (Materie) ist alsdann nicht gegeben. Ob ich nun zwar allgemein"}], "markers": [{"system": "A", "ref": "A396"}, {"system": "A", "ref": "A397"}, {"system": "A", "ref": "A398"}], "running_header": "Betrachtung über die Summe der reinen Seelenlehre zu Folge diesen Paralogismen [A, Anhang]"}, {"page_pdf": 1441, "page_book": null, "page_kind": "body", "sigel": "A399 · A400 · A401", "units": [{"type": "paragraph", "text": "auf jene Frage keine Antwort weiß, so scheint es mir doch, daß ich sie im einzelnen Falle in dem Satze, der das Selbstbewußtsein ausdrückt: Ich denke, geben könne. Denn dieses Ich ist das erste Subject, d.i. Substanz, es ist einfach etc. Dieses müßten aber alsdann lauter Erfahrungssätze sein, die gleichwohl ohne eine allgemeine Regel, welche die Bedingungen der Möglichkeit zu denken überhaupt und _a priori_ aussagte, keine dergleichen Prädicate (welche nicht empirisch sind) enthalten könnten. Auf solche Weise wird mir meine anfänglich so scheinbare Einsicht, über die Natur eines denkenden Wesens und zwar aus lauter Begriffen zu urtheilen, verdächtig, ob ich gleich den Fehler derselben noch nicht entdeckt habe. Allein das weitere Nachforschen hinter den Ursprung dieser Attribute, die ich mir als einem denkenden Wesen überhaupt beilege, kann diesen Fehler aufdecken. Sie sind nichts mehr als reine Kategorien, wodurch ich niemals einen bestimmten Gegenstand, sondern nur die Einheit der Vorstellungen, um einen Gegenstand derselben zu bestimmen, denke. Ohne eine zum Grunde liegende Anschauung kann die Kategorie allein mir keinen Begriff von einem Gegenstande verschaffen; denn nur durch Anschauung wird der Gegenstand gegeben, der hernach der Kategorie gemäß gedacht wird. Wenn ich ein Ding für eine Substanz in der Erscheinung erkläre, so müssen mir vorher Prädicate seiner Anschauung gegeben sein, an denen ich das Beharrliche vom Wandelbaren und das Substratum (Ding selbst) von demjenigen, was ihm blos anhängt, unterscheide. Wenn ich ein Ding einfach in der Erscheinung nenne, so verstehe ich darunter, daß die Anschauung desselben zwar ein Theil der Erscheinung sei, selbst aber nicht getheilt werden könne u.s.w. Ist aber etwas nur für einfach im Begriffe und nicht in der Erscheinung erkannt, so habe ich dadurch wirklich gar keine Erkenntniß von dem Gegenstande, sondern nur von meinem Begriffe, den ich mir von Etwas überhaupt mache, das keiner eigentlichen Anschauung fähig ist. Ich sage nur, daß ich etwas ganz einfach denke, weil ich wirklich nichts weiter als blos, daß es Etwas sei, zu sagen weiß. Nun ist die bloße Apperception (Ich) Substanz im Begriffe, einfach im Begriffe etc., und so haben alle jene psychologische Lehrsätze ihre unstreitige Richtigkeit. Gleichwohl wird dadurch doch dasjenige keinesweges von der Seele erkannt, was man eigentlich wissen will; denn alle diese Prädicate gelten gar nicht von der Anschauung und können daher auch keine Folgen haben, die auf Gegenstände der Erfahrung angewandt würden, mithin sind sie völlig leer. Denn jener Begriff der Substanz lehrt mich nicht, daß die Seele für sich selbst fortdaure, nicht, daß sie von den äußeren Anschauungen ein Theil sei, der selbst nicht mehr getheilt werden könne, und der also durch keine Veränderungen der Natur entstehen oder vergehen könne: lauter Eigenschaften, die mir die Seele im Zusammenhange der Erfahrung kennbar machen und in Ansehung ihres Ursprungs und künftigen Zustandes Eröffnung geben könnten. Wenn ich nun aber durch bloße Kategorie sage: die Seele ist eine einfache Substanz, so ist klar, daß, da der nackte Verstandesbegriff von Substanz nichts weiter enthält, als daß ein Ding als Subject an sich, ohne wiederum Prädicat von einem andern zu sein, vorgestellt werden solle, daraus nichts von Beharrlichkeit folge, und das Attribut des Einfachen diese Beharrlichkeit gewiß nicht hinzusetzen könne, mithin man dadurch über das, was die Seele bei den Weltveränderungen treffen könne, nicht im mindesten unterrichtet werde. Würde man uns sagen können: sie ist ein einfacher Theil der Materie, so würden wir von dieser aus dem, was Erfahrung von ihr lehrt, die Beharrlichkeit und mit der einfachen Natur zusammen die Unzerstörlichkeit derselben ableiten können. Davon sagt uns aber der Begriff des Ich in dem psychologischen Grundsatze (Ich denke) nicht ein Wort. Daß aber das Wesen, welches in uns denkt, durch reine Kategorien und zwar diejenige, welche die absolute Einheit unter jedem Titel derselben ausdrücken, sich selbst zu erkennen vermeine, rührt daher. Die Apperception ist selbst der Grund der Möglichkeit der Kategorien, welche ihrerseits nichts anders vorstellen, als die Synthesis des Mannigfaltigen der Anschauung, so fern dasselbe in der Apperception Einheit hat. Daher ist das Selbstbewußtsein überhaupt die"}], "markers": [{"system": "A", "ref": "A399"}, {"system": "A", "ref": "A400"}, {"system": "A", "ref": "A401"}], "running_header": "Betrachtung über die Summe der reinen Seelenlehre zu Folge diesen Paralogismen [A, Anhang]"}, {"page_pdf": 1442, "page_book": null, "page_kind": "body", "sigel": "A402 · A403 · A404", "units": [{"type": "paragraph", "text": "Vorstellung desjenigen, was die Bedingung aller Einheit und doch selbst unbedingt ist. Man kann daher von dem denkenden Ich (Seele), das sich als Substanz, einfach, numerisch identisch in aller Zeit und das Correlatum alles Daseins, aus welchem alles andere Dasein geschlossen werden muß, denkt, sagen: daß es nicht sowohl sich selbst durch die Kategorien, sondern die Kategorien und durch sie alle Gegenstände in der absoluten Einheit der Apperception, mithin durch sich selbst erkennt. Nun ist zwar sehr einleuchtend, daß ich dasjenige, was ich voraussetzen muß, um überhaupt ein Object zu erkennen, nicht selbst als Object erkennen könne, und daß das bestimmende Selbst (das Denken) von dem bestimmbaren Selbst (dem denkenden Subject), wie Erkenntniß vom Gegenstande unterschieden sei. Gleichwohl ist nichts natürlicher und verführerischer als der Schein, die Einheit in der Synthesis der Gedanken für eine wahrgenommene Einheit im Subjecte dieser Gedanken zu halten. Man könnte ihn die Subreption des hypostasirten Bewußtseins (_apperceptionis substantiatae_) nennen. Wenn man den Paralogism in den dialektischen Vernunftschlüssen der rationalen Seelenlehre, so fern sie gleichwohl richtige Prämissen haben, logisch betiteln will: so kann er für ein _sophisma _ _figurae dictionis_ gelten, in welchem der Obersatz von der Kategorie in Ansehung ihrer Bedingungen einen blos transscendentalen Gebrauch, der Untersatz aber und der Schlußsatz in Ansehung der Seele, die unter diese Bedingung subsumirt worden, von eben der Kategorie einen empirischen Gebrauch macht. So ist z.B. der Begriff der Substanz in dem Paralogismus der Simplicität ein reiner intellectueller Begriff, der ohne Bedingungen der sinnlichen Anschauung blos von transscendentalem, d.i. von gar keinem Gebrauch ist. Im Untersatze aber ist eben derselbe Begriff auf den Gegenstand aller inneren Erfahrung angewandt, ohne doch die Bedingung seiner Anwendung _in concreto_, nämlich die Beharrlichkeit desselben, voraus festzusetzen und zum Grunde zu legen, und daher ein empirischer, obzwar hier unzulässiger Gebrauch davon gemacht worden. Um endlich den systematischen Zusammenhang aller dieser dialektischen Behauptungen in einer vernünftelnden Seelenlehre in einem Zusammenhange der reinen Vernunft, mithin die Vollständigkeit derselben zu zeigen, so merke man: daß die Apperception durch alle Classen der Kategorien, aber nur auf diejenige Verstandesbegriffe durchgeführt werde, welche in jeder derselben den übrigen zum Grunde der Einheit in einer möglichen Wahrnehmung liegen, folglich Subsistenz, Realität, Einheit (nicht Vielheit) und Existenz; nur daß die Vernunft sie hier alle als Bedingungen der Möglichkeit eines denkenden Wesens, die selbst unbedingt sind, vorstellt. Also erkennt die Seele an sich selbst"}, {"type": "paragraph", "text": "1. Die unbedingte Einheit des *Verhältnisses, * d.i. sich selbst, nicht als inhärirend, sondern *subsistirend*"}, {"type": "paragraph", "text": "2. Die unbedingte Einheit der *Qualität,* d.i. nicht als reales Ganze, sondern *einfach** 3. Die unbedingte Einheit bei der *Vielheit* in der Zeit, d.i. nicht in verschiedenen Zeiten numerisch verschieden, sondern als *Eines* und eben *dasselbe Subject*"}, {"type": "paragraph", "text": "4. Die unbedingte Einheit des *Daseins* im Raume,"}], "markers": [{"system": "A", "ref": "A402"}, {"system": "A", "ref": "A403"}, {"system": "A", "ref": "A404"}], "running_header": "Betrachtung über die Summe der reinen Seelenlehre zu Folge diesen Paralogismen [A, Anhang]"}, {"page_pdf": 1443, "page_book": null, "page_kind": "body", "sigel": "A405", "units": [{"type": "paragraph", "text": "d.i. nicht als das Bewußtsein mehrerer Dinge außer ihr, sondern *nur des Daseins ihrer selbst,* anderer Dinge aber blos als ihrer Vorstellungen."}, {"type": "paragraph", "text": "Vernunft ist das Vermögen der Principien. Die Behauptungen der reinen Psychologie enthalten nicht empirische Prädicate von der Seele, sondern solche, die, wenn sie statt finden, den Gegenstand an sich selbst unabhängig von der Erfahrung, mithin durch bloße Vernunft bestimmen sollen. Sie müßten also billig auf Principien und allgemeine Begriffe von denkenden Naturen überhaupt gegründet sein. An dessen Statt findet sich, daß die einzelne Vorstellung: Ich bin, sie insgesammt regiert, welche eben darum, weil sie die reine Formel aller meiner Erfahrung (unbestimmt) ausdrückt, sich wie ein allgemeiner Satz, der vor alle denkende Wesen gelte, ankündigt und, da er gleichwohl in aller Absicht einzeln ist, den Schein einer absoluten Einheit der Bedingungen des Denkens überhaupt bei sich führt und dadurch sich weiter ausbreitet, als mögliche Erfahrung reichen könnte."}, {"type": "paragraph", "text": "__________"}, {"type": "paragraph", "text": "Anmerkungen: * Wie das Einfache hier wiederum der Kategorie der Realität entspreche, kann ich jetzt noch nicht zeigen, sondern wird im folgenden Hauptstücke bei Gelegenheit eines andern Vernunftgebrauchs eben desselben Begriffs gewiesen werden."}], "markers": [{"system": "A", "ref": "A405"}], "running_header": "Betrachtung über die Summe der reinen Seelenlehre zu Folge diesen Paralogismen [A, Anhang]"}]};
